import { _decorator, ScrollView, Node, Prefab, instantiate, size, Size, UITransform, v2 } from 'cc';
import { VirtualListScrollViewCellBase } from './VirtualListScrollViewCellBase';
const { ccclass, property } = _decorator;

@ccclass('VirtualListScrollView')
export class VirtualListScrollView extends ScrollView {

    private curItemPos: number = 0;
    private spawnCount: number = 0;
    private templateWidth: number = 0;
    private templateHeight: number = 0;
    private innerWidth: number = 0;
    private innerHeight: number = 0;
    private template: Prefab = null;
    private scrollViewHeight: number = 0;
    private scrollViewWidth: number = 0;
    private reuseItemOffset: number = 0;
    private totalRange: number = 0;
    private lastContentPos: number = 0;
    private items: VirtualListScrollViewCellBase[] = [];
    private bufferZone: number = 0;
    private spacing: number = 0;
    private totalCount: number = 0;
    private needUpdate: boolean = true;

    cellsUsed: {[key: number]: VirtualListScrollViewCellBase} = {};

    private updateItemCallback: Function;

    private getContentSize(node: Node) {
        return node.getComponent(UITransform).contentSize;
    }

    private setContentSize(node: Node, size: Size) {
        node.getComponent(UITransform).setContentSize(size);
    }

    onLoad() {
        this.lastContentPos = this.content.position.y;
        const size = this.getContentSize(this.node);
        this.scrollViewHeight = size.height;
        this.scrollViewWidth = size.width;
    }

    public removeAllChilren() {
        this.content.removeAllChildren();
        if (this.scrollViewHeight > 0 && this.scrollViewWidth > 0) {
            this.setContentSize(this.node, size(this.scrollViewWidth, this.scrollViewHeight));
        }
        this.curItemPos = 0;
        this.innerWidth = this.innerHeight = 0;
        this.spawnCount = 0;
        this.items = [];
        this.scrollToBottom();
    }

    public setTemplate(template: Prefab) {
        this.template = template;
        this.removeAllChilren();
        const item = instantiate(template);
        const size = this.getContentSize(item);
        this.templateWidth = size.width;
        this.templateHeight = size.height;
        this.bufferZone = this.templateHeight + this.spacing;
        this.lastContentPos = 0;
    }

    public setCallback(update: Function) {
        this.updateItemCallback = update;
    }

    public resize(count: number, exCount = 4, force = true) {
        const size = this.getContentSize(this.node);
        this.scrollViewHeight = size.height;
        this.scrollViewWidth = size.width;
        this.totalCount = count;
        this.spawnCount = Math.ceil(this.scrollViewHeight / this.templateHeight) + exCount;
        this.spawnCount = Math.min(this.spawnCount, this.totalCount);
        let innerContainerSize = new Size(this.getInnerContainerSize());
        this.reuseItemOffset = (this.templateHeight + this.spacing) * this.spawnCount;
        this.totalRange = this.templateHeight * this.totalCount + (this.totalCount - 1) * this.spacing;
        innerContainerSize.height = this.totalRange;
        this.respawn();
        if (force) {
            this.forceDoLayout();
        }
        this.setInnerContainerSize(innerContainerSize);
    }

    forceDoLayout() {
        this.curItemPos = 0;
        this.innerHeight = 0;
        this.innerWidth = 0;
        for (let i = 0; i < this.items.length; i++) {
            const item = this.items[i];
            item.setIdx(i);
            const itemSize = this.getContentSize(item.node);
            const contentSize = this.getContentSize(this.content);
            this.curItemPos -= itemSize.height;
            item.node.setPosition(item.node.position.x, this.curItemPos);
            this.innerHeight += itemSize.height;
            this.innerWidth = contentSize.width;
            this.updateItem(item, item.getIdx());
        }
    }

    private respawn() {
        const count = this.items.length;
        if (count > this.spawnCount) {
            while (this.items.length > this.spawnCount) {
                const item = this.items.pop();
                item!.node.destroy();
            }
        } else if (count < this.spawnCount) {
            let index = this.items.length;
            while (index < this.spawnCount) {
                const widget = instantiate(this.template);
                let comp = widget.getComponent(VirtualListScrollViewCellBase);
                if (!comp) {
                    comp = widget.addComponent(VirtualListScrollViewCellBase);
                }
                comp.onInit();
                comp.setIdx(index);
                this.pushBackCustomItem(widget);
                this.updateItem(comp, index);
                this.items.push(comp);
                index = index + 1;
            }
        }
    }

    updateItem(item: VirtualListScrollViewCellBase, itemID: number) {
        this.cellsUsed[itemID] = item;
        item.setIdx(itemID);
        if (this.updateItemCallback) {
            this.updateItemCallback(item, itemID);
        }
    }

    public pushBackCustomItem(item: Node) {
        let comp = item.getComponent(VirtualListScrollViewCellBase);
        if (!comp) {
            comp = item.addComponent(VirtualListScrollViewCellBase);
        }
        comp.onInit();
        this.content.addChild(item);
        const itemSize = this.getContentSize(item);
        this.curItemPos -= itemSize.height;
        item.setPosition(item.position.x, this.curItemPos);
        item.active = true;
        this.innerHeight += itemSize.height;
        this.innerWidth = itemSize.width;
        this.setInnerContainerSize(size(this.innerWidth, this.innerHeight));
    }

    private setInnerContainerSize(contentSize: Size) {
        const nodeSize = this.getContentSize(this.node);
        if (contentSize.height < nodeSize.height) {
            contentSize.height = nodeSize.height;
        }
        this.setContentSize(this.content, contentSize);
    }

    private getInnerContainerSize() {
        return this.getContentSize(this.content);
    }

    private getInnerContainerPos() {
        return this.content.getPosition;
    }

    private onPageViewEvent(sender: VirtualListScrollView, eventType: number) {
        if (eventType == 4) {
            this.onUpdate();
        }
    }

    setLocation(index: number, time: number) {
        if (index <= 0) {
            index = 1;
        }
        this.updateAllItemPos(index);
        const maxOffset = this.getMaxScrollOffset();
        let offset = 0;
        let onePageTab = Math.floor(this.scrollViewHeight / this.templateHeight);
        if (index > onePageTab) {
            offset = (index - Math.ceil(onePageTab / 2)) * this.templateHeight;
        }
        if (offset > maxOffset.y) {
            offset = maxOffset.y;
        }
        this.scrollToOffset(v2(0, offset), time);
    }

    updateAllItemPos(index: number) {
        let frontNum = 1;
        let pos = 0;
        if (this.items.length == 0) {
            return;
        }
        let onePageNum = 0;
        onePageNum = Math.floor(this.scrollViewHeight / this.templateHeight);
        onePageNum = Math.floor(onePageNum / 2) + 1;
        let endID = index + onePageNum;
        if (endID > this.totalCount) {
            endID = this.totalCount;
        }
        frontNum = endID - this.items.length + 1;
        if (frontNum <= 0) {
            frontNum = 1;
        }
        let itemID = 0;
        for (let i = frontNum; i < index; i++) {
            itemID = i - 1;
            if (pos >= this.items.length) {
                break;
            }
            const item = this.items[pos];
            item.node.setPosition(item.node.position.x, -(itemID + 1) * this.bufferZone);
            this.updateItem(item, itemID);
            pos++;
        }
        itemID = index - 1;
        for (let i = pos; i < this.items.length; i++) {
            const item = this.items[i];
            item.node.setPosition(item.node.position.x, -(itemID + 1) * this.bufferZone);
            this.updateItem(item, itemID);
            itemID++;
        }
    }

    onUpdate() {
        if (!this.needUpdate) {
            return;
        }
        if (this.items.length <= 0) {
            return;
        }
        const scrollOffset = this.getScrollOffset();
        const isDown = this.content.position.y < this.lastContentPos;
        this.lastContentPos = this.content.position.y;
        if (isDown) {
            let lastItem = this.items[0];
            if (lastItem.node.position.y > -scrollOffset.y) {
                return;
            }
            const itemID = lastItem.getIdx();
            if (itemID <= 0) {
                return;
            }
            for (let i = 1; i < this.items.length; i++) {
                const curItem = this.items[i];
                this.items[i] = lastItem;
                lastItem = curItem;
            }
            this.items[0] = lastItem;
            lastItem.node.setPosition(lastItem.node.position.x, -itemID * this.bufferZone);
            this.updateItem(lastItem, itemID - 1);
        } else {
            let nextItem = this.items[this.items.length - 1];
            if (nextItem.node.position.y + scrollOffset.y < -this.scrollViewHeight) {
                return;
            }
            const itemID = nextItem.getIdx();
            if (itemID >= this.totalCount - 1) {
                return;
            }
            nextItem = this.items[0];
            for (let i = this.items.length - 1; i >= 0; i--) {
                const curItem = this.items[i];
                this.items[i] = nextItem;
                nextItem = curItem;
            }
            nextItem.node.setPosition(nextItem.node.position.x, -(itemID + 2) * this.bufferZone);
            this.updateItem(nextItem, itemID + 1);
        }
    }
}
