
import { _decorator, Component, Node, isValid } from 'cc';
import { Label, Sprite, SpriteFrame, Tween, tween, Color, CCString } from 'cc';
import { VirtualListScrollViewCellBase } from '@gamecommon/virtual_scrollview/VirtualListScrollViewCellBase';
import { SingleGameCollectActivityManager } from '@gamecommon/single_game_collect_activity/SingleGameCollectActivityManager';
import * as PlatformModule from '@gamecommon/base/PlatformModule';
const { ccclass, property } = _decorator;

const SingleGameCollectColorWhite = new Color(255, 255, 255, 255);
const SingleGameCollectColorWhiteZeroAlpha = new Color(255, 255, 255, 0);

@ccclass('SingleGameCollectItemElement')
export class SingleGameCollectItemElement extends VirtualListScrollViewCellBase {

    @property(Label)
    indexLabel: Label = null;
    @property(Node)
    lockNode: Node = null;
    @property(Node)
    iconNode: Node = null;
    @property(Node)
    checkNode: Node = null;
    @property(Sprite)
    stateSprite: Sprite = null;
    @property(SpriteFrame)
    receiveSF: SpriteFrame = null;
    @property(SpriteFrame)
    nonReceiveSF: SpriteFrame = null;
    @property(Sprite)
    flashSprite: Sprite = null;
    @property(Node)
    topNode: Node = null;
    @property(Node)
    topBarNode: Node = null;
    @property(Node)
    bottomNode: Node = null;
    @property(Node)
    bottomBarNode: Node = null;

    private state: number = 0;

    private index: number = 0;

    @property(Sprite)
    itemSprite: Sprite = null;
    @property(Label)
    amountLabel: Label = null;

    private onItemClickCallback: (index: number) => void = null;

    public setData(index: number, data?: {
        onItemClickCallback?: (index: number) => void;
    }) {
        this.onItemClickCallback = data?.onItemClickCallback ?? null;

        this.index = index;
        const id = index + 1;
        this.indexLabel.string = id.toString();
            
        const manager = SingleGameCollectActivityManager.Instance;
        const config = manager.findStageConfig(id);
        if (!config) {
            this.itemSprite.node.active = false;
            return;
        }
        const currentCount = manager.CollectedCount;
        if (currentCount < config.collectCount) {
            this.state = 0;
        } else {
            this.state = 1;
        }
        this.updateState();
        if (this.state == 2) {
            this.lockNode.active = false;
        } else {
            this.lockNode.active = currentCount < config.collectCount;
        }
        this.showProgress();
        this.setupItemIconSprite(config.rewardItemNo, config.rewardAmount);
    }

    private async setupItemIconSprite(itemNo: number, amount: number) {
        let item = PlatformModule.ItemFactory?.Instance?.GetItemById(itemNo);
        if (!item) {
            return;
        }
        let spriteFrame: SpriteFrame | null = null;
        spriteFrame = await item.GetImage();
        if (!isValid(spriteFrame)) {
            return;
        }
        this.itemSprite.spriteFrame = spriteFrame;
        this.amountLabel.string = amount.toString();
    }

    public onItemClick() {
        if (this.state !== 1) {
            return;
        }
        this.onItemClickCallback?.(this.index);
        this.updateState();
    }

    private updateState() {
        const isReward = SingleGameCollectActivityManager.Instance.isCollectionRewardClaimed(this.index + 1);
        this.stateSprite.spriteFrame = isReward ? this.receiveSF : this.nonReceiveSF;
        this.checkNode.active = isReward;
        //this.iconNode.active = !isReward;
        if (isReward) {
            this.state = 2;
        }
        this.showFlash();
    }

    private showProgress() {
        const manager = SingleGameCollectActivityManager.Instance;
        const maxIndex = manager.TotalStages - 1;
        if (this.index == 0) {
            this.topNode.active = false;
        } else if (this.index >= maxIndex) {
            this.bottomNode.active = false;
        } else {
            this.topNode.active = true;
            this.bottomNode.active = true;
        }
        let currentIndex = manager.CurrentStage - 1; // 當前已完成階段
        // 此階段未達成獲獎目標，應標示上一階段
        if (!manager.hasReadyStageReward() && !manager.Over) {
            currentIndex = Math.max(currentIndex - 1, 0);
        }
        if (currentIndex < this.index) {
            this.topBarNode.active = false;
            this.bottomBarNode.active = false;
        } else if (currentIndex == this.index) {
            this.bottomBarNode.active = false;
            this.topBarNode.active = true;
        } else {
            this.topBarNode.active = true;
            this.bottomBarNode.active = true;
        }
    }

    private showFlash() {
        if (this.state == 1) {
            this.flashSprite.node.active = true;
            Tween.stopAllByTarget(this.flashSprite);
            const tw = tween(this.flashSprite);
            
            tw
            .set({ color: SingleGameCollectColorWhiteZeroAlpha })
            .repeatForever(
                tween()
                    .to(1, { color: SingleGameCollectColorWhite })
                    .to(1, { color: SingleGameCollectColorWhiteZeroAlpha })
            ).start();
        } else {
            this.flashSprite.node.active = false;
        }
    }
}


