import { _decorator, Component, Node, Vec3, tween, math, Tween, SpriteAtlas, Sprite, Label } from 'cc';
import { Card, Suit } from '../../types';
import { scalePunch } from '../utils/JuiceUtils';

const { ccclass, property } = _decorator;

export enum CardTweenState {
    IDLE,
    FLYING,
    DRAGGING,
    IN_PLAY,
    SCORING,
    DISCARDING,
}

const SUIT_TO_ATLAS_KEY: Record<Suit, string> = {
    Hearts: 'heart',
    Diamonds: 'diamond',
    Clubs: 'club',
    Spades: 'spade',
};

const RANK_TO_ATLAS_NUM: Record<string, string> = {
    A: '01', '2': '02', '3': '03', '4': '04', '5': '05',
    '6': '06', '7': '07', '8': '08', '9': '09', '10': '10',
    J: '11', Q: '12', K: '13',
};

@ccclass('CardView')
export class CardView extends Component {
    @property(Node)
    shadowNode: Node | null = null;

    @property(Node)
    visualNode: Node | null = null;

    @property(SpriteAtlas)
    cardAtlas: SpriteAtlas | null = null;

    @property(Sprite)
    cardFaceSprite: Sprite | null = null;

    @property(Label)
    rankLabel: Label | null = null;
    @property(Label)
    suitLabel: Label | null = null;

    private _isSelected: boolean = false;
    private _state: CardTweenState = CardTweenState.IDLE;
    private _idleTween: Tween<Node> | null = null;

    private _basePosition: Vec3 = new Vec3();
    private _baseAngle: number = 0;
    
    private readonly SELECT_OFFSET_Y = 30;
    private readonly WIGGLE_ANGLE = 2;
    private readonly WIGGLE_DURATION = 1.5;

    public cardModel: Card | null = null;

    public get state(): CardTweenState { return this._state; }
    public get basePositionX(): number { return this._basePosition.x; }

    private _isLockedState(): boolean {
        return this._state === CardTweenState.SCORING
            || this._state === CardTweenState.DISCARDING
            || this._state === CardTweenState.IN_PLAY;
    }

    onLoad() {
        this.startIdleAnimation();
    }

    public setCardModel(card: Card) {
        this.cardModel = card;
        if (this.rankLabel) this.rankLabel.string = card.rank;

        if (this.cardAtlas && this.cardFaceSprite) {
            const suitKey = SUIT_TO_ATLAS_KEY[card.suit];
            const rankNum = RANK_TO_ATLAS_NUM[card.rank];
            const frameName = `sol_poker_${suitKey}_${rankNum}`;
            const frame = this.cardAtlas.getSpriteFrame(frameName);
            if (frame) {
                this.cardFaceSprite.spriteFrame = frame;
            }
        }
    }

    public setBaseTransform(pos: Vec3, angle: number, animate: boolean = false) {
        this._basePosition.set(pos);
        this._baseAngle = angle;
        if (this._state === CardTweenState.DRAGGING || this._isLockedState()) return;

        const targetY = this._isSelected ? this._basePosition.y + this.SELECT_OFFSET_Y : this._basePosition.y;
        const targetPos = new Vec3(this._basePosition.x, targetY, this._basePosition.z);

        Tween.stopAllByTarget(this.node);
        if (animate) {
            tween(this.node)
                .to(0.15, { position: targetPos, angle: this._baseAngle }, { easing: 'quadOut' })
                .start();
        } else {
            this.node.setPosition(targetPos);
            this.node.angle = this._baseAngle;
        }
    }

    public get isSelected(): boolean {
        return this._isSelected;
    }

    public setSelected(selected: boolean) {
        if (this._isSelected === selected) return;
        this._isSelected = selected;

        if (this._state === CardTweenState.DRAGGING || this._isLockedState()) return;

        const targetY = this._basePosition.y + (selected ? this.SELECT_OFFSET_Y : 0);
        Tween.stopAllByTarget(this.node);
        tween(this.node)
            .to(0.15, { position: new Vec3(this._basePosition.x, targetY, this._basePosition.z), angle: this._baseAngle }, { easing: 'quadOut' })
            .start();
            
        this.updateShadow();
    }

    public flyTo(targetPos: Vec3, targetAngle: number, delayMs: number = 0): Promise<void> {
        if (this._isLockedState()) return Promise.resolve();

        this._basePosition.set(targetPos);
        this._baseAngle = targetAngle;
        this._state = CardTweenState.FLYING;
        return new Promise(resolve => {
            const startAnim = () => {
                Tween.stopAllByTarget(this.node);
                tween(this.node)
                    .to(0.28, { position: targetPos, angle: targetAngle }, { easing: 'backOut' })
                    .call(() => {
                        this._state = CardTweenState.IDLE;
                        resolve();
                    })
                    .start();
            };
            delayMs > 0 ? setTimeout(startAnim, delayMs) : startAnim();
        });
    }

    public setDragging(dragging: boolean) {
        if (dragging) {
            if (this._isLockedState()) return;
            this._state = CardTweenState.DRAGGING;
            this.stopIdleAnimation();
            this.updateShadow(true);
        } else {
            this._state = CardTweenState.IDLE;
            this.startIdleAnimation();
            this.updateShadow(false);
            
            const targetY = this._isSelected ? this._basePosition.y + this.SELECT_OFFSET_Y : this._basePosition.y;
            Tween.stopAllByTarget(this.node);
            tween(this.node)
                .to(0.2, { position: new Vec3(this._basePosition.x, targetY, this._basePosition.z), angle: this._baseAngle }, { easing: 'backOut' })
                .start();
        }
    }

    public get isDragging(): boolean {
        return this._state === CardTweenState.DRAGGING;
    }

    public updateDragPosition(delta: Vec3) {
        if (this._state !== CardTweenState.DRAGGING) return;
        
        const currentPos = this.node.position;
        this.node.setPosition(currentPos.x + delta.x, currentPos.y + delta.y, currentPos.z);
        
        // Inertia rotation (simple version)
        const targetAngle = math.clamp(-delta.x * 2, -15, 15);
        this.node.angle = math.lerp(this.node.angle, targetAngle, 0.5);
    }

    // ── Play / Score / Discard FSM transitions ────────────────────────

    public moveToPlayArea(targetPos: Vec3): Promise<void> {
        this._state = CardTweenState.IN_PLAY;
        this.stopIdleAnimation();
        Tween.stopAllByTarget(this.node);
        return new Promise(resolve => {
            tween(this.node)
                .to(0.3, { position: targetPos, angle: 0 }, { easing: 'quadOut' })
                .call(() => resolve())
                .start();
        });
    }

    public animateScore(): Promise<void> {
        if (this._state !== CardTweenState.IN_PLAY) return Promise.resolve();
        this._state = CardTweenState.SCORING;
        const wiggle = new Promise<void>(resolve => {
            tween(this.node)
                .by(0.1, { angle: 15 })
                .by(0.1, { angle: -30 })
                .by(0.1, { angle: 15 })
                .call(() => resolve())
                .start();
        });
        const punch = scalePunch(this.node, 2, 0.25);
        return Promise.all([wiggle, punch]).then(() => {
            this._state = CardTweenState.IN_PLAY;
        });
    }

    public animateDiscard(delayMs: number = 0): Promise<void> {
        this._state = CardTweenState.DISCARDING;
        this.stopIdleAnimation();
        Tween.stopAllByTarget(this.node);
        return new Promise(resolve => {
            tween(this.node)
                .delay(delayMs / 1000)
                .to(0.25, {
                    position: new Vec3(0, 0, 0),
                    scale: new Vec3(0, 0, 0),
                    angle: 360,
                }, { easing: 'quadIn' })
                .call(() => {
                    this.node.destroy();
                    resolve();
                })
                .start();
        });
    }

    private updateShadow(vivid: boolean = false) {
        if (!this.shadowNode) return;
        
        // Cascade shadow effect based on state
        const shadowOffset = vivid ? -15 : (this._isSelected ? -10 : -5);
        
        Tween.stopAllByTarget(this.shadowNode);
        tween(this.shadowNode)
            .to(0.15, { position: new Vec3(shadowOffset, shadowOffset, 0) })
            .start();
    }

    private startIdleAnimation() {
        if (!this.visualNode) return;
        
        this._idleTween = tween(this.visualNode)
            .to(this.WIGGLE_DURATION, { angle: this.WIGGLE_ANGLE }, { easing: 'sineInOut' })
            .to(this.WIGGLE_DURATION * 2, { angle: -this.WIGGLE_ANGLE }, { easing: 'sineInOut' })
            .to(this.WIGGLE_DURATION, { angle: 0 }, { easing: 'sineInOut' })
            .union()
            .repeatForever()
            .start();
    }

    private stopIdleAnimation() {
        if (this._idleTween) {
            this._idleTween.stop();
            this._idleTween = null;
        }
        if (this.visualNode) {
            tween(this.visualNode).stop().to(0.1, { angle: 0 }).start();
        }
    }
}
