import { _decorator, Component, Node, CCInteger, CCBoolean, Vec2, UITransform, Sprite, SpriteFrame, isValid } from 'cc';
import * as PlatformModule from '../base/PlatformModule';
const { ccclass, property } = _decorator;

@ccclass('BasePlatformItemSprite')
export class BasePlatformItemSprite extends Component {
    @property(Sprite)
    targetSprite!: Sprite;
    @property(Vec2)
    targetSize: Vec2 = new Vec2(100, 100);
    @property(CCInteger)
    itemId: number = 0;
    @property(CCBoolean)
    small: boolean = false;

    private done: boolean = false;

    protected onLoad() {
        if (!this.targetSprite) {
            this.targetSprite = this.node.getComponent(Sprite);
        }
    }

    protected onEnable() {
        this.initialize();
    }

    async initialize(force: boolean = false) {
        const inputId = this.itemId;
        if (inputId === 0 || (this.done && !force)) {
            return;
        }
        let item = PlatformModule.ItemFactory.Instance.GetItemById(this.itemId);
        if (!item) {
            return;
        }

        let spriteFrame: SpriteFrame | null = null;
        if (this.small) {
            spriteFrame = await item.GetSmallImage();
        }
        if (!isValid(spriteFrame)) {
            spriteFrame = await item.GetImage();
        }
        if (!isValid(spriteFrame) || !isValid(this.targetSprite)) {
            return;
        }
        if (this.itemId !== inputId) {
            return; // itemId already changed
        }
        this.targetSprite.sizeMode = Sprite.SizeMode.CUSTOM;
        this.targetSprite.getComponent(UITransform).setContentSize(this.targetSize.x, this.targetSize.y);
        this.targetSprite.spriteFrame = spriteFrame;
        this.done = true;
    }
}
