
import { _decorator, Component, assetManager, Prefab, instantiate, Node, find, resources, view } from 'cc';
import { TopBar } from "./TopBar";
import { GameResultSinglePlayerNewUI } from './GameResultSinglePlayerNewUI';
const { ccclass, property } = _decorator;

@ccclass('FakeCommonUI')
export class CommonUI extends Component {


    private static topbar : TopBar = null;
    private static uiCamera = null;
    private static instance : CommonUI = null;
    private static resultUI : Node = null;

    public static get UICamera(){
        return this.uiCamera;
    }

    protected onLoad(): void {
        if(CommonUI.instance != null){
            this.node.destroy();
            return;
        }
        CommonUI.instance = this;
        this._checkMaskNode();
    }

    protected onDestroy(): void {
        if(CommonUI.instance == this){
            CommonUI.topbar = null;
            CommonUI.instance = null;
        }
    }

    public static ClearTopbarStack(){
        
    }

    private static createTopbar() : Promise<void>{
        console.log('createTopbar');
        return new Promise((resolve, reject)=>{
            resources.load('UITopBar', Prefab, (err, pref)=>{
                if(pref){
                    let p = pref as Prefab;
                    let node = instantiate(p);
                    CommonUI.topbar = node.getComponent(TopBar);
                    CommonUI.instance.node.addChild(node);
                    resolve();
                }
            });
        });
        
    }

    public static SetLobbyTopbar(define:any){
        if(CommonUI.topbar == null){
            CommonUI.createTopbar().then(()=>{
                CommonUI.topbar.SetLobbyTopbar(define);
            });
        }else{
            CommonUI.topbar.SetLobbyTopbar(define);
        }
    }
    
    public static CloseNowTopBar(){
        if(CommonUI.topbar != null){
            CommonUI.topbar.CloseNowTopBar();
        }
    }

    public static HideTopbarBackBtn(){
        if(CommonUI.topbar != null){
            CommonUI.topbar.HideTopbarBackBtn();
        }

    }

    public static ShowTopbarBackBtn(){
        if(CommonUI.topbar != null){
            CommonUI.topbar.ShowTopbarBackBtn();
        }
    }

    public static async ShowResultUI(result, param){
        if(CommonUI.resultUI == null){
            await new Promise((resolve, reject) =>{
                resources.load('result_main_new', Prefab, (err, pref)=>{
                    if(pref){
                        let p = pref as Prefab;
                        let node = instantiate(p);
                        CommonUI.instance.node.addChild(node);
                        CommonUI.resultUI = node;
                        resolve(null);
                    } else {
                        console.error('ShowResultUI', err);
                    }
                });
            });
        }
        CommonUI.resultUI.active = true;
        let resultUIComp : GameResultSinglePlayerNewUI = CommonUI.resultUI.getComponent(GameResultSinglePlayerNewUI);

        resultUIComp.setActionWithCost(param.actionButton.actionName, null, ()=>{
            param.btnBackCallback();
            CommonUI.resultUI.destroy();
            CommonUI.resultUI = null;
        });

        await resultUIComp.show(null);
        
    }

    private _checkMaskNode() {
        let maskNode = find('Canvas/MaskNode');
        if (!maskNode) {
            console.warn('CommonUI: MaskNode not found, creating a new one.');
            return;
        }
        let resolution = view.getDesignResolutionSize();
        let islandscape = resolution.width > resolution.height;
        if (islandscape) {
            maskNode.setRotationFromEuler(0, 0, 0);
        } else {
            maskNode.setRotationFromEuler(0, 0, 90);
        }
        maskNode.active = true;
    }
}
