import { _decorator, Component, Node, CCString, Label, assetManager, AssetManager, director, profiler, Asset } from 'cc';
import * as PlatformModule from '@gamecommon/base/PlatformModule';
import { BaseGameData } from '../games/common/script/base/BaseGameData';
import { SoundManager } from '../games/common/fake_platform/SoundManager';
const { ccclass, property } = _decorator;


export const VERSION_INFO = {
    gitHash: "DEBUG_MODE",
    buildTime: "LOCAL_BUILD"
};
/**
 * 小遊戲端專案啟動用途，不要整合回平台 App
 */
@ccclass('FakeMain')
export class FakeMain extends Component {
    @property({
        type: CCString,
        tooltip: "小遊戲 bundle 名稱"
    })
    gameBundleName: string = "";
    @property({
        type: CCString,
        tooltip: "遊戲入口場景名稱"
    })
    gameSceneName: string = "";

    @property({
        type: Label,
        tooltip: "顯示版本號的 Label"
    })
    versionLabel: Label | null = null;

    @property({
        tooltip: "是否在遊戲啟動時就顯示 FPS"
    })
    showFPSOnStart: boolean = false;


    private _isShowingFPS: boolean = false;

    // 紀錄 FakeMain 進入 start 的次數
    private static fakeMainLoadCount: number = 0;

    // 防止載入與退出按鍵連點
    private _isOperating: boolean = false;

    start() {
        FakeMain.fakeMainLoadCount++;

        // 讓 FakeMain 節點在場景切換後仍然存在（包含其底下的 UI / Button）
        director.addPersistRootNode(this.node);

        this.refreshVersionLabel();

        // 是否在啟動時就顯示 FPS
        this._isShowingFPS = this.showFPSOnStart;
        if (this._isShowingFPS) {
            profiler.showStats();
        } else {
            profiler.hideStats();
        }

        // 只有第一次進 FakeMain 場景才會自動加載 Bundle 資源及場景
        if (FakeMain.fakeMainLoadCount === 1) {
            this.loadGame();
        }

        PlatformModule.ItemFactory?.Instance.LoadConfig();
    }

    /**
     * 綁給 Button 的點擊事件，用來載入 Bundle 資源及場景
     */
    public loadGame() {
        if (this._isOperating) return;
        this._isOperating = true;

        if (this.gameBundleName) {
            assetManager.loadBundle(this.gameBundleName, (err, bundle: AssetManager.Bundle) => {
                if (err) {
                    console.error(err);
                    this._isOperating = false;
                    return;
                }
                BaseGameData.Instance.GameBundleName = this.gameBundleName;
                bundle.loadScene(this.gameSceneName, (err, scene) => {
                    this._isOperating = false;
                    if (err) {
                        console.error(err);
                        return;
                    }
                    director.runScene(scene);
                });
            });
        } else {
            this._isOperating = false;
        }
    }

    private refreshVersionLabel() {
        if (!this.versionLabel) return;

        this.versionLabel.string = `v_${VERSION_INFO.gitHash}`;
    }

    /**
     * 綁給 Button 的點擊事件，用來開關 FPS 顯示
     */
    public onClickToggleFPS() {
        this._isShowingFPS = !this._isShowingFPS;
        if (this._isShowingFPS) {
            profiler.showStats();
        } else {
            profiler.hideStats();
        }
    }

    /**
     * 離開遊戲並返回 FakeMain (小遊戲平台), 釋放已加載的遊戲資源與場景
     */
    public exitGameAndReturnToPlatform() {
        if (this._isOperating) return;
        this._isOperating = true;

        // 從常駐節點移除，避免回到 fake_main 場景時產生兩個相同的節點
        director.removePersistRootNode(this.node);

        const bundleName = this.gameBundleName;
        // 為了順利切換場景並釋放舊場景，需要載入回 fake_main
        director.loadScene("fake_main", () => {
            this._isOperating = false;

            if (bundleName) {
                const bundle = assetManager.getBundle(bundleName);
                if (bundle) {
                    let config = bundle["_config"];
                    let paths = config.paths;
                    //遍歷bundle內所有資源，並嘗試將其釋放
                    paths.forEach((value, key: string) => {
                        let asset = bundle.get(key, Asset);
                        if (asset) {
                            if (asset.refCount == 0) {
                                bundle.release(key, Asset);
                                console.log("GameBundle release path:", key);
                            } else {
                                console.log("GameBundle unrelease path:", key, "asset.refCount:", asset?.refCount);
                            }
                        }
                    });
                    assetManager.removeBundle(bundle);
                    console.log(`[FakeMain] Released game bundle: ${bundleName}`);
                }
            }
            SoundManager.dispose();
        });

        // 銷毀目前的 FakeMain 節點，由新載入的 fake_main 場景中的 FakeMain 接手
        this.node.destroy();
    }
}


