export const CardEvents = {
    TAP: 'card-tap',
    LONG_PRESS_START: 'card-long-press',
    LONG_PRESS_END: 'card-long-press-end',
    DRAG_START: 'card-drag-start',
    DRAG_MOVE: 'card-drag-move',
    DRAG_END: 'card-drag-end'
} as const;

export type CardEventType = typeof CardEvents[keyof typeof CardEvents];

export const HandEvents = {
    SELECTION_CHANGED: 'hand-selection-changed',
} as const;

export type HandEventType = typeof HandEvents[keyof typeof HandEvents];
