import { _decorator, Component, Node, Animation } from 'cc';
import * as PlatformModule from './PlatformModule';
import { BaseGameEvent } from './BaseGameEvent';
import { BaseGameEventDefine, BaseGameState } from './BaseGameDefine';
import { BaseGameData } from './BaseGameData';


const { ccclass, property } = _decorator;

@ccclass('BaseGameResult')
export class BaseGameResult extends Component {

    @property({type:Boolean, tooltip: "離開時是否自動銷毀"})
    destoryWhenExit: boolean = true;

    @property({type:Boolean, tooltip: "離開時是否自動de-active"})
    deactiveWhenExit: boolean = true;

    @property({type:Animation, tooltip: "轉場動畫"})
    transAnim: Animation = null;

    @property({type:String, tooltip: "進場動畫名稱, 無設定即不播放"})
    enterAnimName: string = "";

    @property({type:String, tooltip: "離場動畫名稱, 無設定即不播放"})
    exitAnimName: string = "";

    @property({type :PlatformModule.TopbarHamburgerPos, tooltip: "天bar漢堡選單位置"})
    hamburgerPos: PlatformModule.TopbarHamburgerPos = PlatformModule.TopbarHamburgerPos.Left;

    protected reward : PlatformModule.GameCommonPb.GameReward = null;

    public async enter(){

        this.node.active = true;

        if(this.transAnim && (this.enterAnimName.length > 0)){
            this.transAnim.play(this.enterAnimName);
            //等待動畫播完
            await new Promise<void>(resolve => {
                this.transAnim.once(Animation.EventType.FINISHED, () => {
                    resolve();
                }, this);
            });
        }

        if(!BaseGameData.Instance.HideCommonUI){
            this.setTopbar(); 
            await this.showResultUI();
        }else{
            //如果沒連線平台, 不秀結算頁面, 直接返回遊戲大廳
            setTimeout(() => {
                this.backToGameLobby();
            }, 1000);
        }
    }

    public async exit(){

        if(this.transAnim && (this.exitAnimName.length > 0)){
            this.transAnim.play(this.exitAnimName);
            //等待動畫播完
            await new Promise<void>(resolve => {
                this.transAnim.once(Animation.EventType.FINISHED, () => {
                    if(this.deactiveWhenExit){
                        this.node.active = false;
                    }
                    resolve();
                }, this);
            });
        }else{
            if(this.deactiveWhenExit){
                this.node.active = false;
            }
        }
        
    }

    protected backToGameLobby(){
        BaseGameEvent.emit(BaseGameEventDefine.ChangeBaseGameState, BaseGameState.GAME_LOBBY);
    }

    protected onClickNext( arg?: any ){
        BaseGameEvent.emit(BaseGameEventDefine.ChangeBaseGameState, BaseGameState.GAME_PLAY, false, arg);
    }

    /**
     * 只是為了示範，subclass 必須自己重新實現
     */
    protected async showResultUI () {
        if(this.reward == null){
            this.reward = new PlatformModule.GameCommonPb.GameReward();
        }
        if (!PlatformModule.HasPlatformModule) {
            let param: PlatformModule.ResultV4Param = {
                actionButton: {
                    actionName: "再玩一局",
                    cost: {
                        itemNo: 10000002,
                        amount: "0"
                    },
                    actionCallback: this.onClickNext.bind(this),
                    checkCostFunc: null,
                },
                btnBackCallback: this.backToGameLobby.bind(this),  // 按下返回大廳Callback
            }
            PlatformModule.CommonUI?.ShowResultUI(null, param);
            return;
        }
        let result = PlatformModule.ResultParam.ParseProtoAny(this.reward);
        let param: PlatformModule.ResultV4Param = {
            actionButton: {
                actionName: "再玩一局",
                cost: {
                    itemNo: 10000002,
                    amount: "0"
                },
                actionCallback: this.onClickNext.bind(this),
                checkCostFunc: null,
            },
            wlGameParam: {
                wlType: PlatformModule.WLGameGradeType.evaluate,
                score: 0,
                evaluate: result.evlaute,
                dropBonusRate: `${result.evaluate_bonus_percentage}`,
            }, // 勝負宣告參數
            btnBackCallback: this.backToGameLobby.bind(this),  // 按下返回大廳Callback
        }
        PlatformModule.CommonUI?.ShowResultUI(result, param);
    }


    protected setTopbar() {
        PlatformModule.CommonUI?.ClearTopbarStack();
    }

}


