import { _decorator, Component, Node, Label, Button } from 'cc';
import { Joker } from '../../types/Joker';

const { ccclass, property } = _decorator;

@ccclass('JokerDraftPanel')
export class JokerDraftPanel extends Component {

    @property(Label)
    titleLabel: Label | null = null;

    @property([Node])
    jokerOptionNodes: Node[] = [];

    @property(Button)
    skipButton: Button | null = null;

    private _onPick: ((joker: Joker | null) => void) | null = null;
    private _offers: Joker[] = [];

    setup(offers: Joker[], onPick: (joker: Joker | null) => void) {
        this._offers = offers;
        this._onPick = onPick;

        if (this.titleLabel) {
            this.titleLabel.string = '選擇一張小丑牌';
        }

        offers.forEach((joker, i) => {
            const optionNode = this.jokerOptionNodes[i];
            if (!optionNode) return;

            const labels = optionNode.getComponentsInChildren(Label);
            if (labels[0]) labels[0].string = joker.name;
            if (labels[1]) labels[1].string = joker.description;

            const btn = optionNode.getComponent(Button) ?? optionNode.getComponentInChildren(Button);
            if (btn) {
                btn.node.targetOff(this);
                btn.node.on(Button.EventType.CLICK, () => this._pick(joker), this);
            }
        });

        if (this.skipButton) {
            this.skipButton.node.targetOff(this);
            this.skipButton.node.on(Button.EventType.CLICK, () => this._pick(null), this);
        }
    }

    private _pick(joker: Joker | null) {
        this._onPick?.(joker);
    }

    protected onDestroy(): void {
        this.jokerOptionNodes.forEach(n => n.targetOff(this));
        this.skipButton?.node.targetOff(this);
    }
}
