import { _decorator, Component, Node, Label, UITransform, Vec3, view, Canvas } from 'cc';
import { getCardPoint } from '../../engine/Evaluator';
import { CardView } from './CardView';
import { RichText } from 'cc';

const { ccclass, property } = _decorator;

@ccclass('CardInfoPopup')
export class CardInfoPopup extends Component {
    @property(RichText)
    nameLabel: RichText | null = null;

    @property(RichText)
    chipsLabel: RichText | null = null;

    private _currentTarget: Node | null = null;
    private readonly PADDING_Y = 20;

    onLoad() {
        this.hide();
        
        // Handle "tap anywhere to hide" (air-tap)
        const canvas = this.node.scene?.getComponentInChildren(Canvas);
        if (canvas) {
            canvas.node.on(Node.EventType.TOUCH_START, this.onGlobalTap, this);
        }
    }

    onDestroy() {
        const canvas = this.node.scene?.getComponentInChildren(Canvas);
        if (canvas) {
            canvas.node.off(Node.EventType.TOUCH_START, this.onGlobalTap, this);
        }
    }

    private onGlobalTap(event: any) {
        // If we tap outside the current target card, hide the info
        // We'd ideally check if the tap hit a card, but for now any tap hides it
        // The card tap will just re-trigger its own events.
        if (this.node.active) {
            this.hide();
        }
    }

    public show(cardView: CardView) {
        const card = cardView.cardModel;
        if (!card) return;

        this._currentTarget = cardView.node;
        
        if (this.nameLabel) this.nameLabel.string = `<b><color=#B9085D>${card.suit}</color> <color=#000000>${card.rank}</color></b>`;
        
        const basePoints = getCardPoint(card);
        if (this.chipsLabel) this.chipsLabel.string = `<b><color=#006A62>+${basePoints}</color> <color=#000000>籌碼</color></b>`;

        this.node.active = true;
        this.updatePosition();
    }

    public hide() {
        this.node.active = false;
        this._currentTarget = null;
    }

    update(dt: number) {
        // If tracking a dragging card, keep position updated
        if (this.node.active && this._currentTarget) {
            this.updatePosition();
        }
    }

    private updatePosition() {
        if (!this._currentTarget) return;

        const targetTransform = this._currentTarget.getComponent(UITransform);
        const myTransform = this.node.getComponent(UITransform);
        if (!targetTransform || !myTransform) return;

        // Get target world pos
        const worldPos = targetTransform.convertToWorldSpaceAR(new Vec3(0, 0, 0));
        
        // Convert to local pos of the popup's parent
        const parentTransform = this.node.parent?.getComponent(UITransform);
        if (!parentTransform) return;
        
        const localPos = parentTransform.convertToNodeSpaceAR(worldPos);

        // Determine if we should show above or below based on canvas bounds
        const visibleSize = view.getVisibleSize();
        // Simple heuristic: if card is in the top 30% of screen, show below.
        const showBelow = worldPos.y > (visibleSize.height * 0.7);

        const targetHeight = targetTransform.height;
        const myHeight = myTransform.height;

        let finalY = 0;
        if (showBelow) {
            finalY = localPos.y - (targetHeight / 2) - (myHeight / 2) - this.PADDING_Y;
        } else {
            finalY = localPos.y + (targetHeight / 2) + (myHeight / 2) + this.PADDING_Y;
        }

        this.node.setPosition(localPos.x, finalY, 0);
    }
}
