import { _decorator, Component, Node, Button } from 'cc';
const { ccclass, property } = _decorator;

@ccclass('FakeGamePause')
export class GamePause extends Component {
    @property(Node)
    private m_pausePage: Node = null;
    @property(Button)
    private m_pauseBtn: Button = null;
    @property(Button)
    private m_resumeBtn: Button = null;
    @property(Button)
    private m_closeBtn: Button = null;
    @property(Button)
    private m_leaveBtn: Button = null;


    pauseCallback: Function = null;
    endPauseCallback: Function = null;
    leaveCallback: Function = null;


    onLoad() {
        this.registerAllBtn();    
    }

    //按鈕事件註冊
    registerAllBtn() {
        this.m_pauseBtn.node.on(Button.EventType.CLICK, this.onPauseBtnClick, this);
        this.m_resumeBtn.node.on(Button.EventType.CLICK, this.onResumeBtnClick, this);
        this.m_closeBtn.node.on(Button.EventType.CLICK, this.onResumeBtnClick, this);
        this.m_leaveBtn.node.on(Button.EventType.CLICK, this.onLeaveBtnClick, this);
    }
    unregisterAllBtn() {
        //只在onLoad註冊事件的話，理論上不會用到
        this.m_pauseBtn.node.off(Button.EventType.CLICK, this.onPauseBtnClick, this);
        this.m_resumeBtn.node.off(Button.EventType.CLICK, this.onResumeBtnClick, this);
        this.m_closeBtn.node.off(Button.EventType.CLICK, this.onResumeBtnClick, this);
        this.m_leaveBtn.node.off(Button.EventType.CLICK, this.onLeaveBtnClick, this);
    }

    //註冊callback
    registerPauseCallback(callback: Function) {
        this.pauseCallback = callback;
    }
    registerEndPauseCallback(callback: Function) {
        this.endPauseCallback = callback;
    }
    registerLeaveCallback(callback: Function) {
        this.leaveCallback = callback
    }

    //清除callback
    clearAllCallback() {
        this.pauseCallback = null;
        this.endPauseCallback = null;
        this.leaveCallback = null;
    }


    onPauseBtnClick() {
        //開啟暫停頁面
        this.m_pausePage.active = true;
        
        if(this.pauseCallback !=null && this.pauseCallback != undefined)
            this.pauseCallback();
    }
    hidePausePage() {
        this.m_pausePage.active = false;
    }

    activePauseBtn(active: boolean) {
        //顯示暫停按鈕,有的遊戲可能會在特定時機隱藏暫停按鈕
        this.m_pauseBtn.node.active = active;
    }
    
    interactablePauseBtn(interactable: boolean) {
        //設定暫停按鈕是否可點擊
        this.m_pauseBtn.interactable = interactable;
    }

    onResumeBtnClick() {
        //返回功能
        this.hidePausePage();
        
        if(this.endPauseCallback !=null && this.endPauseCallback != undefined)
            this.endPauseCallback();
    }

    onLeaveBtnClick() {

        if(this.leaveCallback !=null && this.leaveCallback != undefined)
            this.leaveCallback();

        this.hidePausePage();
    }

}


