//----------------------------------------------- 底下為假平台用
import { GamePause } from '../../fake_platform/GamePause';
import { CommonUI } from '../../fake_platform/CommonUI';
import { TopbarHamburgerPos, TopbarType, ResourceDefine } from '../../fake_platform/TopBar';
import { GameResultSinglePlayerNewUI, ResultParam, GameCommonPb} from '../../fake_platform/GameResultSinglePlayerNewUI';
import { GameResultV4UI, ResultV4Param, WLGameGradeType } from '../../fake_platform/GameResultV4UI';
import { SoundManager } from '../../fake_platform/SoundManager';
import { GameSysHamburgerButton } from '../../fake_platform/GameSysHamburgerButton';
import { ItemFactory, EnumCurrency } from '../../fake_platform/item/ItemFactory';
import { IItem, Item } from '../../fake_platform/item/ItemData';

export { GamePause, CommonUI, TopbarHamburgerPos, TopbarType, ResourceDefine, GameResultSinglePlayerNewUI, ResultParam, GameCommonPb};
export type { ResultV4Param };
export { GameResultV4UI, WLGameGradeType };
export { SoundManager };
export { GameSysHamburgerButton };
export { ItemFactory, EnumCurrency };
export type { IItem };
export { Item };
export let SceneManager = null;
export let PlatformService = null;
export let InviteService = null;
export let GameDefine = null;
export let Define = null;
export let ResourceManager = null;
export let ClientEvent = null;
export let HasPlatformModule = false;
export let PlatformApp = null;
export let BaseAPP = null;
export let CommApp = null;
export let FireBaseAnalytics = null;
export let FireBaseLogEventExt = null;
export let GameColleDataModel = null;

export function loadModule(node : Node){

    const sceneManager = js.getClassByName('scene_manager');
    if(sceneManager){
        SceneManager = sceneManager;
    }

    const platformService = js.getClassByName('PlatformService');
    if(platformService){
        PlatformService = platformService;
    }

    const inviteService = js.getClassByName('InviteService');
    if(inviteService){
        InviteService = inviteService;
    }

    const gameDefine = js.getClassByName('GameDef');
    if(gameDefine){
        GameDefine = gameDefine;
    }

    const define = js.getClassByName('CommonDefine');
    if(define){
        Define = define;
    }

    const resourceManager = js.getClassByName('resource_manager');
    if(resourceManager){
        ResourceManager = resourceManager;
    }  
    
    const clientEvent = js.getClassByName('ClientEvent');
    if(clientEvent){
        ClientEvent = clientEvent;
    }

    const platformApp = js.getClassByName('PlatformAPP');
    if(platformApp){
        PlatformApp = platformApp;
    }
    node.addComponent(CommonUI);

    HasPlatformModule = (SceneManager && PlatformService && InviteService && GameDefine && Define && ResourceManager && ClientEvent && PlatformApp) != null;
}

