// import APP from "@platform/common/APP";
import { CCString, CCFloat, CCBoolean, _decorator, math, AudioClip, Component, isValid } from "cc";

import * as PlatformModule from './PlatformModule';

const { ccclass, property } = _decorator;


@ccclass("BaseSoundData")
export class BaseSoundData {
    @property({ type: CCString })
    public keyName: string = "";
    @property({ type: AudioClip })
    public audio: AudioClip | null = null;
    private _volume: number = 1;
    @property({ type: CCFloat, visible: PlatformModule.HasPlatformModule })
    public set volume(value: number) {
        this._volume = math.clamp01(value);
    }
    public get volume(): number {
        return math.clamp01(this._volume);
    }
    @property({ type: CCFloat, visible: PlatformModule.HasPlatformModule })
    audioFadeInOutTime: number = 0;
    @property({ type: CCFloat, visible: PlatformModule.HasPlatformModule })
    audioFadeInOutSpeed: number = 0;
    @property({ type: CCBoolean, visible: PlatformModule.HasPlatformModule })
    isWaitPlayFinish: boolean = false;
    @property({ type: CCBoolean, visible: PlatformModule.HasPlatformModule })
    isFadeOutMusic: boolean = false;
}

class AduioData {
    public audio: AudioClip | null = null;
    public volume: number = 1;
    public audioFadeInOutTime: number = 0;
    public audioFadeInOutSpeed: number = 0;
    public isWaitPlayFinish: boolean = false;
    public isFadeOutMusic: boolean = false;
}
/**
 * 對外接口  
 * musicData 是音樂
 * soundData 是音效
 * 
 */
@ccclass('BaseSoundMgr')
export class BaseSoundMgr extends Component {

    private static _instance: BaseSoundMgr;
    public static get Instance(): BaseSoundMgr {
        return this._instance;
    }
    @property({ type: CCFloat , visible: PlatformModule.HasPlatformModule })
    fadeOutMusicTime: number = 50;
    @property({ type: CCFloat , visible: PlatformModule.HasPlatformModule })
    musicMaxVolume: number = 0.8;
    @property({ type: CCFloat , visible: PlatformModule.HasPlatformModule })
    soundMaxVolume: number = 1;
    @property({ type: BaseSoundData })
    musicData: BaseSoundData[] = [];
    @property({ type: BaseSoundData })
    soundData: BaseSoundData[] = [];

    private _musicDataDirectory: Map<string, AduioData> = new Map<string, AduioData>();
    private _soundDataDirectory: Map<string, AduioData> = new Map<string, AduioData>();


    onLoad() {
        if (BaseSoundMgr.Instance) {
            this.node.destroy();
            return;
        }
        BaseSoundMgr._instance = this;

        this.initAudioData();
    }
    onDestroy() {
        if (BaseSoundMgr._instance == this) BaseSoundMgr._instance = null;
    }

    private initAudioData() {
        if (!this.musicData) return;
        // set music map
        for (let d of this.musicData) {
            let data = new AduioData();
            data.audio = d.audio;
            data.volume = d.volume;
            data.audioFadeInOutSpeed = d.audioFadeInOutSpeed;
            data.audioFadeInOutTime = d.audioFadeInOutTime;
            data.isWaitPlayFinish = d.isWaitPlayFinish;
            this._musicDataDirectory.set(d.keyName, data);
        }
        // set sound map
        for (let d of this.soundData) {
            let data = new AduioData();
            data.audio = d.audio;
            data.volume = d.volume;
            data.audioFadeInOutSpeed = d.audioFadeInOutSpeed;
            data.audioFadeInOutTime = d.audioFadeInOutTime;
            data.isWaitPlayFinish = d.isWaitPlayFinish;
            data.isFadeOutMusic = d.isFadeOutMusic;
            this._soundDataDirectory.set(d.keyName, data);
        }
    }

    private playingSound = {}

    /**
     * 播放音效 key 需要帶入再prefab中設定的 Key Name
     * 若 isMusic 為 true 會找 musicData 的資料
     * 若 isMusic 為 false 會找 soundData 的資料
     */
    public PlaySound(key: string, isMusic: boolean = false, currentTime: number = 0): number {
        console.log(`PlaySound: ${key}, ${isMusic}, ${currentTime}`);
        let clipData = isMusic ? this._musicDataDirectory.get(key) : this._soundDataDirectory.get(key);
        if (!clipData) return;
        if (isMusic) {
            let id = PlatformModule.SoundManager.getInstance().PlayBackGround(clipData.audio, true, null, true, currentTime);
            return id;
        }
        else {
            if (clipData.isFadeOutMusic) {
                PlatformModule.SoundManager.getInstance().TweenBGMVolume(0.5, 0);
                try {
                    let cb = PlatformModule.SoundManager.getInstance().TweenBGMVolume.bind(PlatformModule.SoundManager.getInstance(), 0.5)
                    let id = PlatformModule.SoundManager.getInstance().Play(clipData.audio, false, cb, 1, currentTime);
                    return id;

                    
                }
                catch (e) {
                    console.error(e);
                }
            } else {
                if (this.playingSound[key] == undefined) {
                    this.playingSound[key] = { playmap: [] };
                }
                if( this.playingSound[key].playmap.length > 3 ) {
                    PlatformModule.SoundManager.getInstance().Stop(this.playingSound[key].playmap[0]);
                    this.playingSound[key].playmap.shift();
                }
                let idx = -1
                idx = PlatformModule.SoundManager.getInstance().Play(clipData.audio, false, 
                    () => {
                        if (!this || !isValid(this.node, true)) {
                            return;
                        }
                        if( this.playingSound[key] ){ // 中途有 StopSound 的話會被清掉
                            this.playingSound[key].playmap.splice(this.playingSound[key].playmap.indexOf(idx), 1);
                        }
                    }, 1, currentTime)
                
                this.playingSound[key].playmap.push(idx);
                return idx;
            }
        }
    }

    /**
     * 停止聲音
     * 
     */
    public async StopSound(isMusic: boolean = false, index: number = -1) {
        if (isMusic) {
            PlatformModule.SoundManager.getInstance().StopBackGround(true)
            return;
        }
        else {
            if (index < 0) {
                PlatformModule.SoundManager.getInstance().StopAll();
                this.playingSound = {}
            }
            else {
                PlatformModule.SoundManager.getInstance().Stop(index);
                for( let key in this.playingSound ){
                    let idx = this.playingSound[key].playmap.indexOf(index);
                    if( idx >= 0 ){
                        this.playingSound[key].playmap.splice(idx, 1);
                    }
                }
            }
            return
        }
    }

    private sleep(interval: number) {
        return new Promise((resolve, reject) => setTimeout(resolve, interval));
    }
}
