import { _decorator, Component, Node, AudioClip, AudioSource, find, tween, director } from 'cc';
const { ccclass, property } = _decorator;

/**
 * !!! 內部調用 !!!
 * !!! 遊戲層請勿 直接使用 !!!
 */
const BGM_ID = 9999;

export class SoundManager {

    private static _instance: SoundManager;

    public static getInstance(): SoundManager {
        if (!SoundManager._instance) {
            SoundManager._instance = new SoundManager();
        }
        return SoundManager._instance;
    }

    public static dispose(): void {
        if (!SoundManager._instance) {
            return;
        }
        const root = SoundManager._instance._rootNode;
        if (root && root.isValid) {
            root.destroy();
        }
        SoundManager._instance._rootNode = null;
        SoundManager._instance.m_audioPool = [];
        SoundManager._instance = null;
    }

    //#region Audio

    private _rootNode: Node = null;
    private get m_rootNode(): Node {
        // 加入 isValid 檢查，避免 scene 切換後 _rootNode 已被 destroy 但不為 null 的情況
        if (!this._rootNode || !this._rootNode.isValid) {
            this._rootNode = new Node('FakePlatformAPI');
            director.getScene().addChild(this._rootNode);
            // scene 切換後舊的 AudioSource pool 已失效，一併清空
            this.m_audioPool = [];
        }
        return this._rootNode;
    }

    private BGM_NODE_NAME = 'BGM';
    // private SE_NODE_NAME = 'SE';

    private _bgMute: boolean = false;
    private _seMute: boolean = false;
    private m_audioPool: AudioSource[] = [];

    get bgIsMute(): boolean { return this._bgMute; }
    set bgIsMute(value: boolean) {
        let node = find(this.BGM_NODE_NAME)
        if (!node) {
            node = new Node(this.BGM_NODE_NAME);
            director.getScene().addChild(node);
        }
        let bgm = node.getComponent(AudioSource);
        if (!bgm) {
            bgm = node.addComponent(AudioSource);
        }
        bgm.volume = value ? 0 : 1;
        this._bgMute = value;
    }

    get soundEffectIsMute(): boolean { return this._seMute; }
    set soundEffectIsMute(value: boolean) {
        this.m_audioPool.forEach(source => {
            source.volume = value ? 0 : 1;
        })
        this._seMute = value;
    }

    public PlayBackGround(clip: AudioClip, loop: boolean, cb: Function = null, isSoftPlay: boolean = false, currentTime: number = 0): number {
        let node = find(this.BGM_NODE_NAME)
        if (!node) {
            node = new Node(this.BGM_NODE_NAME);
            director.getScene().addChild(node);
        }
        let bgm = node.getComponent(AudioSource);
        if (!bgm) {
            bgm = node.addComponent(AudioSource);
        }
        bgm.clip = clip;
        bgm.loop = true;
        bgm.currentTime = currentTime;
        bgm.play();
        console.log('FakePlatformAPI.PlayBackGround');
        return BGM_ID;
    }

    public async TweenBGMVolume(duration: number, targetVolume?: number) {
        console.log('FakePlatformAPI.TweenBGMVolume');
    }

    public StopBackGround(isForce: boolean) {
        console.log('FakePlatformAPI.StopBackGround');
        let node = find(this.BGM_NODE_NAME);
        if (!node) {
            return;
        }
        let bgm = node.getComponent(AudioSource);
        if (bgm) {
            bgm.stop();
        }
    }

    Play(clip: AudioClip, loop: boolean, cb: Function, volume: number = 1, currentTime: number = 0): number {
        console.log('FakePlatformAPI.Play');
        if (!clip) {
            return null;
        }

        let [source, index] = this.getAudioSource();
        if (!source) {
            console.log(`SoundManager Play source is null`);
            return null;
        }
        try {
            source.clip = clip;
            source.loop = loop;
            source.volume = 1;
            source.currentTime = currentTime;
            source.play();
            // Clean up clip when audio ends naturally
            let onCleanup = function () {
                source.clip = null;
                source.node.off(AudioSource.EventType.ENDED, onCleanup, this);
            }
            source.node.on(AudioSource.EventType.ENDED, onCleanup, this);

            if (cb) {
                let onCB = function () {
                    cb();
                    source.node.off(AudioSource.EventType.ENDED, onCB, this);
                }
                source.node.on(AudioSource.EventType.ENDED, onCB, this);
            }

            return index;
        } catch (e) {
            console.error(`SoundManager Play error : ${e}`);
            return index;
        } finally {
            return index;
        }
    }

    Stop(id: number) {
        console.log('FakePlatformAPI.Stop');
        if (id == BGM_ID) {
            this.StopBackGround(true);
            return;
        }
        if (!this.m_audioPool[id]) {
            console.warn(`FakePlatformAPI.Stop: id ${id} not found`);
            return;
        }
        this.m_audioPool[id].stop();
        this.m_audioPool[id].clip = null;
        this.m_audioPool[id].node.emit(AudioSource.EventType.ENDED);
    }

    StopAll() {
        console.log('FakePlatformAPI.StopAll');
        this.StopBackGround(true);
        this.m_audioPool.forEach(source => {
            source.stop();
            source.clip = null;
            source.node.emit(AudioSource.EventType.ENDED);
        })
    }
    private getAudioSource(): [AudioSource, number] {
        let canUseAudioSource: AudioSource = null
        let index: number = null

        //let playingSoundNum = 0;
        for (let i = 0; i < this.m_audioPool.length; i++) {
            let audioSource = this.m_audioPool[i]

            if ((audioSource.state != AudioSource.AudioState.PLAYING && audioSource.state != AudioSource.AudioState.PAUSED) && audioSource.clip == null) {
                canUseAudioSource = audioSource
                index = i;
                break;
            }
        }

        //console.log("Fiona SoundManager getAudioSource , is playing number :", playingSoundNum);

        if (!canUseAudioSource) {

            if (this.m_audioPool.length >= (AudioSource.maxAudioChannel - 5)) { // for music and character voice
                let pickScore = 0
                for (let i = 0; i < this.m_audioPool.length; i++) {
                    let audioSource = this.m_audioPool[i]
                    let cliplength = audioSource.duration
                    let currentPos = audioSource.currentTime
                    let played = currentPos / cliplength
                    let score = 2.0 / cliplength + played * 10
                    if (score > pickScore) {
                        pickScore = score
                        canUseAudioSource = audioSource
                        index = i
                    }
                }
            } else {
                let node = new Node;
                this.m_rootNode.addChild(node);

                let source = node.addComponent(AudioSource)
                source.playOnAwake = false;
                this.m_audioPool.push(source);

                index = this.m_audioPool.length - 1;
                canUseAudioSource = source
            }
        }

        return [canUseAudioSource, index];
    }
    //#endregion Audio
}
