import { _decorator, Component, Node } from 'cc';
const { ccclass, property } = _decorator;

@ccclass('GameSysHamburgerButton')
export class GameSysHamburgerButton extends Component {

    @property({type:Node})
    private topbarFroceEndNode = null;  

    LeaveConfirmDelegate: Function | null = null;

    public onClickLeave(){
        if(this.LeaveConfirmDelegate){
            this.LeaveConfirmDelegate();
        }
        this.topbarFroceEndNode.active = false;
    }

    public onClickHamburgerBtn(){
        this.topbarFroceEndNode.active = !this.topbarFroceEndNode.active;
    }
}


