import { _decorator, Component, Node } from 'cc';
import * as PlatformModule from './PlatformModule';
import { IBaseGameService } from './IBaseGameService';
import { BaseGameEvent } from './BaseGameEvent';
import { BaseGameEventDefine } from './BaseGameDefine';
import { SingleGameCollectActivityState, SingleGameCollectStageConfig } from '@gamecommon/single_game_collect_activity/SingleGameCollectActivityDataDefine';
const { ccclass, property } = _decorator;

// 假資料階段設定
const FAKE_COLLECTACTIVITY_STAGE_CONFIGS: SingleGameCollectStageConfig[] = [
    { stageNo: 1, collectCount: 5, rewardItemNo: 10000003, rewardAmount: 10 },
    { stageNo: 2, collectCount: 5, rewardItemNo: 10000002, rewardAmount: 5 },
    { stageNo: 3, collectCount: 10, rewardItemNo: 10000003, rewardAmount: 100 },
];

/**
 * 簡單單機版遊戲服務，示範用 class 非真實實現情境
 * 可考慮繼承 SimpleSingleGameService class 實現真實遊戲邏輯
 */
@ccclass('SimpleSingleGameService')
export class SimpleSingleGameService implements IBaseGameService {
    // 假資料，示範用
    private fakeCollectTotal: number = 0;
    private fakeCollectCurrentStage: number = 1;
    private fakeIsCollectionOver: boolean = false;

    public async requestGameInfo(): Promise<void> {
        console.log("[SimpleSingleGameService] requestGameInfo");
    }

    public async requestGameStart(bet: number, gameMode: number, currentLevel: number): Promise<boolean> { 
        console.log("[SimpleSingleGameService] requestGameStart");
        return true;
    }

    public async requestGameAction(): Promise<void> {
        // TODO：按 log 規格需求開發
    }

    public async requestGameOver(reason: number): Promise<void> {
        console.log("[SimpleSingleGameService] requestGameOver");
    }

    public async requestGameContinue(): Promise<boolean> {
        console.log("[SimpleSingleGameService] requestGameContinue");
        return true;
    }

    public canGameContinueFromOver(): boolean {
        return true;
    }

    public computeGameoverContinueCost(): number {
        return 0;
    }

    public getItemAmount(itemId: number): number { 
        return 0;
    }

    public async requestUseItem(id: number): Promise<boolean> {
        console.log("[SimpleSingleGameService] requestUseItem", id);
        return true;
    }

    public computeItemCost(id: number): number {
        return 0;
    }

    public async requestCollectActivityState(mode?: number): Promise<void> {
        console.log("[SimpleSingleGameService] requestCollectActivityState");
        // 準備好並送出 SingleGameCollectActivityState，這裡示範假資料
        const stateData = this.buildFakeCollectActivityState();
        BaseGameEvent.emit(BaseGameEventDefine.CollectActivityState, stateData);
    }

    /**
     * 建立收集活動狀態資料
     */
    private buildFakeCollectActivityState(): SingleGameCollectActivityState {
        return {
            config: {
                stageConfigsList: FAKE_COLLECTACTIVITY_STAGE_CONFIGS,
                collectObjectNo: 1,
            },
            player: {
                currentStage: this.fakeCollectCurrentStage,
                currentCount: this.fakeCollectTotal,
                isOver: this.fakeIsCollectionOver,
            },
        };
    }

    public async requestAddCollections(count: number, mode?: number): Promise<boolean> {
        console.log("[SimpleSingleGameService] requestAddCollections");
        this.fakeCollectTotal += count;
        BaseGameEvent.emit(BaseGameEventDefine.CollectProgressRefresh, this.fakeCollectTotal); // 更新收集進度
        return true;
    }
    
    public async requestClaimCollectedRewards(rewardCallback?: (rewards: PlatformModule.IItem[]) => void, mode?: number): Promise<boolean> {
        console.log("[SimpleSingleGameService] requestClaimCollectedRewards");
        
        // 只為了示範 Server 端流程，Client 不必實現此邏輯流程
        // 已完成所有階段，無法領取
        if (this.fakeIsCollectionOver) {
            console.log("[SimpleSingleGameService] All stages completed, no rewards to claim");
            return false;
        }
        // 取得當前階段設定
        const stageConfig = FAKE_COLLECTACTIVITY_STAGE_CONFIGS.find(s => s.stageNo === this.fakeCollectCurrentStage);
        if (!stageConfig) {
            console.log("[SimpleSingleGameService] Stage config not found for stage:", this.fakeCollectCurrentStage);
            return false;
        }
        // 檢查是否達到領獎門檻
        if (this.fakeCollectTotal < stageConfig.collectCount) {
            console.log("[SimpleSingleGameService] Not enough collected:", this.fakeCollectTotal, "/", stageConfig.collectCount);
            return false;
        }
        // 建立獎勵資料
        const rewards: PlatformModule.IItem[] = [{
            itemNo: stageConfig.rewardItemNo,
            amount: stageConfig.rewardAmount.toString(),
        }];
        // 更新狀態：扣除本階段收集數，進入下一階段
        this.fakeCollectTotal -= stageConfig.collectCount;
        const isLastStage = this.fakeCollectCurrentStage >= FAKE_COLLECTACTIVITY_STAGE_CONFIGS.length;
        if (isLastStage) {
            this.fakeIsCollectionOver = true;
        } else {
            this.fakeCollectCurrentStage++;
        }
        // 真實 Server 端會一次發出所有可領取階段獎勵

        // 呼叫獎勵回調顯示獲獎
        if (rewardCallback) {
            rewardCallback(rewards);
        }

        console.log("[SimpleSingleGameService] Reward claimed, new stage:", this.fakeCollectCurrentStage, "isOver:", this.fakeIsCollectionOver);
        return true;
    }
}

