import { _decorator, Component, Node , Prefab, instantiate, Canvas, assetManager, Camera, CCString, CCBoolean, isValid } from 'cc';
import * as PlatformModule from './PlatformModule';
import { BaseGameLobby } from './BaseGameLobby';
import { BaseGamePlay } from './BaseGamePlay';
import { BaseGameResult } from './BaseGameResult';
import { BaseGameEvent} from './BaseGameEvent';
import { BaseGameState, BaseGameEventDefine } from './BaseGameDefine';
import { BaseGameData } from './BaseGameData';

const { ccclass, property } = _decorator;

@ccclass('BaseGameMain')
export class BaseGameMain extends Component {

    @property({type: Number, tooltip: "於GameDef中設定的遊戲ID"})
    gameID : number = 0;

    @property({type:Canvas, tooltip: "主畫布, 會自動設定camera"})
    canvas: Canvas = null;

    @property({type: CCString, tooltip: "繼承BaseGameLobby的遊戲大廳prefab路徑", visible: PlatformModule.HasPlatformModule})
    gameLobbyPrefabPath: string = "";

    @property({type:Prefab, tooltip: "繼承BaseGameLobby的遊戲大廳prefab"})
    gameLobbyPrefab: Prefab = null;

    @property({type:Node, tooltip: "遊戲大廳掛上的節點, 無設定即為此節點"})
    gameLobbyRoot: Node = null;

    @property({type: CCString, tooltip: "繼承BaseGamePlay的遊戲核心prefab路徑", visible: PlatformModule.HasPlatformModule})
    gamePlayPrefabPath: string = "";

    @property({type:Prefab, tooltip: "繼承BaseGamePlay的遊戲核心prefab"})
    gamePlayPrefab: Prefab = null;

    @property({type:Node, tooltip: "遊戲核心掛上的節點, 無設定即為此節點"})
    gamePlayRoot: Node = null;

    @property({type: CCString, tooltip: "繼承BaseGameResult的遊戲結算prefab路徑", visible: PlatformModule.HasPlatformModule})
    gameResultPrefabPath: string = "";

    @property({type:Prefab, tooltip: "繼承BaseGameResult的遊戲結算prefab"})
    gameResultPrefab: Prefab = null;

    @property({type:Node, tooltip: "遊戲結算掛上的節點, 無設定即為此節點"})
    gameResultRoot: Node = null;
    
    @property({type:Camera, tooltip: "獨立本地運行時,canvas使用的2D camera"})
    devCamera: Camera = null;

    @property(CCBoolean)
    preInstallAllPrefabs: boolean = false;

    protected gameLobby : BaseGameLobby = null;
    protected gamePlay : BaseGamePlay = null;
    protected gameResult : BaseGameResult = null;
    protected curGameState : BaseGameState = BaseGameState.NONE;
    private loadedPrefabs: Prefab[] = [];
    private lobbyLoadingPromise: Promise<void> = undefined;
    private playLoadingPromise: Promise<void> = undefined;
    private resultLoadingPromise: Promise<void> = undefined;

    protected async onLoad(){
        //init
        let gameEvent = BaseGameEvent.Instance;
        PlatformModule.loadModule(this.node);
        this.curGameState = BaseGameState.NONE;

        BaseGameData.Instance.GameID = this.gameID;
        if (PlatformModule.HasPlatformModule) {
            BaseGameData.Instance.GameBundleName = PlatformModule.GameDefine?.Infos.get(this.gameID)?.bundleName ?? "";
        }
        BaseGameData.Instance.HasPlatformModule = PlatformModule.HasPlatformModule;
        BaseGameData.Instance.IsLoginFromPlatform = (PlatformModule.PlatformApp?.CrldSession?.Token != null);

        console.log("[BaseGameMain] isLoginFromPlatform, hasPlatformModule:", BaseGameData.Instance.IsLoginFromPlatform, BaseGameData.Instance.HasPlatformModule);

        if (this.preInstallAllPrefabs) {
            let promises = [];
            promises.push(this.loadAndInstallLobbyPrefab());
            promises.push(this.loadAndInstallPlayPrefab());
            promises.push(this.loadAndInstallResultPrefab());
        } else {
            this.preloadPrefabs();
        }

        if(this.canvas)
        {
            //使用平台提供的camera
            if(BaseGameData.Instance.IsLoginFromPlatform){
                this.canvas.cameraComponent = PlatformModule.CommonUI?.UICamera;
                if(this.devCamera){
                    this.devCamera.node.active = false;
                }
            }else{
                //使用開發者提供的camera
                this.devCamera.node.active = true;
                this.canvas.cameraComponent = this.devCamera;
            }
        }

        //註冊事件
        BaseGameEvent.on(BaseGameEventDefine.ChangeBaseGameState, this.changeGameState, this);

    }

    protected start(){

    }
    

    protected onDestroy(){

        //解註冊
        BaseGameEvent.off(BaseGameEventDefine.ChangeBaseGameState, this.changeGameState, this);
        BaseGameEvent.clearAll();
        BaseGameData.clearAll();
        PlatformModule.GameColleDataModel?.DisposeCollectionCaches()

        this.loadedPrefabs.forEach(prefab => {
            if (prefab?.isValid) {
                prefab.decRef();
            }
        });
    }

    //需在start 後呼叫
    public async changeGameState( state: BaseGameState, isContinue:boolean=false ,gamePlayArg?:any ) {
        switch(this.curGameState){
            case BaseGameState.GAME_LOBBY:
                await this.leaveGameLobby();
                break;
            case BaseGameState.GAME_PLAY:
                await this.leaveGamePlay();
                break;
            case BaseGameState.GAME_RESULT:
                await this.leaveGameResult();
                break;
        }

        this.curGameState = state;

        switch(this.curGameState){
            case BaseGameState.GAME_LOBBY:
                await this.enterGameLobby();
                break;
            case BaseGameState.GAME_PLAY:
                await this.enterGamePlay(isContinue, gamePlayArg);
                break;
            case BaseGameState.GAME_RESULT:
                await this.enterGameResult();
                break;
            case BaseGameState.To_GAME_LOBBY:
                await this.backToPlatformLobby();
                break;
        }
    }



    protected async enterGameLobby() {

        let quitGame = PlatformModule.PlatformService?.Instance.checkKickGame(BaseGameData.Instance.GameID.toString());
        if(quitGame){
            return;
        }

        if(this.gameLobby == null) {
            await this.loadAndInstallLobbyPrefab();
            let gameLobbyNode = instantiate(this.gameLobbyPrefab);
            if(this.gameLobbyRoot){
                this.gameLobbyRoot.addChild(gameLobbyNode);
            }else{
                this.node.addChild(gameLobbyNode);
            }
            this.gameLobby = gameLobbyNode.getComponent(BaseGameLobby);
        }

        await this.gameLobby.enter();

        if (this.gamePlay && isValid(this.gamePlay.node, true)) {
            if (this.gamePlay.destroyInGameLobbyEnter) {
                this.gamePlay.node.destroy();
                this.gamePlay = null;
            } else if (this.gamePlay.deactiveInGameLobbyEnter) {
                this.gamePlay.node.active = false;
            }
        }
    }

    protected async leaveGameLobby() {
        if(this.gameLobby != null) {
            await this.gameLobby.exit();

            if(this.gameLobby.destoryWhenExit){
                this.gameLobby.node.destroy();
                this.gameLobby = null;
            }
        }
    
    }

    protected async enterGamePlay( isContinue:boolean, arg?:any ) {

        //遊戲是否開啟
        let quitGame = PlatformModule.PlatformService?.Instance.checkKickGame(BaseGameData.Instance.GameID.toString());
        if(quitGame){
            return;
        }

        // 關閉遊戲邀請
        if (!PlatformModule.InviteService?.Instance.isGameMasking) {
            PlatformModule.InviteService?.Instance.SetGameMask(true); 
        }


        if(this.gamePlay == null) {
            await this.loadAndInstallPlayPrefab();
            let gamePlayNode = instantiate(this.gamePlayPrefab);
            if(this.gameLobbyRoot){
                this.gamePlayRoot.addChild(gamePlayNode);
            }else{
                this.node.addChild(gamePlayNode);
            }
            this.gamePlay = gamePlayNode.getComponent(BaseGamePlay);
        }

        await this.gamePlay.enter(isContinue,arg);
    
    }

    protected async leaveGamePlay() {
        if(this.gamePlay != null) {
            await this.gamePlay.exit();
            if(this.gamePlay.destoryWhenExit){
                this.gamePlay.node.destroy();
                this.gamePlay = null;
            }
        }

        if (PlatformModule.InviteService?.Instance.isGameMasking) {
            PlatformModule.InviteService?.Instance.SetGameMask(false); // 開啟遊戲邀請
        }

    }

    protected async enterGameResult() {
        if(this.gameResult == null) {
            await this.loadAndInstallResultPrefab();
            let gameResultNode = instantiate(this.gameResultPrefab);
            if(this.gameResultRoot){
                this.gameResultRoot.addChild(gameResultNode);
            }else{
                this.node.addChild(gameResultNode);
            }
            this.gameResult = gameResultNode.getComponent(BaseGameResult);
        }
        await this.gameResult.enter();
    }

    protected async leaveGameResult() {
        if(this.gameResult != null) {
            await this.gameResult.exit();
            if(this.gameResult.destoryWhenExit){
                this.gameResult.node.destroy();
                this.gameResult = null;
            }
        }
    }

    protected async backToPlatformLobby() {
        await this.leaveGamePlay();
        await this.leaveGameLobby();
        PlatformModule.SceneManager?.Instance.ToPlatform(PlatformModule.Define?.UIPanel.LobbyUI);
    }

    protected loadAndInstallLobbyPrefab(): Promise<void> {
        if (this.gameLobbyPrefab) {
            return Promise.resolve();
        }
        if (this.lobbyLoadingPromise === undefined) {
            this.lobbyLoadingPromise = new Promise((resolve, reject) => {
                this.loadPrefab(this.gameLobbyPrefabPath, (result: boolean, prefab: Prefab) => {
                    this.gameLobbyPrefab = prefab;
                    if (result) {
                        resolve();
                    } else {
                        reject();
                    }
                    this.lobbyLoadingPromise = undefined;
                });
            });        
        }
        return this.lobbyLoadingPromise;
    }

    protected loadAndInstallPlayPrefab(): Promise<void> {
        if (this.gamePlayPrefab) {
            return Promise.resolve();
        }
        if (this.playLoadingPromise === undefined) {
            this.playLoadingPromise = new Promise((resolve, reject) => {
                this.loadPrefab(this.gamePlayPrefabPath, (result: boolean, prefab: Prefab) => {
                    this.gamePlayPrefab = prefab;
                    if (result) {
                        resolve();
                    } else {
                        reject();
                    }
                    this.playLoadingPromise = undefined;
                });
            });
        }
        return this.playLoadingPromise;
    }

    protected loadAndInstallResultPrefab(): Promise<void> {
        if (this.gameResultPrefab) {
            return Promise.resolve();
        }
        if (this.resultLoadingPromise === undefined) {
            this.resultLoadingPromise = new Promise((resolve, reject) => {
                this.loadPrefab(this.gameResultPrefabPath, (result: boolean, prefab: Prefab) => {
                    this.gameResultPrefab = prefab;
                    if (result) {
                        resolve();
                    } else {
                        reject();
                    }
                    this.resultLoadingPromise = undefined;
                });
            });
        }
        return this.resultLoadingPromise;
    }

    protected loadPrefab(path: string, onComplete?: (succ: boolean, prefab: Prefab) => void) {
        if (!path || path === "") {
            onComplete?.(false, null);
            return;
        }
        if (!PlatformModule.GameDefine ||
            !PlatformModule.GameDefine.Infos.has(BaseGameData.Instance.GameID)) {
            onComplete?.(false, null);
            return;
        }
        let assetbundle = assetManager.getBundle(
            PlatformModule.GameDefine.Infos.get(BaseGameData.Instance.GameID).bundleName);
        if (!assetbundle) {
            onComplete?.(false, null);
            return;
        }
        return assetbundle.load(path, Prefab, (err, prefab) => {
            if (!this || !this.isValid) { // destroyed
                return;
            }
            if (err) {
                console.error(err);
                onComplete?.(false, null);
                return;
            }
            if (prefab?.isValid) {
                prefab.addRef();
            }
            this.loadedPrefabs.push(prefab);
            onComplete?.(true, prefab);
        });
    }

    private preloadPrefabs() {
        if (!PlatformModule.GameDefine ||
            !PlatformModule.GameDefine.Infos.has(BaseGameData.Instance.GameID)) {
            return;
        }
        let assetbundle = assetManager.getBundle(
            PlatformModule.GameDefine.Infos.get(BaseGameData.Instance.GameID).bundleName);
        if (!assetbundle) {
            return;
        }
        if (this.gameLobbyPrefabPath) {
            assetbundle.preload(this.gameLobbyPrefabPath, Prefab);
        }
        if (this.gamePlayPrefabPath) {
            assetbundle.preload(this.gamePlayPrefabPath, Prefab);
        }
        if (this.gameResultPrefabPath) {
            assetbundle.preload(this.gameResultPrefabPath, Prefab);
        }
    }
}


