import { _decorator, Component, Node, Label, Button } from 'cc';

const { ccclass, property } = _decorator;

@ccclass('BlindSelectPanel')
export class BlindSelectPanel extends Component {

    public onSelectSmallBlind: () => void;
    public onSelectLargeBlind: () => void;
    public onSelectBossBlind: () => void;

    public set smallBlindDescription(text: string) {
        if (this.smallBlindLabel) this.smallBlindLabel.string = text;
    }
    public set largeBlindDescription(text: string) {
        if (this.largeBlindLabel) this.largeBlindLabel.string = text;
    }
    public set bossBlindDescription(text: string) {
        if (this.bossBlindLabel) this.bossBlindLabel.string = text;
    }

    public setBlindCompleted(levelIndex: number, completed: boolean): void {
        const button = levelIndex === 1 ? this.smallBlindButton
                     : levelIndex === 2 ? this.largeBlindButton
                     : this.bossBlindButton;
        const label  = levelIndex === 1 ? this.smallBlindLabel
                     : levelIndex === 2 ? this.largeBlindLabel
                     : this.bossBlindLabel;
        if (button) button.interactable = !completed;
        if (label && completed) label.string = '✓ 已完成';
    }

    @property(Label)
    private smallBlindLabel: Label | null = null;

    @property(Label)
    private largeBlindLabel: Label | null = null;

    @property(Label)
    private bossBlindLabel: Label | null = null;

    @property(Button)
    private smallBlindButton: Button | null = null;

    @property(Button)
    private largeBlindButton: Button | null = null;

    @property(Button)
    private bossBlindButton: Button | null = null;

    @property(Node)
    private gameCreditNode: Node | null = null;

    protected start(): void {
        if (this.smallBlindButton) {
            this.smallBlindButton.node.on(Button.EventType.CLICK, this.onSelectSmallBlind, this);
        }
        if (this.largeBlindButton) {
            this.largeBlindButton.node.on(Button.EventType.CLICK, this.onSelectLargeBlind, this);
        }
        if (this.bossBlindButton) {
            this.bossBlindButton.node.on(Button.EventType.CLICK, this.onSelectBossBlind, this);
        }
    }
    protected onDestroy(): void {
        this.smallBlindButton?.node.targetOff(this);
        this.largeBlindButton?.node.targetOff(this);
        this.bossBlindButton?.node.targetOff(this);
    }
}