import { _decorator, Component, CCString, assetManager, Asset, AssetManager } from 'cc';
const { ccclass, property, disallowMultiple} = _decorator

import { BaseGameData } from './BaseGameData';

/**
 * 小遊戲用(加載) asset 管理器
 * 使用前必須正確設置 BaseGameData.Instance.GameBundleName，BaseGameMain.onLoad() 中已完成設置，
 * 如果沒有使用 BaseGameMain class，必須自行正確設置 BaseGameData.Instance.GameBundleName
 */
@ccclass("BaseGameAssetMgr")
@disallowMultiple
export class BaseGameAssetMgr extends Component {
    private static _instance: BaseGameAssetMgr = null;
    public static get Instance (){
        return this._instance;
    }

    private assetMap = new Map<string, Asset>();
    private gameBundle: AssetManager.Bundle | null = null;

    protected onLoad() {
        BaseGameAssetMgr._instance = this;
    }

    protected onDestroy(): void {
        this.assetMap.clear();
        BaseGameAssetMgr._instance = null;
    }

    /**
     * 從小遊戲唯一 bundle 加載取得 asset
     * @param url asset url
     * @param callback 加載失敗傳入 null
     */
    fetchAsset(url: string, callback: (asset: Asset | null) => void) {
        if( this.assetMap.has(url) ){
            callback(this.assetMap.get(url));
            return;
        }
        this.initBundle();
        if (!this.gameBundle) {
            callback(null);
            return;
        }
        this.gameBundle?.load(url, (err, asset) => {
            if (err) {
                console.warn(`[BaseGameAssetMgr] fetchAsset(${url}): error=${err}`);
                callback(null);
                return;
            }
            this.assetMap.set(url, asset);
            callback(asset);
        });
    }

    initBundle() {
        if (this.gameBundle) {
            return;
        }
        let name = BaseGameData.Instance.GameBundleName;
        this.gameBundle = assetManager.getBundle(name);
        if (!this.gameBundle) {
            console.warn(`[BaseGameAssetMgr] initBundle(): game-bundle, ${name}, not found`);
        }
    }
}
