import { _decorator, Component, Node, director, Animation } from 'cc';
import * as PlatformModule from './PlatformModule';
import { BaseGameEvent } from './BaseGameEvent';
import { BaseGameEventDefine, BaseGameState } from './BaseGameDefine';
import { BaseGameData } from './BaseGameData';

const { ccclass, property } = _decorator;

@ccclass('BaseGamePlay')
export class BaseGamePlay extends Component {

    @property({type:Boolean, tooltip: "離開時是否自動銷毀"})
    destoryWhenExit: boolean = false;

    @property({type:Boolean, tooltip: "離開時是否自動de-active"})
    deactiveWhenExit: boolean = true;

    @property({type:Boolean, tooltip: "在進入 GAME_LOBBY 時自動銷毀"})
    destroyInGameLobbyEnter: boolean = false;

    @property({type:Boolean, tooltip: "在進入 GAME_RESULT 時自動關閉"})
    deactiveInGameLobbyEnter: boolean = false;
    
    @property({type:Boolean, tooltip: "遊戲是否能暫停"})
    canPause: boolean = false;

    @property({type : Node, tooltip: "請放入 game_pause_panel prefab" ,visible() { return this.canPause; }})
    gamePauseNode: Node = null;

    @property({type:Node, tooltip: "漢堡選單", visible() { return !this.canPause; }})
    hamburgerButtonNode: Node = null;

    @property({type:Animation, tooltip: "轉場動畫"})
    transAnim: Animation = null;

    @property({type:String, tooltip: "進場動畫名稱, 無設定即不播放"})
    enterAnimName: string = "";

    @property({type:String, tooltip: "離場動畫名稱, 無設定即不播放"})
    exitAnimName: string = "";



    private topbarDef : PlatformModule.ResourceDefine.TopbarDefine = null;
    private gamePause : any = null;
    
    protected onLoad(): void {

    }

    protected start(): void {
        
    }

    protected onEnable(): void {
        
    }

    protected onDisable(): void {
        
    }

    protected onDestroy(): void {
    }


    public async enter(isContinue:boolean, arg?:any){

        if(this.canPause){
            this.gamePause = this.gamePauseNode?.getComponent(PlatformModule.GamePause);
            if(this.gamePause == null){
                console.error("BaseGamePlay : gamePauseNode must have GamePause component");
            }
        }else{
            if(this.gamePauseNode){
                this.gamePauseNode.active = false;
            }
        }

        this.node.active = true;
        PlatformModule.FireBaseAnalytics?.instance.logEvent(PlatformModule.FireBaseLogEventExt.START_GAME, 
            { identification: PlatformModule.CommApp.instance.id, 
              gameID: PlatformModule.PlatformApp.openingGameInfo.gameID,
            });
        if(!BaseGameData.Instance.HideCommonUI){
            this.setTopbar();
        }

        if(this.transAnim && (this.enterAnimName.length > 0)){
            this.transAnim.play(this.enterAnimName);
            //等待動畫播完
            await new Promise<void>(resolve => {
                this.transAnim.once(Animation.EventType.FINISHED, () => {
                    resolve();
                }, this);
            });
        }

        if(isContinue){
            this.continueGame( arg );
        }else{
            this.startGame( arg );
        }
    }

    public async exit(){
        if(!BaseGameData.Instance.HideCommonUI){
            PlatformModule.CommonUI?.CloseNowTopBar();
        }

        if(this.gamePause){
            this.gamePause.clearAllCallback();
        }

        if(this.transAnim && (this.exitAnimName.length > 0)){
            this.transAnim.play(this.exitAnimName);
            //等待動畫播完
            await new Promise<void>(resolve => {
                this.transAnim.once(Animation.EventType.FINISHED, () => {
                    if(this.deactiveWhenExit){
                        this.node.active = false;
                    }
                    resolve();
                }, this);
            });
        }else{
            if(this.deactiveWhenExit){
                this.node.active = false;
            }
        }
    }

    //重頭開始遊戲
    protected startGame( arg?:any ){
    
    }

    //若斷線重連需要一半開始的遊戲, 會經由continue game進入, 使用本地暫存的進度繼續遊戲
    protected continueGame( arg?: any ){
        
    
    }

    //暫停遊戲
    protected pauseGame(){
        
    }

    //繼續遊戲
    protected resumeGame(){
    }    

    //玩家主動結束遊戲, 如果有需進入勝負宣告, 如果沒有須前往公版結算(goToResult)
    protected forceEndGame(){
    }
    

    //往公版結算
    protected goToResult(){
        BaseGameEvent.emit(BaseGameEventDefine.ChangeBaseGameState, BaseGameState.GAME_RESULT);
    }
    
    //設定自定義Topbar
    protected setCustomTopbarDefine(topbarDef : PlatformModule.ResourceDefine.TopbarDefine): void {
        this.topbarDef = topbarDef;    
    }

    protected setTopbar(): void {
        let define: PlatformModule.ResourceDefine.TopbarDefine;
        define = this.topbarDef;
        if(define == null){
            define = new PlatformModule.ResourceDefine.TopbarDefine("", PlatformModule.TopbarType.None);
        }
        
        this.gamePauseNode && (this.gamePauseNode.active = this.canPause);
        this.hamburgerButtonNode && (this.hamburgerButtonNode.active = !this.canPause);

        if(this.canPause){
            //可暫停的遊戲, 顯示暫停鈕
            this.gamePause.registerLeaveCallback(this.forceEndGame.bind(this));
            this.gamePause.registerPauseCallback(this.pauseGame.bind(this));
            this.gamePause.registerEndPauseCallback(this.resumeGame.bind(this));
        }else{
            //不可暫停的遊戲, 顯示漢堡選單
            if(this.hamburgerButtonNode){
                let hamburgerButton = this.hamburgerButtonNode.getComponent(PlatformModule.GameSysHamburgerButton);
                hamburgerButton && (hamburgerButton.LeaveConfirmDelegate = this.forceEndGame.bind(this));
            }
        }
        PlatformModule.CommonUI?.SetLobbyTopbar(define);
    }  


}


