import { _decorator, Component, Node, Button, EventHandler, Animation, Enum } from 'cc';
import * as PlatformModule from './PlatformModule';
import { BaseGameEvent } from './BaseGameEvent';
import { BaseGameEventDefine, BaseGameState } from './BaseGameDefine';
import { BaseGameData } from './BaseGameData';

const { ccclass, property } = _decorator;

@ccclass('BaseGameLobby')
export class BaseGameLobby extends Component {

    @property({type:Boolean, tooltip: "離開時是否自動銷毀"})
    destoryWhenExit: boolean = true;

    @property({type:Boolean, tooltip: "離開時是否自動de-active"})
    deactiveWhenExit: boolean = true;     

    @property({type:Animation, tooltip: "轉場動畫"})
    transAnim: Animation = null;

    @property({type:String, tooltip: "進場動畫名稱, 無設定即不播放"})
    enterAnimName: string = "";

    @property({type:String, tooltip: "離場動畫名稱, 無設定即不播放"})
    exitAnimName: string = "";

    @property({type:Enum(PlatformModule.TopbarHamburgerPos), tooltip: "天bar漢堡選單位置"})
    hamburgerPos: PlatformModule.TopbarHamburgerPos = PlatformModule.TopbarHamburgerPos.Left;


    protected onEnable(): void {
    }

    protected onDisable(): void {
    }


    public async enter(){
        this.node.active = true;
        PlatformModule.FireBaseAnalytics?.instance.logEvent(PlatformModule.FireBaseLogEventExt.ENTER_GAMELOBBY, 
            { identification: PlatformModule.CommApp.instance.id, 
              gameID: PlatformModule.PlatformApp.openingGameInfo.gameID,
            });
        if(!BaseGameData.Instance.HideCommonUI){
            this.setTopbar();
        }

        if(this.transAnim && (this.enterAnimName.length > 0)){
            this.transAnim.play(this.enterAnimName);
            //等待動畫播完
            await new Promise<void>(resolve => {
                this.transAnim.once(Animation.EventType.FINISHED, () => {
                    resolve();
                }, this);
            });
        }
    }

    public async exit(){
        if(!BaseGameData.Instance.HideCommonUI){
            PlatformModule.CommonUI?.CloseNowTopBar();
        }

        if(this.transAnim && (this.exitAnimName.length > 0)){
            this.transAnim.play(this.exitAnimName);
            //等待動畫播完
            await new Promise<void>(resolve => {
                this.transAnim.once(Animation.EventType.FINISHED, () => {
                    if(this.deactiveWhenExit){
                        this.node.active = false;
                    }
                    resolve();
                }, this);
            });
        }else{
            if(this.deactiveWhenExit){
                this.node.active = false;
            }
        }

    }



    protected startGame( arg? : any ){
        BaseGameEvent.emit(BaseGameEventDefine.ChangeBaseGameState, BaseGameState.GAME_PLAY ,false,arg);
    }

    protected backToPlatformLobby(){
        BaseGameEvent.emit(BaseGameEventDefine.ChangeBaseGameState, BaseGameState.To_GAME_LOBBY);
    }

    protected onClickTopbarTip(){
       
    }

    protected setTopbar() {
        let define: PlatformModule.ResourceDefine.TopbarDefine = new PlatformModule.ResourceDefine.TopbarDefine(PlatformModule.GameDefine?.Infos.get(BaseGameData.Instance.GameID).name, PlatformModule.TopbarType.Default);
        define.ExitEvent = this.backToPlatformLobby.bind(this);
        define.TipEvent = this.onClickTopbarTip.bind(this);
        define.IsShowBuff = true;
        define.HamburgerPos = this.hamburgerPos;
        define.CustomHamburgerMenuStyle= new PlatformModule.ResourceDefine.CustomHamburgerMenu(null, PlatformModule.ResourceDefine.DefaultHamburgerMenuPreset.InGameDefaultSetting);

        PlatformModule.CommonUI?.SetLobbyTopbar(define);

    }

}


