import { _decorator, Component, Node, isValid, Vec2, CCBoolean, ProgressBar, Animation, Sprite, SpriteFrame, Label, CCString, UITransform, Tween, tween } from 'cc';
import { BaseGameAssetMgr } from '@gamecommon/base/BaseGameAssetMgr';
import { SingleGameCollectActivityManager } from '../SingleGameCollectActivityManager';
import * as PlatformModule from '@gamecommon/base/PlatformModule';
const { ccclass, property } = _decorator;

@ccclass('SingleGameCollectionProgressIconSetting')
export class SingleGameCollectionProgressIconSetting {
    @property(Sprite)
    public collectionSprite: Sprite = null
    @property(Sprite)
    public itemIcon: Sprite = null
    @property({type: CCString, displayName: '收集物 Sprite 格式化路徑', 
        tooltip: '使用 {id} 替換目標物件ID-SpriteFrame，填入 asset Path 如 image/good{id}/spriteFrame'})
    public collectionSpritePathFormat: string = 'image/good_{id}/spriteFrame';
    @property(Vec2)
    public rewardTargetSize: Vec2 = new Vec2(240, 240);
    @property(CCBoolean)
    public rewardUseSmallSprite: boolean = false;
}

@ccclass('SingleGameCollectionProgress')
export class SingleGameCollectionProgress extends Component {
    @property(SingleGameCollectionProgressIconSetting)
    public iconSetting: SingleGameCollectionProgressIconSetting = new SingleGameCollectionProgressIconSetting();
    @property(ProgressBar)
    public progress: ProgressBar = null
    @property(Label)
    public progressLabel: Label = null
    @property(Node)
    public redpoint: Node = null
    @property(CCBoolean)
    public showAni: boolean = false;

    private get rewardIcon() {
        return this.iconSetting.itemIcon;
    }
    private get collectionIcon() {
        return this.iconSetting.collectionSprite;
    }
    private get collectionSpritePathFormat() {
        return this.iconSetting.collectionSpritePathFormat;
    }

    /** 已通過或不設限請回傳 0 */
    public getActivityOpenLevel: () => number = () => 0;

    private guiSprites: Sprite[] = [];
    
    protected onEnable(): void {
        this.setupCollectionSprite();
    }

    protected onDisable(): void {
    }

    private onCollectionReward() {
        this.updateProgress()
    }

    public updateOldProgress() {
        const manager = SingleGameCollectActivityManager.Instance;
        const singleGameActivityStartLevel = this.getActivityOpenLevel?.() ?? 0;
        if (!manager.isOpenAndValid()) {
            this.progressLabel.string = `關卡 ${singleGameActivityStartLevel + 1} 解鎖`;
            this.progress.progress = 0;
            this.rewardIcon.node.active = true;
            this.setupRewardIconSprite();
            this.showRedPoint(false);
            this.grayedOutGuis(true);
            return;
        }
        this.grayedOutGuis(false);
        
        const total = manager.StageTargetCollectCount;
        const current = manager.Over ? total : manager.OldCollectionCount;
        this.progressLabel.string = `${current}/${total}`;
        this.progress.progress = current / total;
        if (manager.Over) {
            this.rewardIcon.node.active = false;
            this.showRedPoint(false);
        } else {
            this.rewardIcon.node.active = true;
            this.setupRewardIconSprite();
            this.showRedPoint(current >= total);
        }
    }

    public async updateProgress(ani: boolean = false) {
        const manager = SingleGameCollectActivityManager.Instance;
        const total = manager.StageTargetCollectCount;
        if (manager.Over) {
            this.progressLabel.string = `${total}/${total}`;
            this.progress.progress = 1;
            this.rewardIcon.node.active = false;
            this.showRedPoint(false);
            return;
        }
        this.rewardIcon.node.active = true;
        this.setupRewardIconSprite();
        if (!ani) {
            const currentResult = manager.CollectedCount;
            this.progressLabel.string = `${currentResult}/${total}`;
            this.progress.progress = currentResult / total;
            this.showRedPoint(currentResult >= total);
            return;
        }
        const oldResult = manager.OldCollectionCount;
        this.progressLabel.string = `${oldResult}/${total}`;

        return new Promise<void>(resolve => {
            Tween.stopAllByTarget(this.progress);
            const tw = tween(this.progress);
            const manager = SingleGameCollectActivityManager.Instance;
            tw.to(0.5, { progress: manager.CollectedCount / manager.StageTargetCollectCount }).call(() => {
                if (this && isValid(this.node, true)) {
                    this.updateProgress();
                }
                resolve();
            }).start();
        });
    }

    private showRedPoint(show: boolean) {
        this.redpoint.active = show;
        if (!this.showAni) {
            return
        }
        const ani = this.rewardIcon.node.getComponent(Animation);
        if (show) {
            ani.play("shake");
        } else {
            ani.stop();
            this.rewardIcon.node.angle = 0;
        }
    }

    private async setupCollectionSprite() {
        const id: number = SingleGameCollectActivityManager.Instance.TargetObject;
        if (id === 0) {
            this.collectionIcon.node.active = false;
            this.collectionIcon.spriteFrame = null;
            return;
        }
        this.collectionIcon.node.active = true;
        BaseGameAssetMgr.Instance.fetchAsset(this.collectionSpritePathFormat.replace('{id}', id.toString()), (asset) => {
            if (asset && isValid(asset) && isValid(this.collectionIcon)) {
                this.collectionIcon.spriteFrame = asset as SpriteFrame;
            }
        });
    }

    private get rewardIconUseSmallSprite() {
        return this.iconSetting.rewardUseSmallSprite;
    }
    private get rewardIconTargetSize() {
        return this.iconSetting.rewardTargetSize;
    }
    
    private async setupRewardIconSprite() {
        const id: number = SingleGameCollectActivityManager.Instance.TargetReward;
        if (id === 0) {
            return;
        }

        let item = PlatformModule.ItemFactory?.Instance?.GetItemById(id);
        if (!item) {
            return;
        }

        let spriteFrame: SpriteFrame | null = null;
        if (this.rewardIconUseSmallSprite) {
            spriteFrame = await item.GetSmallImage();
        }
        if (!isValid(spriteFrame)) {
            spriteFrame = await item.GetImage();
        }
        if (!isValid(spriteFrame) || !isValid(this.rewardIcon)) {
            return;
        }
        this.rewardIcon.sizeMode = Sprite.SizeMode.CUSTOM;
        this.rewardIcon.getComponent(UITransform).setContentSize(this.rewardIconTargetSize.x, this.rewardIconTargetSize.y);
        this.rewardIcon.spriteFrame = spriteFrame;
    }

    private grayedOutGuis(gray: boolean) {
        if (this.guiSprites.length === 0) {
            this.guiSprites = this.node.getComponentsInChildren(Sprite);
        }
        this.guiSprites.forEach(sprite => {
            sprite.grayscale = gray;
        });
    }
    
}


