import { _decorator, Component, Node, Label, Button, Vec3, tween, UIOpacity, Color, ProgressBar } from 'cc';
import { GameEngine } from '../engine/GameEngine';
import { HandView } from './components/HandView';
import { CardInteraction } from './components/CardInteraction';
import { CardView } from './components/CardView';
import { GamePhase } from '../types/GamePhase';
import { BlindSelectPanel } from './components/BlindSelectPanel';
import { HandsRulePanel } from './components/HandsRulePanel';
import { JokerDraftPanel } from './components/JokerDraftPanel';
import { evaluateLevel } from '../engine/Evaluator';
import { getDraftOffer } from '../engine/JokerCatalog';
import { Card } from '../types';
import { JokerEffect, DrawJokerEffect } from '../types/PlayHandResult';
import { screenShake, scalePunch } from './utils/JuiceUtils';
import { __private } from 'cc';
import { Sprite } from 'cc';
import { profiler } from 'cc';

const { ccclass, property } = _decorator;

@ccclass('GameRendererEngine')
export class GameRendererEngine extends Component {

    public engine: GameEngine;

    private cardNodes: Map<string, Node> = new Map();
    private jokerNodes: Map<string, Node> = new Map();
    private _blindLevelIndices: number[] = [];

    @property(HandView)
    handView: HandView | null = null;

    @property(BlindSelectPanel)
    blindSelectPanel: BlindSelectPanel | null = null;

    @property(Button)
    playButton: Button | null = null;

    @property(Button)
    discardButton: Button | null = null;

    @property(Button)
    sortByCardRankButton: Button | null = null;

    @property(Button)
    sortByCardSuitButton: Button | null = null;

    @property(Label)
    sortByCardRankIconLabel: Label | null = null;

    @property(Label)
    sortByCardSuitIconLabel: Label | null = null;

    @property(Button)
    claimRewardButton: Button | null = null;

    @property(Button)
    leaveShopButton: Button | null = null;

    @property(Button)
    startButton: Button | null = null;

    @property(Label)
    scoreLabel: Label | null = null;

    @property(Label)
    cardDeckLabel: Label | null = null;

    @property(Label)
    targetScoreLabel: Label | null = null;

    @property(Label)
    handsLeftLabel: Label | null = null;

    @property(Label)
    discardsLeftLabel: Label | null = null;

    @property(Label)
    moneyLabel: Label | null = null;

    @property(Label)
    anteRoundLabel: Label | null = null;

    @property(Label)
    currentHandTypeLabel: Label | null = null;

    @property(Label)
    runningChipsLabel: Label | null = null;

    @property(Label)
    runningMultLabel: Label | null = null;

    @property(Node)
    shopPanel: Node | null = null;

    @property(JokerDraftPanel)
    jokerDraftPanel: JokerDraftPanel | null = null;

    @property(Node)
    gameplayPanel: Node | null = null;

    @property(Node)
    claimRewardPanel: Node | null = null;

    @property(Node)
    gameOverPanel: Node | null = null;

    @property(Node)
    discardArea: Node | null = null;

    @property(Node)
    playHandArea: Node | null = null;

    @property(Label)
    valuePopupLabel: Label | null = null;

    @property(Label)
    climaxLabel: Label | null = null;

    @property(ProgressBar)
    scoreProgressBar: ProgressBar | null = null;

    @property(Label)
    levelNameLabel: Label | null = null;

    @property(Button)
    tutorialButton: Button | null = null;

    @property(Button)
    handsRuleButton: Button | null = null;

    @property(HandsRulePanel)
    handsRulePanel: HandsRulePanel | null = null;

    @property(Node)
    gameCompleteNode: Node | null = null;

    private static readonly HAND_TYPE_RANK: Record<string, number> = {
        'High Card': 0,
        'Pair': 1,
        'Two Pair': 2,
        'Three of a Kind': 3,
        'Straight': 4,
        'Flush': 5,
        'Full House': 6,
        'Four of a Kind': 7,
        'Straight Flush': 8,
    };

    private static readonly HAND_NAME_ZH: Record<string, string> = {
        'High Card': '高牌',
        'Pair': '一對',
        'Two Pair': '兩對',
        'Three of a Kind': '三條',
        'Straight': '順子',
        'Flush': '同花',
        'Full House': '葫蘆',
        'Four of a Kind': '四條',
        'Straight Flush': '同花順',
    };

    private phaseUIMap: Record<GamePhase, Node[]> = {} as any;
    private previewChips: number = 0;
    private previewMult: number = 0;
    private _prevHandTypeName: string = '';
    private _chipsLabelBaseScale: Vec3 = new Vec3(1, 1, 1);

    start() {
        this.engine = new GameEngine();
        this.init(this.engine);
        if (this.runningChipsLabel) {
            this._chipsLabelBaseScale = this.runningChipsLabel.node.scale.clone();
        }
        this.engine.setPhase(GamePhase.START);
        this.syncInitialUI();
        this._updateSortButtonVisuals();
        profiler.showStats();
    }

    init(engine: GameEngine) {
        this.engine = engine;

        const commonTopBar = [this.moneyLabel?.node, this.anteRoundLabel?.node];

        this.phaseUIMap = {
            [GamePhase.START]: [
                this.startButton?.node,
                this.tutorialButton?.node
            ].filter(Boolean) as Node[],
            [GamePhase.GAMEPLAY]: [
                ...commonTopBar,
                this.scoreLabel?.node, 
                this.targetScoreLabel?.node,
                this.handsLeftLabel?.node,
                this.discardsLeftLabel?.node,
                this.cardDeckLabel?.node,
                this.currentHandTypeLabel?.node,
                this.runningChipsLabel?.node,
                this.runningMultLabel?.node,
                this.playButton?.node,
                this.discardButton?.node,
                this.handView?.node,
                this.discardArea,
                this.playHandArea,
                this.gameplayPanel,
                this.sortByCardRankButton?.node,
                this.sortByCardSuitButton?.node,
                this.climaxLabel?.node,
                this.scoreProgressBar?.node,
                this.levelNameLabel?.node,
                this.handsRuleButton?.node,
                this.handsRulePanel?.node,
            ].filter(Boolean) as Node[],

            [GamePhase.REWARD]: [
                ...commonTopBar,
                this.claimRewardPanel,
                this.claimRewardButton?.node,
            ].filter(Boolean) as Node[],

            [GamePhase.JOKER_DRAFT]: [
                this.jokerDraftPanel?.node,
            ].filter(Boolean) as Node[],

            [GamePhase.SHOP]: [
                ...commonTopBar,
                this.shopPanel,
                this.leaveShopButton?.node,
            ].filter(Boolean) as Node[],

            [GamePhase.BLIND_SELECT]: [
                this.blindSelectPanel?.node
            ].filter(Boolean) as Node[],

            [GamePhase.GAME_OVER]: [
                this.gameOverPanel,
                this.startButton?.node,
            ].filter(Boolean) as Node[]
        };

        if (this.handView) {
            this.handView.node.on('INTENT_TOGGLE_CARD', this._onToggleCard.bind(this), this);
        }

        if (this.startButton) {
            this.startButton.node.on(Button.EventType.CLICK, this._onStartClicked, this);
        }
        if (this.playButton) {
            this.playButton.node.on(Button.EventType.CLICK, this.handlePlayHand, this);
        }
        if (this.discardButton) {
            this.discardButton.node.on(Button.EventType.CLICK, this.handleDiscard, this);
        }
        if (this.claimRewardButton) {
            this.claimRewardButton.node.on(Button.EventType.CLICK, this._onClaimRewardClicked, this);
        }
        if (this.leaveShopButton) {
            this.leaveShopButton.node.on(Button.EventType.CLICK, this._onLeaveShopClicked, this);
        }
        if (this.sortByCardRankButton) {
            this.sortByCardRankButton.node.on(Button.EventType.CLICK, this._onSortByCardRankClicked, this);
        }
        if (this.sortByCardSuitButton) {
            this.sortByCardSuitButton.node.on(Button.EventType.CLICK, this._onSortByCardSuitClicked, this);
        }
        if (this.handsRuleButton) {
            this.handsRuleButton.node.on(Button.EventType.CLICK, this._onHandsRuleClicked, this);
        }

        if (this.blindSelectPanel) {
            // FIXME: hardcode level for 1 week project practice
            const smallBlindLevelIndex = 1;
            const largeBlindLevelIndex = 2;
            const bossBlindLevelIndex = 3;
            this.blindSelectPanel.smallBlindDescription = evaluateLevel(smallBlindLevelIndex)?.blindName ?? '';
            this.blindSelectPanel.largeBlindDescription = evaluateLevel(largeBlindLevelIndex)?.blindName ?? '';
            this.blindSelectPanel.bossBlindDescription = evaluateLevel(bossBlindLevelIndex)?.blindName ?? '';
            this.blindSelectPanel.onSelectSmallBlind = () => this.handleBlindSelect(smallBlindLevelIndex);
            this.blindSelectPanel.onSelectLargeBlind = () => this.handleBlindSelect(largeBlindLevelIndex);
            this.blindSelectPanel.onSelectBossBlind = () => this.handleBlindSelect(bossBlindLevelIndex);
            this._blindLevelIndices = [smallBlindLevelIndex, largeBlindLevelIndex, bossBlindLevelIndex];
        }

        if (this.valuePopupLabel) {
            this.valuePopupLabel.node.getComponent(UIOpacity).opacity = 0;
        }
        if (this.climaxLabel) {
            this.climaxLabel.node.getComponent(UIOpacity).opacity = 0;
        }

        this.setupBindings();
    }
    private async _onSortByCardSuitClicked() {
        const sorted = this.engine.sortByCardSuit();
        this._updateSortButtonVisuals();
        await this.handView?.animateSortHand(sorted);
    }
    private async _onSortByCardRankClicked() {
        const sorted = this.engine.sortByCardRank();
        this._updateSortButtonVisuals();
        await this.handView?.animateSortHand(sorted);
    }

    private _onHandsRuleClicked() {
        if (!this.handsRulePanel) return;
        const isVisible = this.handsRulePanel.node.active;
        isVisible ? this.handsRulePanel.hide() : this.handsRulePanel.show();
    }

    private _updateSortButtonVisuals() {
        const mode = this.engine.getSortMode();
        const dir = this.engine.getSortDirection();
        const activeColor = new Color(255, 220, 80, 255);
        const inactiveColor = new Color(255, 255, 255, 50);

        if (this.sortByCardRankButton) {
            this.sortByCardRankButton.node.getComponent(Sprite).color = mode === 'rank' ? activeColor : inactiveColor;
        }
        if (this.sortByCardSuitButton) {
            this.sortByCardSuitButton.node.getComponent(Sprite).color = mode === 'suit' ? activeColor : inactiveColor;
        }

        if (this.sortByCardRankIconLabel) {
            this.sortByCardRankIconLabel.string = mode === 'rank'
                ? (dir === 'asc' ? '1→9' : '9→1')
                : '1→9';
        }
        if (this.sortByCardSuitIconLabel) {
            this.sortByCardSuitIconLabel.string = mode === 'suit'
                ? (dir === 'asc' ? '♥️ ♦️ ♣️ ♠️' : '♠️ ♣️ ♦️ ♥️')
                : '♥️ ♦️ ♣️ ♠️';
        }
    }

    // ── Reactive bindings ─────────────────────────────────────────────

    private setupBindings() {
        this.engine.selection$.bind(() => {
            if (this.handView) {
                const selectedIds = this.engine.getSelectedCards().map(c => c.id);
                this.handView.syncSelectionState(selectedIds);
            }
            this.updateButtonStates();
            this.updateHandPreview();
        });

        this.engine.phase$.bind(() => {
            this.updateUIForPhase(this.engine.phase);
        });

        this.engine.score$.bind((_prev, next) => {
            if (this.scoreLabel) this.scoreLabel.string = `${next}`;
            this.animateScoreProgress(_prev, next, this.engine.blind);
        });

        this.engine.playsLeft$.bind((_prev, next) => {
            if (this.handsLeftLabel) this.handsLeftLabel.string = `${next} / ${this.engine.maxPlayHands}`;
            this.updateButtonStates();
        });

        this.engine.discardsLeft$.bind((_prev, next) => {
            if (this.discardsLeftLabel) this.discardsLeftLabel.string = `${next} / ${this.engine.maxDiscards}`;
            this.updateButtonStates();
        });

        this.engine.blind$.bind((_prev, next) => {
            if (this.targetScoreLabel) this.targetScoreLabel.string = `${next}`;
            this.animateScoreProgress(this.engine.score, this.engine.score, next);
        });

        this.engine.money$.bind((_prev, next) => {
            if (this.moneyLabel) this.moneyLabel.string = `$${next}`;
        });

        const updateAnteLabel = () => {
            if (this.anteRoundLabel) {
                this.anteRoundLabel.string = `Ante ${this.engine.ante}/8`;
            }
        };
        this.engine.ante$.bind(updateAnteLabel);
        this.engine.currentLevel$.bind(updateAnteLabel);

        this.engine.levelData$.bind((_prev, next) => {
            if (this.levelNameLabel && next) {
                this.levelNameLabel.string = next.levelName;
            }
        });

        this.engine.completedBlinds$.bind(() => {
            this.refreshBlindStates();
        });
    }

    private refreshBlindStates() {
        if (!this.blindSelectPanel) return;
        const done = this.engine.completedBlinds;
        for (const idx of this._blindLevelIndices) {
            this.blindSelectPanel.setBlindCompleted(idx, done.has(idx));
        }
        const allComplete = this._blindLevelIndices.length > 0
            && this._blindLevelIndices.every(idx => done.has(idx));
        if (allComplete) {
            this._showGameCompleted(true);
        } else {
            this._showGameCompleted(false);
        }
    }
    private _showGameCompleted(arg0: boolean) {
        if (this.gameCompleteNode) this.gameCompleteNode.active = arg0;
    }

    private updateButtonStates() {
        if (this.playButton) this.playButton.interactable = this.engine.canPlayHand();
        if (this.discardButton) this.discardButton.interactable = this.engine.canDiscard();
    }

    private updateHandPreview() {
        if (!this.currentHandTypeLabel) return;
        const ht = this.engine.getHandType();

        const nameChanged = ht.name !== this._prevHandTypeName;
        this.currentHandTypeLabel.string = GameRendererEngine.HAND_NAME_ZH[ht.name] ?? ht.name;
        this._prevHandTypeName = ht.name;

        if (nameChanged && ht.name) {
            this._animateHandTypeChange(ht.name);
        }

        this.animateRunningScore(this.previewChips, ht.chips, this.previewMult, ht.mult);
        this.previewChips = ht.chips;
        this.previewMult = ht.mult;
    }

    private _animateHandTypeChange(handName: string): void {
        const node = this.currentHandTypeLabel?.node;
        if (!node) return;

        const rank = GameRendererEngine.HAND_TYPE_RANK[handName] ?? 0;
        const t = rank / 8; // 0.0 (High Card) → 1.0 (Straight Flush)

        tween(node).stop();

        // Punch scale grows from 1.15 at rank 0 up to 2.0 at rank 8
        const peakScale = 1.15 + t * 5;
        const duration = 0.18 + t * 0.12;
        scalePunch(node, peakScale, duration);

        // Full House and above get an extra shake to sell the impact
        if (rank >= 3) {
            screenShake(node, 2 + t * 6, 0.25);
        }
    }

    private syncInitialUI() {
        this.engine.score$.notify();
        this.engine.blind$.notify();
        this.engine.playsLeft$.notify();
        this.engine.discardsLeft$.notify();
        this.engine.money$.notify();
        this.engine.ante$.notify();
        this.engine.currentLevel$.notify();
        this.engine.levelData$.notify();
        if (this.cardDeckLabel) this.cardDeckLabel.string = `${this.engine.getDeck().length}/52`;
        if (this.scoreProgressBar) {
            this.scoreProgressBar.progress = this.engine.blind > 0
                ? Math.min(this.engine.score / this.engine.blind, 1)
                : 0;
        }
        this.updateButtonStates();
        this.updateUIForPhase(this.engine.phase);
    }

    // ── Handler methods ──────────────────────────────────────────────

    public async handlePlayHand() {
        if (!this.engine.canPlayHand()) return;

        const cardIds = this.engine.getSelectedCards().map(c => c.id);

        this.engine.score$.suppress();
        this.engine.selection$.suppress();

        const prevScore = this.engine.score;
        const result = this.engine.playHand(cardIds);
        if (!result) {
            this.engine.score$.resume();
            this.engine.selection$.resume();
            return;
        }

        await this.moveCardsToPlayArea(cardIds);

        let runningChips = result.evalResult.chips;
        let runningMult = result.evalResult.mult;

        for (const detail of result.scoringDetails) {
            const hasChips = detail.chips > 0;
            const hasMult = detail.mult > 0;
            if (!hasChips && !hasMult) continue;

            const cardNode = this.cardNodes.get(detail.cardId);
            const cardView = cardNode?.getComponent(CardView);
            if (cardView) {
                await cardView.animateScore();
            }

            if (hasChips) {
                await this.showValuePopup(detail.cardId, detail.chips, '+', 'chips');
                const prevChips = runningChips;
                runningChips += detail.chips;
                await this.animateRunningScore(prevChips, runningChips, runningMult, runningMult);
            }
            if (hasMult) {
                await this.showValuePopup(detail.cardId, detail.mult, '+', 'mult');
                const prevMult = runningMult;
                runningMult += detail.mult;
                await this.animateRunningScore(runningChips, runningChips, prevMult, runningMult);
            }
        }

        for (const effect of result.jokerEffects) {
            await this.triggerJoker(effect);
            const prevChips = runningChips;
            const prevMult = runningMult;
            if (effect.chips > 0) runningChips += effect.chips;
            if (effect.mult > 0) runningMult += effect.mult;
            await this.animateRunningScore(prevChips, runningChips, prevMult, runningMult);
        }

        await this.delay(300);

        await this.showClimaxBeat(runningChips, runningMult, result.totalScore);

        await this.animateTotalScore(prevScore, prevScore + result.totalScore);
        await this.animateScoreProgress(this.engine.score, this.engine.score + result.totalScore, this.engine.blind);
        if (this.scoreLabel) {
            await scalePunch(this.scoreLabel.node, 2, 0.3);
        }

        this.engine.score = prevScore + result.totalScore;

        await this.resetRunningScore(runningChips, runningMult);
        await this.delay(300);
        this.previewChips = 0;
        this.previewMult = 0;

        await this.moveCardsToDiscardArea(cardIds);

        this.engine.score$.resume();

        if (result.roundWon) {
            this.engine.setPhase(GamePhase.REWARD);
        } else if (result.roundLost) {
            this.engine.setPhase(GamePhase.GAME_OVER);
        } else {
            const drawResult = this.engine.drawCards();
            await this.renderHand(drawResult.hand);
            await this.triggerDrawJokers(drawResult.jokerEffects);
        }

        this.engine.selection$.resumeAndNotify();
    }

    public async handleDiscard() {
        if (this.engine.isGameOver() || !this.engine.canDiscard()) return;

        const cardIds = this.engine.getSelectedCards().map(c => c.id);

        const result = this.engine.discardHand(cardIds);
        if (!result) return;

        await this.moveCardsToDiscardArea(result.discardedCardIds);
        await this.renderHand(result.newHand);
        await this.triggerDrawJokers(result.drawJokerEffects);
    }

    public async handleBlindSelect(levelIndex: number) {
        const level = evaluateLevel(levelIndex);
        if (!level) return;
        const result = this.engine.selectLevel(level, levelIndex);
        this.syncInitialUI();
        await this.renderHand(result.newHand);
        await this.triggerDrawJokers(result.drawJokerEffects);
        this._updateSortButtonVisuals();
    }

    _onClaimRewardClicked() {
        this.engine.claimReward();
    }

    _onLeaveShopClicked() {
        this.engine.leaveShop();
    }

    _onStartClicked() {
        const offers = getDraftOffer();
        this.jokerDraftPanel?.setup(offers, (picked) => {
            this.engine.confirmJokerDraft(picked);
        });
        this.engine.setPhase(GamePhase.JOKER_DRAFT);
    }

    _onToggleCard(cardId: string) {
        this.engine.toggleCardSelection(cardId);
    }

    // ── Animation primitives ─────────────────────────────────────────

    private moveCardsToPlayArea(cardIds: string[]): Promise<void> {
        if (!this.playHandArea) return Promise.resolve();

        const spacing = 160;
        const totalWidth = (cardIds.length - 1) * spacing;
        const startX = -totalWidth / 2;

        const promises = cardIds.map((id, index) => {
            const cardNode = this.cardNodes.get(id);
            if (!cardNode) return Promise.resolve();

            const interaction = cardNode.getComponent(CardInteraction);
            if (interaction) interaction.enabled = false;

            const worldPos = cardNode.worldPosition.clone();
            cardNode.parent = this.playHandArea!;
            cardNode.setWorldPosition(worldPos);

            const targetX = startX + index * spacing;
            const cardView = cardNode.getComponent(CardView);
            if (cardView) {
                return cardView.moveToPlayArea(new Vec3(targetX, 0, 0));
            }
            return Promise.resolve();
        });
        return Promise.all(promises).then(() => {});
    }

    private moveCardsToDiscardArea(cardIds: string[]): Promise<void> {
        if (!this.discardArea) return Promise.resolve();

        const STAGGER_MS = 30;
        const promises = cardIds.map((id, index) => {
            const cardNode = this.cardNodes.get(id);
            if (!cardNode) return Promise.resolve();

            const worldPos = cardNode.worldPosition.clone();
            cardNode.parent = this.discardArea!;
            cardNode.setWorldPosition(worldPos);

            const cardView = cardNode.getComponent(CardView);
            if (cardView) {
                return cardView.animateDiscard(index * STAGGER_MS).then(() => {
                    this.cardNodes.delete(id);
                });
            }
            return Promise.resolve();
        });
        return Promise.all(promises).then(() => {});
    }

    private async triggerJoker(effect: JokerEffect): Promise<void> {
        const jokerNode = this.jokerNodes.get(effect.jokerId);
        if (!jokerNode) return;

        const pulsePromise = new Promise<void>(resolve => {
            tween(jokerNode)
                .to(0.12, { scale: new Vec3(1.35, 1.35, 1.35) }, { easing: 'quadOut' })
                .to(0.2, { scale: new Vec3(1, 1, 1) }, { easing: 'backOut' })
                .call(() => resolve())
                .start();
        });

        const labelPromise = effect.label
            ? this.showJokerLabel(jokerNode, effect.label)
            : Promise.resolve();

        await Promise.all([pulsePromise, labelPromise]);
    }

    private async triggerDrawJokers(effects: DrawJokerEffect[]): Promise<void> {
        for (const effect of effects) {
            const jokerNode = this.jokerNodes.get(effect.jokerId);
            if (!jokerNode) continue;

            const pulsePromise = new Promise<void>(resolve => {
                tween(jokerNode)
                    .to(0.12, { scale: new Vec3(1.35, 1.35, 1.35) }, { easing: 'quadOut' })
                    .to(0.2, { scale: new Vec3(1, 1, 1) }, { easing: 'backOut' })
                    .call(() => resolve())
                    .start();
            });

            const labelPromise = this.showJokerLabel(jokerNode, effect.label);
            await Promise.all([pulsePromise, labelPromise]);
        }
    }

    private showJokerLabel(anchorNode: Node, label: string): Promise<void> {
        if (!this.valuePopupLabel) return Promise.resolve();

        const popupNode = this.valuePopupLabel.node;
        const uiOpacity = popupNode.getComponent(UIOpacity) ?? popupNode.addComponent(UIOpacity);

        tween(popupNode).stop();
        tween(uiOpacity).stop();

        this.valuePopupLabel.string = label;
        this.valuePopupLabel.color = Color.WHITE;
        uiOpacity.opacity = 255;
        popupNode.active = true;

        const worldPos = anchorNode.worldPosition.clone();
        popupNode.setWorldPosition(new Vec3(worldPos.x, worldPos.y + 60, worldPos.z));
        const startPos = popupNode.position.clone();

        return new Promise(resolve => {
            tween(popupNode)
                .to(0.4, { position: new Vec3(startPos.x, startPos.y + 50, startPos.z) })
                .start();
            tween(uiOpacity)
                .delay(0.2)
                .to(0.3, { opacity: 0 })
                .call(() => {
                    popupNode.active = false;
                    resolve();
                })
                .start();
        });
    }

    private async showClimaxBeat(totalChips: number, totalMult: number, totalScore: number): Promise<void> {
        const shakeTarget = this.gameplayPanel ?? this.node;
        const shakePromise = screenShake(shakeTarget, 6, 0.3);

        const labelPunches: Promise<void>[] = [];
        if (this.runningChipsLabel) labelPunches.push(scalePunch(this.runningChipsLabel.node, 1.25, 0.25));
        if (this.runningMultLabel) labelPunches.push(scalePunch(this.runningMultLabel.node, 1.25, 0.25));

        if (this.climaxLabel) {
            const climaxNode = this.climaxLabel.node;
            const uiOpacity = climaxNode.getComponent(UIOpacity) ?? climaxNode.addComponent(UIOpacity);
            tween(climaxNode).stop();
            tween(uiOpacity).stop();

            this.climaxLabel.string = `${totalChips} × ${totalMult} = ${totalScore}`;
            uiOpacity.opacity = 255;
            climaxNode.active = true;
            climaxNode.setScale(new Vec3(0.5, 0.5, 1));

            labelPunches.push(scalePunch(climaxNode, 1.3, 0.3));
        }

        await Promise.all([shakePromise, ...labelPunches]);
        await this.delay(400);

        if (this.climaxLabel) {
            const climaxNode = this.climaxLabel.node;
            const uiOpacity = climaxNode.getComponent(UIOpacity) ?? climaxNode.addComponent(UIOpacity);
            await new Promise<void>(resolve => {
                tween(uiOpacity)
                    .to(0.25, { opacity: 0 })
                    .call(() => {
                        climaxNode.active = false;
                        resolve();
                    })
                    .start();
            });
        }
    }

    private static readonly CHIPS_COLOR = new Color(68, 138, 255, 255);
    private static readonly MULT_COLOR = new Color(239, 83, 80, 255);

    private showValuePopup(cardId: string, value: number, prefix: string = '+', type: 'chips' | 'mult' = 'chips'): Promise<void> {
        const cardNode = this.cardNodes.get(cardId);
        if (!cardNode || !this.valuePopupLabel) return Promise.resolve();

        const popupNode = this.valuePopupLabel.node;
        const uiOpacity = popupNode.getComponent(UIOpacity) ?? popupNode.addComponent(UIOpacity);

        tween(popupNode).stop();
        tween(uiOpacity).stop();

        this.valuePopupLabel.string = `${prefix}${value} ${type}`;
        this.valuePopupLabel.color = type === 'chips'
            ? GameRendererEngine.CHIPS_COLOR
            : GameRendererEngine.MULT_COLOR;
        uiOpacity.opacity = 255;
        popupNode.active = true;

        const worldPos = cardNode.worldPosition.clone();
        popupNode.setWorldPosition(new Vec3(worldPos.x, worldPos.y + 180, worldPos.z));
        const startPos = popupNode.position.clone();

        return new Promise(resolve => {
            tween(popupNode)
                .to(0.4, { position: new Vec3(startPos.x, startPos.y + 50, startPos.z) })
                .start();
            tween(uiOpacity)
                .delay(0.2)
                .to(0.3, { opacity: 0 })
                .call(() => {
                    popupNode.active = false;
                    resolve();
                })
                .start();
        });
    }

    private chipScaleMultiplier(chips: number): number {
        if (chips <= 0) return 1.0;
        return Math.min(2.5, 1.0 + Math.log10(chips) * 2);
    }

    private animateChipScale(node: Node, fromChips: number, toChips: number): Promise<void> {
        const base = this._chipsLabelBaseScale;
        const fromMul = this.chipScaleMultiplier(fromChips);
        const toMul = this.chipScaleMultiplier(toChips);
        const targetScale = new Vec3(base.x * toMul, base.y * toMul, base.z);
        if (Math.abs(fromMul - toMul) < 0.001) {
            node.setScale(targetScale);
            return Promise.resolve();
        }
        const delta = Math.abs(toChips - fromChips);
        const duration = Math.min(0.8, 0.15 + delta * 0.001);
        return new Promise<void>(resolve => {
            const counter = { value: fromMul };
            tween(counter)
                .to(duration, { value: toMul }, {
                    onUpdate: (target: { value: number }) => {
                        node.setScale(base.x * target.value, base.y * target.value, base.z);
                    },
                })
                .call(() => {
                    node.setScale(targetScale);
                    resolve();
                })
                .start();
        });
    }

    private animateRunningScore(fromChips: number, toChips: number, fromMult: number, toMult: number): Promise<void> {
        const promises: Promise<void>[] = [
            this.animateLabelValue(fromChips, toChips, this.runningChipsLabel),
            this.animateLabelValue(fromMult, toMult, this.runningMultLabel),
        ];
        if (this.runningChipsLabel) {
            promises.push(this.animateChipScale(this.runningChipsLabel.node, fromChips, toChips));
        }
        return Promise.all(promises).then(() => {});
    }

    private animateTotalScore(fromScore: number, toScore: number): Promise<void> {
        return this.animateLabelValue(fromScore, toScore, this.scoreLabel, n => `${n}`);
    }

    private resetRunningScore(fromChips: number, fromMult: number): Promise<void> {
        const promises: Promise<void>[] = [
            this.animateLabelValue(fromChips, 0, this.runningChipsLabel),
            this.animateLabelValue(fromMult, 0, this.runningMultLabel),
        ];
        if (this.runningChipsLabel) {
            promises.push(this.animateChipScale(this.runningChipsLabel.node, fromChips, 0));
        }
        return Promise.all(promises).then(() => {});
    }

    private async renderHand(cards: Card[]): Promise<void> {
        if (!this.handView) return;
        await this.handView.dealCards(cards);
        this.handView.getCardViews().forEach(cv => {
            if (cv.cardModel) {
                this.cardNodes.set(cv.cardModel.id, cv.node);
            }
        });
        if (this.cardDeckLabel) {
            this.cardDeckLabel.string = `${this.engine.getDeck().length}/52`;
        }
    }

    private animateLabelValue(
        fromValue: number,
        targetValue: number,
        label: Label | null,
        format: (n: number) => string = (n) => `${n}`,
    ): Promise<void> {
        if (!label) return Promise.resolve();

        if (fromValue === targetValue) {
            label.string = format(targetValue);
            return Promise.resolve();
        }

        const delta = Math.abs(targetValue - fromValue);
        const duration = Math.min(0.8, 0.15 + delta * 0.001);

        return new Promise(resolve => {
            const counter = { value: fromValue };
            tween(counter)
                .to(duration, { value: targetValue }, {
                    onUpdate: (target: { value: number }) => {
                        label.string = format(Math.round(target.value));
                    },
                })
                .call(() => {
                    label.string = format(targetValue);
                    resolve();
                })
                .start();
        });
    }

    // ── UI helpers ──────────────────────────────────────────────────

    private updateUIForPhase(currentPhase: GamePhase) {
        const activeNodes = this.phaseUIMap[currentPhase];
        if (!activeNodes) return;

        const allRegisteredNodes = new Set<Node>();
        Object.values(this.phaseUIMap).forEach(nodes => {
            nodes.forEach(n => allRegisteredNodes.add(n));
        });

        allRegisteredNodes.forEach(node => {
            const shouldBeVisible = activeNodes.includes(node);
            if (node.active !== shouldBeVisible) {
                node.active = shouldBeVisible;
            }
        });
        this.handsRulePanel?.hide();
    }

    public registerCardNode(id: string, node: Node) {
        this.cardNodes.set(id, node);
    }

    public registerJokerNode(id: string, node: Node) {
        this.jokerNodes.set(id, node);
    }

    private animateScoreProgress(fromScore: number, toScore: number, blind: number): void {
        if (!this.scoreProgressBar || blind <= 0) return;
        const bar = this.scoreProgressBar;
        const fromProgress = Math.min(fromScore / blind, 1);
        const toProgress = Math.min(toScore / blind, 1);
        if (fromProgress === toProgress) {
            bar.progress = toProgress;
            return;
        }
        const delta = Math.abs(toProgress - fromProgress);
        const duration = Math.min(0.8, 0.15 + delta * 2);
        const counter = { value: fromProgress };
        tween(counter)
            .to(duration, { value: toProgress }, {
                easing: 'quadOut',
                onUpdate: (target: { value: number }) => {
                    bar.progress = target.value;
                },
            })
            .call(() => { bar.progress = toProgress; })
            .start();
    }

    private delay(ms: number): Promise<void> {
        return new Promise(resolve => setTimeout(resolve, ms));
    }
}
