import { _decorator, Component, Node } from 'cc';
import { Item, ItemConfigJson } from './ItemData';
import { resources, JsonAsset } from 'cc';
const { ccclass, property } = _decorator;

class ItemConfigHelper {
    public static getItemConfig() {
        return new Promise<JsonAsset>((resolve, reject) => {
            resources.load<JsonAsset>('dynamic/item/config/ItemConfig', (err, asset: JsonAsset) => {
                if (err || !asset) {
                    reject(err);
                    return;
                }
                resolve(asset);
            });
        });
    }
}

export interface ItemWithAmount {
    item: Item,
    amount: number
}

export const EnumCurrency = {
    /** 星幣 */
    Coin: 10000003,
    /** 星鑽 */
    Diamond: 10000001,
    /** 能量 */
    Energy: 10000002,
    /** 角色升級用經驗值 */
    Dust: 10000006,
    /** 玩家經驗值 */
    EXP: 10000005,
    /** 能量上限 */
    EXP_LIMIT: 10100004,
}


export class ItemFactory {
    private static _instance: ItemFactory = null;
    static get Instance(): ItemFactory {
        if (!this._instance) {
            ItemFactory._instance = new ItemFactory();
        }
        return ItemFactory._instance;
    }
    private loadData: Promise<JsonAsset> = null;
    private itembaseConfig: Record<string, ItemConfigJson> = null;

    private itemMap = new Map();
    private typeOfItemMap = new Map<number, Item[]>();

    /**
     * 讀取Item的Config
     */
    public async LoadConfig() {
        if (this.itembaseConfig) {
            return;
        }
        if (this.loadData) {
            return;
        }
        this.loadData = ItemConfigHelper.getItemConfig();
        const json = await this.loadData;
        this.typeOfItemMap.forEach((items, type) => {
            items.length = 0; // empty the old array
        });
        this.itembaseConfig = json.json;
        for (const key in this.itembaseConfig) {
            if (Object.prototype.hasOwnProperty.call(this.itembaseConfig, key)) {
                const element = this.itembaseConfig[key] as ItemConfigJson;
                const itemdata = new Item(element);
                this.itemMap.set(element.itemId, itemdata);
                // 初始化 typeOfItemMap，小心效能(記憶體配置)問題
                const type = element.itemType;
                if (!this.typeOfItemMap.has(type)) {
                    this.typeOfItemMap.set(type, []);
                }
                this.typeOfItemMap.get(type).push(itemdata);
            }
        }
    }

    private createPlaceHolderItem(itemId: number) {
        const placeHolderItemData = {
            itemId: itemId,
            itemName: '道具' + itemId,
            itemInfo: '這是一個 placeholder 道具，僅供測試用',
            itemType: -1,
            itemQuality: 0,
            stringValue: itemId.toString(),
        }
        const placeHolderItem = new Item(placeHolderItemData);
        this.itemMap.set(itemId, placeHolderItem);
        return placeHolderItem;
    }

    public GetItemById(itemId: number): Item {
        if (!this.itembaseConfig && this.loadData == null) {
            this.LoadConfig();
        }

        if (this.itemMap.has(itemId)) {
            return this.itemMap.get(itemId);
        }

        return this.createPlaceHolderItem(itemId);
    }

    public GetItemsByType(type: number): Item[] | null {
        if (!this.typeOfItemMap.has(type)) {
            return null;
        }
        return this.typeOfItemMap.get(type);
    }

}


