export const SUITS = ['Hearts', 'Diamonds', 'Clubs', 'Spades'] as const;
export type Suit = (typeof SUITS)[number];

export const SUIT_SYMBOL: Record<Suit, string> = {
    Hearts: '♥️',
    Diamonds: '♦️',
    Clubs: '♣️',
    Spades: '♠️',
};

export interface Card {
    id: string;
    suit: Suit;
    rank: string; // e.g., '2', '10', 'J', 'Q', 'K', 'A'
    chips: number;
    mult: number;
}
