import { Card, Suit } from '../types/Card';

export type SpotlightTarget =
    | 'hand' | 'selectedCard' | 'playButton' | 'scoreArea'
    | 'handType' | 'chipsLabel' | 'targetScore' | 'handsLeft' | 'none';

export type AdvanceTrigger =
    | 'cardSelected'
    | 'twoSameRankSelected'
    | 'handPlayed'
    | 'animDone'
    | 'tap'
    | 'tutorialDone';

export interface TutorialStep {
    bubble: string;
    spotlight: SpotlightTarget;
    advanceOn: AdvanceTrigger;
    presetHand?: Card[];
}

function card(id: string, rank: string, suit: Suit): Card {
    return { id, rank, suit, chips: 0, mult: 0 };
}

