import { AssetManager, assetManager } from 'cc';
import { Sprite, SpriteFrame } from 'cc';
import { _decorator, Component, Node } from 'cc';
const { ccclass, property } = _decorator;

export type ItemConfigJson = {
    itemId: number;
    itemName: string;
    itemInfo: string;
    itemType: number;
    itemQuality: number;
    stringValue: string;
}

export interface IItem {
    itemNo: number,
    amount: string,
}

const DYNAMIC_ITEM_PATH: string = 'dynamic/item/';

export class Item {

    private static _itemBundle: AssetManager.Bundle | null = null;
    private static _itemBundlePromise: Promise<AssetManager.Bundle> | null = null;
    private static async getBundle() {
        if (this._itemBundlePromise) {
            await this._itemBundlePromise;
        }
        if (!this._itemBundle) {
            this._itemBundle = assetManager.getBundle('resources');
            if (!this._itemBundle) {
                this._itemBundlePromise = new Promise((resolve, reject) => {
                    assetManager.loadBundle('resources', (err, bundle) => {
                        if (err) {
                            reject(err);
                        }
                        resolve(bundle);
                    });
                });
                this._itemBundle = await this._itemBundlePromise;
                this._itemBundlePromise = null;
            }
        }
        return this._itemBundle;
    }

    private itemId: number;
    private itemName: string;
    private itemInfo: string;
    private itemType: number;
    private itemQuality: number;
    private stringValue: string;
    
    /** 道具ID */
    public get ItemId(): number { return this.itemId; }
    /** 道具名稱 */
    public get ItemName(): string { return this.itemName; }
    /** 道具描述 */
    public get ItemInfo(): string { return this.itemInfo; }
    /** 道具種類 */
    public get ItemType(): number { return this.itemType; }
    /** 道具品質 (稀有度) */
    public get ItemQuality(): number { return this.itemQuality; }
    

    constructor(json: ItemConfigJson) {
        this.LoadDefault(json);
    }

    private LoadDefault(json: ItemConfigJson) {
        this.itemId = json.itemId;
        this.itemName = json.itemName;
        this.itemInfo = json.itemInfo;
        this.itemType = json.itemType;
        this.itemQuality = json.itemQuality;
        this.stringValue = json.stringValue;
    }

    /** 獲取 256x256 的大型道具圖 */
    public async GetImage(sprite: Sprite = null): Promise<SpriteFrame> {
        let target: SpriteFrame = null;
        try {
            target = await this.getImageFromItemBundle(this.imagePath + '/spriteFrame');
        } catch(e) {
            console.warn('GetImage error', e);
        }
        if (target == null) {
            target = await this.getPlaceholderImage();
        }
        if (sprite && target) {
            sprite.spriteFrame = target;
        }
        return target;
    }

    /** 獲取 74x74 的道具icon專用圖 */
    public async GetSmallImage(sprite: Sprite = null): Promise<SpriteFrame> {
        let target: SpriteFrame = null;
        try {
            target = await this.getImageFromItemBundle(this.smallImagePath + '/spriteFrame');
        } catch(e) {
            console.warn('GetSmallImage error', e);
        }
        if (target == null) {
            target = await this.getPlaceholderImage(true);
        }
        if (sprite && target) {
            sprite.spriteFrame = target;
        }
        return target;
    }

    private async getPlaceholderImage(small: boolean = false): Promise<SpriteFrame> {
        let target: SpriteFrame = null;
        try {
            target = await this.getImageFromItemBundle('placeholder' + (small ? '_s' : '') + '/spriteFrame');
        } catch(e) {
            console.warn('GetSmallImage error', e);
        }
        return target;
    }

    private get imagePath(): string {
        return this.stringValue;
    }

    private get smallImagePath(): string {
        return this.stringValue + '_s';
    }

    private getImageFromItemBundle(path: string): Promise<SpriteFrame> {
        return this.getImageFromResourceBundle(DYNAMIC_ITEM_PATH + path);
    }

    private async getImageFromResourceBundle(path: string): Promise<SpriteFrame> {
        const bundle = await Item.getBundle();
        if (!bundle) {
            return null;
        }
        return new Promise((resolve, reject) => {
            bundle.load<SpriteFrame>(path, (err, asset: SpriteFrame) => {
                if (err || !asset) {
                    reject(err);
                    console.log('getImageFromResourceBundle load', path, err, asset);
                    return;
                }
                resolve(asset);
            });
        });
    }

}
