import { _decorator, Component, EventTouch, Node } from 'cc';
import { CardView } from './CardView';
import { CardInputMachine } from '../../engine/CardInputMachine';
import { CardEvents } from '../../types';

const { ccclass, property, requireComponent } = _decorator;

@ccclass('CardInteraction')
@requireComponent(CardView)
export class CardInteraction extends Component {
    private _cardView: CardView | null = null;
    private _fsm: CardInputMachine = new CardInputMachine();

    onLoad() {
        this._cardView = this.getComponent(CardView);
        this.bindFSMSubscriptions();
    }

    onEnable() {
        this.node.on(Node.EventType.TOUCH_START, this.onTouchStart, this);
        this.node.on(Node.EventType.TOUCH_MOVE, this.onTouchMove, this);
        this.node.on(Node.EventType.TOUCH_END, this.onTouchEnd, this);
        this.node.on(Node.EventType.TOUCH_CANCEL, this.onTouchCancel, this);
    }

    onDisable() {
        this.node.off(Node.EventType.TOUCH_START, this.onTouchStart, this);
        this.node.off(Node.EventType.TOUCH_MOVE, this.onTouchMove, this);
        this.node.off(Node.EventType.TOUCH_END, this.onTouchEnd, this);
        this.node.off(Node.EventType.TOUCH_CANCEL, this.onTouchCancel, this);
        this._fsm.pointerCancel();
    }

    private bindFSMSubscriptions() {
        // CardInteraction acts purely as a dumb pipe, emitting intents to HandView.
        // It does NOT modify CardView state directly.

        this._fsm.onSelectToggle = () => {
            this.node.emit(CardEvents.TAP, this._cardView);
        };

        this._fsm.onLongPressStart = () => {
            this.node.emit(CardEvents.LONG_PRESS_START, this._cardView);
        };

        this._fsm.onLongPressEnd = () => {
            this.node.emit(CardEvents.LONG_PRESS_END, this._cardView);
        };

        this._fsm.onDragStart = () => {
            this.node.emit(CardEvents.DRAG_START, this._cardView);
        };

        this._fsm.onDragMove = (dx: number, dy: number) => {
            this.node.emit(CardEvents.DRAG_MOVE, this._cardView, dx, dy);
        };

        this._fsm.onDragEnd = () => {
            this.node.emit(CardEvents.DRAG_END, this._cardView);
        };
    }

    // --- Dumb Input Pipes ---

    private onTouchStart(event: EventTouch) {
        event.preventSwallow = true;
        const loc = event.getUILocation();
        this._fsm.pointerDown(loc.x, loc.y, Date.now());
    }

    private onTouchMove(event: EventTouch) {
        const loc = event.getUILocation();
        const delta = event.getUIDelta();
        this._fsm.pointerMove(loc.x, loc.y, delta.x, delta.y);
    }

    private onTouchEnd(event: EventTouch) {
        this._fsm.pointerUp();
    }

    private onTouchCancel(event: EventTouch) {
        this._fsm.pointerCancel();
    }

    update(dt: number) {
        this._fsm.tick(Date.now());
    }
}
