import { _decorator, Component, Node, Prefab, Label, CCString } from 'cc';
import { VirtualListScrollView } from '@gamecommon/virtual_scrollview/VirtualListScrollView';
import { BaseGameEvent } from '@gamecommon/base/BaseGameEvent';
import { SingleGameCollectActivityManager } from '../SingleGameCollectActivityManager';
import { SingleGameCollectItemElement } from './SingleGameCollectItemElement';
import { SingleGameCollectionProgress } from './SingleGameCollectionProgress';
import * as PlatformModule from '@gamecommon/base/PlatformModule';
const { ccclass, property } = _decorator;

const _SECONDS_PER_DAY_ = 86400;

@ccclass('SingleGameCollectItemPopup')
export class SingleGameCollectItemPopup extends Component {
    @property(VirtualListScrollView)
    public scrollView: VirtualListScrollView = null;
    @property(Prefab)
    public elementPrefab: Prefab = null;

    @property(Label)
    public countdownStr: Label = null;

    @property(SingleGameCollectionProgress)
    public collectionProgress: SingleGameCollectionProgress = null;

    protected onEnable(): void {
        this.initList();
        this.updateCountdown();
        this.unschedule(this.updateCountdown);
        this.schedule(this.updateCountdown, 1);
        this.collectionProgress?.updateOldProgress();
    }

    private initList() {
        this.scrollView.setTemplate(this.elementPrefab);
        this.scrollView.setCallback(this.itemCallback);
        this.scrollView.resize(SingleGameCollectActivityManager.Instance.TotalStages);

        //const currentIndex = SingleGameCollectActivityManager.Instance.service?.data?.getCollectionCurrentReward() ?? 0;
        const currentIndex = SingleGameCollectActivityManager.Instance.CurrentStage - 1;
        this.scrollView.setLocation(currentIndex + 2, 0.3);
    }

    protected onDisable(): void {
    }

    private itemCallback = (item: SingleGameCollectItemElement, index: number) => {
        item.setData(index);
    }

    onClose() {
        this.node.active = false;
    }

    private updateCountdown = () => {
        const currentTime = Math.floor(Date.now() / 1000);
        
        const leftTime = SingleGameCollectActivityManager.Instance.ActivityEndTime - currentTime;
        this.countdownStr.string = this.convertLeftTimeToString2(leftTime);
    }

    private convertLeftTimeToString2(leftTime: number): string {
        if (leftTime <= 0) {
            return "已結束";
        }
        const day = Math.floor(leftTime / _SECONDS_PER_DAY_);
        const hours = Math.floor(leftTime / 3600);
        const minutes = Math.floor(leftTime / 60);
        const seconds = leftTime;
        if (day > 0) {
            const hours = Math.floor((leftTime - day * _SECONDS_PER_DAY_) / 3600);
            return `${day}天${hours}小時`;
        } else if (hours > 0) {
            const minutes = Math.floor((leftTime - hours * 3600) / 60);
            return `${hours}小時${minutes}分`;
        } else if (minutes > 0) {
            const seconds = Math.floor((leftTime - minutes * 60));
            return `${minutes}分${seconds}秒`;
        } else {
            return `${seconds}秒`;
        }
    }

}