import { InputState } from "../types/InputState";

export class CardInputMachine {
    public state: InputState = InputState.IDLE;
    
    // Config
    private readonly DRAG_THRESHOLD = 10;
    private readonly LONG_PRESS_TIME = 500; // ms

    private startX = 0;
    private startY = 0;
    private pressTime = 0;

    // View Subscriptions (Callbacks)
    public onSelectToggle?: () => void;
    public onDragStart?: () => void;
    public onDragMove?: (dx: number, dy: number) => void;
    public onDragEnd?: () => void;
    public onLongPressStart?: () => void;
    public onLongPressEnd?: () => void;

    public pointerDown(x: number, y: number, timeMs: number) {
        this.state = InputState.PRESSED;
        this.startX = x;
        this.startY = y;
        this.pressTime = timeMs;
    }

    public pointerMove(x: number, y: number, dx: number, dy: number) {
        if (this.state === InputState.IDLE) return;

        // Check if we broke the drag threshold
        if (this.state === InputState.PRESSED || this.state === InputState.LONG_PRESS) {
            const dist = Math.sqrt(Math.pow(x - this.startX, 2) + Math.pow(y - this.startY, 2));
            if (dist > this.DRAG_THRESHOLD) {
                if (this.state === InputState.LONG_PRESS) {
                    this.onLongPressEnd?.(); // Cancel long press if we start dragging
                }
                this.state = InputState.DRAGGING;
                this.onDragStart?.();
            }
        }

        if (this.state === InputState.DRAGGING) {
            this.onDragMove?.(dx, dy);
        }
    }

    public pointerUp() {
        if (this.state === InputState.DRAGGING) {
            this.onDragEnd?.();
        } else if (this.state === InputState.LONG_PRESS) {
            this.onLongPressEnd?.();
        } else if (this.state === InputState.PRESSED) {
            // It was a clean tap (didn't drag, didn't hold long enough)
            this.onSelectToggle?.();
        }
        
        this.state = InputState.IDLE;
    }

    public pointerCancel() {
        this.pointerUp();
    }

    // Called every frame by the engine to check time-based states
    public tick(currentTimeMs: number) {
        if (this.state === InputState.PRESSED) {
            if (currentTimeMs - this.pressTime >= this.LONG_PRESS_TIME) {
                this.state = InputState.LONG_PRESS;
                this.onLongPressStart?.();
            }
        }
    }
}
