import { _decorator, Component, Label, Node } from 'cc';
const { ccclass, property } = _decorator;

@ccclass('FakeGameResultSinglePlayerNewUI')
export class GameResultSinglePlayerNewUI extends Component {

    @property({type:Label})
    private actionText = null;

    @property({type:Node})
    private actionNode = null;

    private actionCallback : Function = null;

    protected onLoad(): void {
        this.node.active = false;
    }

    public prepareWLParam(wlgameparam: any) {
    }

    public setActionWithCost( actionName: string, cost: any, actionCallback: Function) {
        this.actionText.string = actionName;
        this.actionCallback = actionCallback;
    }

    public async show(resultParam: any, donCallBack?: Function, btnBackCallback?: Function, initEndCallback?: Function) {
        
        this.actionNode.active = false;
        if(initEndCallback){
            initEndCallback();
        }

        //等候三秒
        await new Promise<void>(resolve => {
            setTimeout(() => {
                resolve();
            }, 3000);
        });

        this.actionNode.active = true;
        if(donCallBack){
            donCallBack();
        }
    }

    public onClickAction() {
        if(this.actionCallback){
            this.actionCallback();
        }
    }

}

