import { Enum } from 'cc';
import { _decorator, Component, Node, SpriteFrame, Color } from 'cc';
const { ccclass, property } = _decorator;


export enum TopbarType {
    Default = 0, // 基本顯示 體力 鑽石 學員幣
    NotChange = 1, // 不處理
    None = 2, // 不顯示
    Custom_currency = 3, // 自訂義要顯示的 幣值
    Addition = 4, // 基本顯示+自訂
    NoCurrency = 5, // 只有標題與漢堡選單
    HamburgerOnly = 6, // 只有漢堡選單
    TitleOnly = 7, // 只有標題
}

// 漢堡選單的位置選項與定義
export enum TopbarHamburgerPos {
    Default = 0, // 預設的右邊那個位置
    Left = 1,    // 靠左邊一點避開右側選單的位置
    None = 2,    // 不要漢堡選單
}Enum(TopbarHamburgerPos);


@ccclass('FakeTopBar')
export class TopBar extends Component {

    @property({type:Node})
    private topbarRoot = null;

    @property({type:Node})
    private topbarInfoRoot = null;    

    @property({type:Node})
    private topbarBackNode = null;

    @property({type:Node})
    private topbarTipNode = null;

    @property({type:Node})
    private topbarFroceEndNode = null;    

    private static instance = null;
    public get Instance(){
        return TopBar.instance;
    }

    private topbarDefine: ResourceDefine.TopbarDefine = null;


    protected onLoad(): void {
        if(TopBar.instance != null){
            this.node.destroy();
            return;
        }
        TopBar.instance = this;
    }

    protected onDestroy(): void {
        TopBar.instance = null;
    }

    public SetLobbyTopbar(define : ResourceDefine.TopbarDefine){
        this.topbarDefine = define;
    
        switch(define.TopbarType){
            case TopbarType.Default:
            case TopbarType.Addition:
            case TopbarType.Custom_currency:
            case TopbarType.NoCurrency:
            case TopbarType.TitleOnly:
            case TopbarType.NotChange:    
                this.topbarRoot.active = true;                         
                this.topbarInfoRoot.active = true;
                break;
            case TopbarType.HamburgerOnly:
                this.topbarRoot.active = true;
                this.topbarInfoRoot.active = false;
                break;
            case TopbarType.None:
                this.topbarRoot.active = false;
                break;
        }

        this.topbarTipNode.active = define.TipEvent != null;
        this.topbarFroceEndNode.active = false;
    }
    
    public CloseNowTopBar(){
        this.topbarRoot.active = false;
    }

    public HideTopbarBackBtn(){
        this.topbarBackNode.active = false;
    }

    public ShowTopbarBackBtn(){
        this.topbarBackNode.active = true;
    }

    public onClickBackBtn(){
        if(this.topbarDefine.ExitEvent != null){
            this.topbarDefine.ExitEvent();
        }
    
    }

    public onClickTipBtn(){
        if(this.topbarDefine.TipEvent != null){
            this.topbarDefine.TipEvent();
        }
    }

    public onClickHamburgerBtn(){
        this.topbarFroceEndNode.active = !this.topbarFroceEndNode.active;
    }

    public onClickForceExitBtn(){
        if(this.topbarDefine.CustomHamburgerMenuStyle?.MenuOptions?.length > 0){
            if(this.topbarDefine.CustomHamburgerMenuStyle.MenuOptions[0].Callback != null){
                this.topbarDefine.CustomHamburgerMenuStyle.MenuOptions[0].Callback();
            }
        }

        this.topbarFroceEndNode.active = false;
    }    

}


export namespace ResourceDefine {
    export class TopbarDefine {

        // 天bar顯示類型
        private topbarType: TopbarType;
        // 點擊離開按鈕時的事件(沒給基本上就是關閉目前UI)
        private exitCallback: Function;
        // tip按鈕按下去後的回呼事件(有給事件驚嘆號按鈕就會打開)
        private tipClickCallback?: Function = null;
        // 是否顯示buff
        private isShowBuff: boolean = false;
        // 漢堡選單的位置
        private hamburgerPos: any = null;        
        // 客製化漢堡選單的背景圖與選項
        private customHamburgerMenu: CustomHamburgerMenu = null;
        // 是否顯示返回按鈕
        private isShowBack: boolean = true;

        public set ExitEvent(callback: Function) {
            this.exitCallback = callback;
        }

        public get ExitEvent() {
            return this.exitCallback;
        }

        public set TipEvent(callback: Function) {
            this.tipClickCallback = callback;
        }

        public get TipEvent() {
            return this.tipClickCallback;
        }

        public set IsShowBuff(isShow: boolean) {
            this.isShowBuff = isShow;
        }

        public set HamburgerPos(pos: any) {
            this.hamburgerPos = pos;
        }

        public set CustomHamburgerMenuStyle(customHamburgerMenu: CustomHamburgerMenu) {
            this.customHamburgerMenu = customHamburgerMenu;
        }

        public get CustomHamburgerMenuStyle() {
            return this.customHamburgerMenu;
        }

        public get TopbarType() {
            return this.topbarType;
        }



        constructor(title?: string, topbarSetting?: TopbarType, topbarCurrencys?: any, isClean: boolean = true) {
            this.topbarType = topbarSetting;
        }
    }

    export class HamburgerOption {

        // 選項點選後的callback
        private callback: Function = null;

        public get Callback() {
            return this.callback;
        }

        constructor(title: string, bg?: any, icon?: any, callback?: Function) {
            this.callback = callback;
        }
    }

    export class HamburgerOptionSpriteSetup {
        constructor(bundle: string, path: string, color: Color = Color.WHITE) {
        }
    }

    export class CustomHamburgerMenu {
        // 漢堡選單內的額外選項
        private menuOptions: HamburgerOption[] = null;

        public get MenuOptions() {
            return this.menuOptions;
        }
        constructor(options?: HamburgerOption[], preset?: any, bg?: SpriteFrame) {
            this.menuOptions = options;
        }
    }

    export enum DefaultHamburgerMenuOption {
        SystemSetting,
        News,
        Mail,
        Sticker,
        Backpack,
    }
    export const DefaultHamburgerMenuPreset = {
        None: [],
        Default: [DefaultHamburgerMenuOption.SystemSetting, DefaultHamburgerMenuOption.News, DefaultHamburgerMenuOption.Mail, DefaultHamburgerMenuOption.Sticker, DefaultHamburgerMenuOption.Backpack],
        InGameDefaultSetting: [DefaultHamburgerMenuOption.SystemSetting, DefaultHamburgerMenuOption.Sticker],
        SystemSettingOnly: [DefaultHamburgerMenuOption.SystemSetting],
        NewsOnly: [DefaultHamburgerMenuOption.News],
        MailOnly: [DefaultHamburgerMenuOption.Mail],
        SystemSetting_News: [DefaultHamburgerMenuOption.SystemSetting, DefaultHamburgerMenuOption.News],
        SystemSetting_Mail: [DefaultHamburgerMenuOption.SystemSetting, DefaultHamburgerMenuOption.Mail],
    }

}



