import { SingleGameCollectActivityState } from '@gamecommon/single_game_collect_activity/SingleGameCollectActivityDataDefine';
import { BaseGameData } from '@gamecommon/base/BaseGameData';
import { SingleGameCollectActivityManager } from '@gamecommon/single_game_collect_activity/SingleGameCollectActivityManager';
import { SingleGameCollectionProgress } from '@gamecommon/single_game_collect_activity/ui/SingleGameCollectionProgress';
import { SingleGameCollectItemPopup } from '@gamecommon/single_game_collect_activity/ui/SingleGameCollectItemPopup';
import { isValid, Tween, TweenEasing, CCBoolean, CCInteger, CCString, instantiate, tween, UITransform, v3, Vec3 } from 'cc';
import { _decorator, Component, Node } from 'cc';
import { BaseGameEvent } from '@gamecommon/base/BaseGameEvent';
import { BaseGameEventDefine } from '@gamecommon/base/BaseGameDefine';
const { ccclass, property } = _decorator;

/**
 * single_game_collection_activity_lobbyovrlay.prefab：GAME_LOBBY 畫面收集活動覆蓋頁 UI
 * @collectionProgress 收集進度條：返回 GAME_LOBBY 會表演進度推進(飛行)動畫，並嘗試自動領獎，點擊時進行領獎或開啟 popup 頁面
 * @popup 收集活動資訊頁
 */
@ccclass('SingleGameCollectActivityLobbyOverlay')
export class SingleGameCollectActivityLobbyOverlay extends Component {
    private static _flystartCoord: Vec3 = new Vec3();
    private static _flycontrolCoord: Vec3 = new Vec3();
    private static _flyendCoord: Vec3 = new Vec3();

    @property(Node)
    private blockInputNode: Node = null;
    @property(CCBoolean)
    private disposeSingleGameCollectActivityManager: boolean = true;
    @property({ type: CCBoolean, displayName: 'onEnable 執行初始化 (defaultMode)' })
    private initDefaultModeOnEnable: boolean = false;
    @property({ type: CCInteger, displayName: '初始化用預設模式' })
    private defaultMode: number = 0;

    @property({
        type: CCString, displayName: '收集物 Sprite 格式化路徑',
        tooltip: '使用 {id} 替換目標物件ID-SpriteFrame，填入 asset Path 如 image/good{id}/spriteFrame'
    })
    private collectionSpritePathFormat: string = "image/good{id}/spriteFrame";

    @property(SingleGameCollectItemPopup)
    private popup!: SingleGameCollectItemPopup;
    @property(SingleGameCollectionProgress)
    private collectionProgress!: SingleGameCollectionProgress;
    @property(CCString)
    private flyEasing: string = "cubicIn"
    @property(Node)
    private flyNodePrototype: Node | null = null;
    @property(Node)
    private flyStartNode: Node | null = null;
    @property(Node)
    private flyBezierControlNode: Node | null = null;
    @property(Node)
    private flyEndNode: Node | null = null;

    private mode: number = 0;
    private _busy = false;
    private stateInitialized: boolean = false;
    private flyPool: Node[] = [];
    private tmpV3: Vec3 = new Vec3();

    // Get a node from the pool or create a new one
    private getFlyNodeFromPool(): Node {
        if (this.flyPool.length > 0) {
            return this.flyPool.pop();
        }
        const node = instantiate(this.flyNodePrototype);
        node.setParent(this.node);
        return node;
    }

    // Return a node to the pool
    private returnFlyNodeToPool(node: Node): void {
        if (!isValid(node)) {
            return;
        }
        Tween.stopAllByTarget(node);
        node.active = false;
        this.flyPool.push(node);
    }

    public get busy() {
        return this._busy;
    }
    public set busy(value: boolean) {
        this._busy = value;
        if (!this.blockInputNode) return;
        this.blockInputNode.active = value;
    }

    protected onLoad() {
        // requestCollectActivityState 初始化事件
        BaseGameEvent.on(BaseGameEventDefine.CollectActivityState, this.onInitializeCollectActivityState, this);
        // requestAddCollections() 後更新收集進度事件
        BaseGameEvent.on(BaseGameEventDefine.CollectProgressRefresh, this.onCollectProgressRefresh, this);
        this.collectionProgress.iconSetting.collectionSpritePathFormat = this.collectionSpritePathFormat;
        this.popup.collectionProgress.iconSetting.collectionSpritePathFormat = this.collectionSpritePathFormat;
        if (this.blockInputNode) {
            this.blockInputNode.active = false;
        }
        if (!this.collectionProgress) {
            return;
        }
        this.collectionProgress.node.active = false;
    }

    protected onDestroy() {
        BaseGameEvent.off(BaseGameEventDefine.CollectActivityState, this.onInitializeCollectActivityState, this);
        if (this.disposeSingleGameCollectActivityManager) {
            SingleGameCollectActivityManager.Dispose();
        }
    }

    protected onEnable() {
        if (this.initDefaultModeOnEnable) {
            this.initializeState(this.defaultMode);
        }
    }

    /**
     * 建議在 GAME_LOBBY 場景啟動 (onEnable) 執行一次
     * @param activityMode: 收集活動模式
     */
    async initializeState(activityMode: number) {
        this.mode = activityMode;
        if (BaseGameData.Instance.Service) {
            this.busy = true;
            await BaseGameData.Instance.Service.requestCollectActivityState(activityMode);
            this.busy = false;
        }
    }

    private async doFlyAnimation(delay: number) {
        return new Promise<void>(async resolve => {
            const node = this.getFlyNodeFromPool();
            node.active = true;
            node.setPosition(SingleGameCollectActivityLobbyOverlay._flystartCoord);
            Tween.stopAllByTarget(node);
            const tw = tween(node);
            tw.delay(delay).to(0.5, { position: SingleGameCollectActivityLobbyOverlay._flyendCoord }, {
                easing: this.flyEasing as TweenEasing,
                onUpdate(target, radio) {
                    const t = radio;
                    const x = (1 - t) * (1 - t) * SingleGameCollectActivityLobbyOverlay._flystartCoord.x +
                        2 * t * (1 - t) * SingleGameCollectActivityLobbyOverlay._flycontrolCoord.x +
                        t * t * SingleGameCollectActivityLobbyOverlay._flyendCoord.x;
                    const y = (1 - t) * (1 - t) * SingleGameCollectActivityLobbyOverlay._flystartCoord.y +
                        2 * t * (1 - t) * SingleGameCollectActivityLobbyOverlay._flycontrolCoord.y +
                        t * t * SingleGameCollectActivityLobbyOverlay._flyendCoord.y;
                    // 更新节点位置
                    target.setPosition(x, y);
                }
            }).call(() => {
                this.returnFlyNodeToPool(node);
                resolve();
            }).start();
        });
    }

    private async flyAnimationFinish() {
        await this.collectionProgress.updateProgress(true);
        SingleGameCollectActivityManager.Instance.syncCollectionProgress();
        this.busy = false;

        if (SingleGameCollectActivityManager.Instance.hasReadyStageReward()) {
            await this.verifyAutoClaimCollectActivityRewards();
        }

        return;
    }

    async playCollectionAnimation() {
        if (!SingleGameCollectActivityManager.Instance.isOpenAndValid()) {
            console.warn(`playCollectionAnimation: activity not open`);
            return;
        }

        const count = SingleGameCollectActivityManager.Instance.CollectedCount - SingleGameCollectActivityManager.Instance.OldCollectionCount;

        if (count == 0) {
            console.warn(`playCollectionAnimation: no collected count`);
            return;
        }
        if (this.flyNodePrototype && this.flyStartNode && this.flyBezierControlNode && this.flyEndNode) {
            const transform = this.node.getComponent(UITransform);
            this.flyStartNode.getWorldPosition(this.tmpV3);
            transform.convertToNodeSpaceAR(this.tmpV3, SingleGameCollectActivityLobbyOverlay._flystartCoord);
            this.flyBezierControlNode.getWorldPosition(this.tmpV3);
            transform.convertToNodeSpaceAR(this.tmpV3, SingleGameCollectActivityLobbyOverlay._flycontrolCoord);
            this.flyEndNode.getWorldPosition(this.tmpV3);
            transform.convertToNodeSpaceAR(this.tmpV3, SingleGameCollectActivityLobbyOverlay._flyendCoord);
            const tasks: Promise<void>[] = [];
            for (let i = 0; i < count; ++i) {
                const task = this.doFlyAnimation(i * 0.1);
                tasks.push(task);
            }
            this.busy = true;
            await Promise.all(tasks);
        }
        await this.flyAnimationFinish();
    }

    public async openCollectionPopup() {
        if (this.busy) {
            return;
        }
        const manager = SingleGameCollectActivityManager.Instance;
        if (!manager.isOpenAndValid()) {
            return;
        }
        if (manager.hasReadyStageReward()) {
            this.verifyAutoClaimCollectActivityRewards();
            return;
        }
        this.popup.node.active = true;
    }

    private async verifyAutoClaimCollectActivityRewards() {
        const service = BaseGameData.Instance.Service;
        this.busy = true;
        let success: boolean = await service?.requestClaimCollectedRewards((rewards) => {
            if (!this || !isValid(this.node)) {
                return;
            }
            if (!rewards) {
                this.busy = false;
                return;
            }
            // TODO: 目前外包 Client 端不必實現恭喜獲獎
            // SingleGameProtoHelper.showClaimedRewards(rewards, () => {
            //     this.busy = false;
            //     this.initializeState(this.mode);
            // });
            this.busy = false; // 領獎完成，設為非忙碌狀態
            this.initializeState(this.mode); // 重新初始化活動狀態
        }, this.mode);
    }

    public onInitializeCollectActivityState(sourceState: SingleGameCollectActivityState) {
        const manager = SingleGameCollectActivityManager.Instance;
        manager.initialize(sourceState);
        if (manager.isOpenNow()) {
            this.collectionProgress.node.active = true;
            if (!this.stateInitialized) {
                this.updateActivity();
                this.stateInitialized = true;
            } else {
                this.collectionProgress.updateOldProgress();
                this.playCollectionAnimation();
            }
        } else {
            this.collectionProgress.node.active = false;
        }
    }

    public onCollectProgressRefresh(count: number) {
        const manager = SingleGameCollectActivityManager.Instance;
        manager.refreshCollected(count);
        if (this.node.activeInHierarchy && manager.isOpenNow()) {
            this.collectionProgress.node.active = true;
            this.collectionProgress.updateOldProgress();
            this.playCollectionAnimation();
        }
    }

    updateActivity() {
        const manager = SingleGameCollectActivityManager.Instance;
        if (manager.isOpenAndValid()) {
            this.collectionProgress.node.active = true;
            manager.syncCollectionProgress();
            this.collectionProgress.updateOldProgress();
        } else {
            this.collectionProgress.node.active = false;
        }
    }

}