import { Sprite } from 'cc';
import { _decorator, Component, Node, ToggleContainer, Button, Color } from 'cc';

const { ccclass, property } = _decorator;

@ccclass
export default class UISelectableGroup extends Component {

    @property(ToggleContainer)
    container: ToggleContainer = null;

    @property([Button])
    buttons: Button[] = [];

    @property(Color)
    toggleOffColor: Color = new Color(200, 200, 200);

    @property(Color)
    toggleOnColor: Color = new Color(150, 150, 150);

    onLoad () {
        this.bindToggleEvents();
        this.bindButtonEvents();
        this.updateToggleVisuals();
    }

    bindToggleEvents () {
        if (!this.container) return;

        this.container.toggleItems.forEach(toggle => {
            toggle.node.on('toggle', this.updateToggleVisuals, this);
        });
    }

    updateToggleVisuals () {
        this.container.toggleItems.forEach(toggle => {
            this.setColor(toggle.node, toggle.isChecked ? this.toggleOnColor : this.toggleOffColor);
        });
    }

    // ======================
    // Button Handling
    // ======================
    private _selectedButton: Button | null = null;

    bindButtonEvents () {
        this.buttons.forEach(btn => {
            btn.node.on(Node.EventType.TOUCH_END, () => {
                this._selectedButton = btn;
                this.updateButtonVisuals();
            });
        });
        this.updateButtonVisuals();
    }

    updateButtonVisuals () {
        this.buttons.forEach(btn => {
            this.setColor(btn.node, btn === this._selectedButton ? this.toggleOnColor : this.toggleOffColor);
        });
    }

    setColor(node: Node, color: Color) {
        const sprite = node.getComponent(Sprite);
        if (!sprite) return;
        sprite.color = color;
    }
}