/**
 * 使用方法:
 * 
 *  configManager : BaseConfigManager  = new BaseConfigManager();
 *  // 步驟 1 加載文件
 *  // 要先註冊 加載文件方法
 *  configManager.addLoader({ onLoadConfig: this.onLoadConfig.bind(this) });
 *  await configManager.loadConfig(FileName);
 * 
 *  // 步驟 2 取用 T帶入相應的結構
 *  const data = configManager.getConfig<DATA_TYPE>(FileName);
 */


class CSVLoader<T> {
    csv: T[] = [];
    protected rowToObject(fields: string[], row: any[]): any {
        let ret = {};
        try {
            for (let i in fields) {
                if (fields[i].indexOf(".") > -1) {
                    let subfields = fields[i].split(".");
                    let subret = ret;
                    for (let j = 0; j < subfields.length - 1; j++) {
                        if (subret[subfields[j]] == null) {
                            subret[subfields[j]] = {}
                        }
                        subret = subret[subfields[j]];
                    }
                    if (row[i] != null) {
                        subret[subfields[subfields.length - 1]] = row[i];
                    }
                    continue;
                } else {
                    if (row[i] != null) {
                        ret[fields[i]] = row[i];
                    }
                }

            }
        }
        catch (e) {
            console.log('Confgi load error', e);
        }
        return ret;
    }
    public load(csv: any[][]) {
        let fields: string[] = [];
        let rowIdx = 0;
        try {
            for (let row of csv) {
                if (row.length == 0) {
                    continue;
                }
                if (typeof row[0] === 'string' && (row[0]?.startsWith("#") || row[0]?.startsWith("//"))) {
                    continue;
                }

                if (fields.length == 0) {
                    // fields = row;                
                    for (let i in row) {
                        fields.push(row[i]?.trim());
                    }
                    continue;
                }

                this.csv.push(this.rowToObject(fields, row));
                rowIdx += 1;
            }
        } catch (e) {
            console.error("ConfigFieldedCSV load error", e);
        }
    }
}
/**
 * 配置文件加载器
 * 傳入 文件名稱 返回 文件內容
 */
export interface IBaseConfigLoader {
    onLoadConfig(name: string): Promise<string>;
}

class BaseConfig<V> {
    private csv: CSVLoader<V> = new CSVLoader<V>();

    public get data(): V[] {
        return this.csv.csv;
    }
    public async loadConfig(loader: (name: string) => Promise<string>, nameTarget: string) {
        this.csv = this.parseConfig(await this.tryLoad(loader, nameTarget));
    }
    private async tryLoad(loader: (name: string) => Promise<string>, nameTarget: string, tryCount?: number): Promise<string> {
        if (tryCount == null) {
            tryCount = 1;
        }
        try {
            return await loader(nameTarget);
        } catch (e) {
            console.error(`ConfigMgr loadConfig error ${nameTarget} tryCount:${tryCount}`, nameTarget, e);
            await new Promise((resove) => {
                setTimeout(resove, 300);
            })
            if (tryCount > 20) {
                return null;
            }

            return this.tryLoad(loader, nameTarget, tryCount + 1);
        }
    }
    private parseConfig(txt: string): CSVLoader<V> {
        if (txt == null || txt == '') {
            return null;
        }

        let csv = txt.split("\n").filter((x) => {
            return x.trim() != '';
        }).map((line) => {
            return line.split(",").map((x) => {
                if (x == '') {
                    return null;
                }
                x = x.trim();
                let nx = parseFloat(x);
                if (Number.isNaN(nx)) {
                    return x;
                }
                return nx;
            });
        });

        let ret = new CSVLoader<V>();
        ret.load(csv);
        return ret;
    }
}

export class BaseConfigManager{
    private loader: IBaseConfigLoader;
    private configMap: Map<string, BaseConfig<any>> = new Map<string, BaseConfig<any>>();
    /**
     * 添加配置文件加载器
     * @param loader 
     */
    public addLoader(loader: IBaseConfigLoader): void {
        this.loader = loader;
    }
    public async loadConfig<T>(name: string): Promise<BaseConfig<T>> {
        if (this.configMap.has(name)) {
            return this.configMap.get(name) as BaseConfig<T>;
        }
        const config = new BaseConfig<T>();
        await config.loadConfig(this.loader.onLoadConfig, name);
        this.configMap.set(name, config);
        return config;
    }
    public getConfig<T>(name: string): BaseConfig<T> {
        if (!this.configMap.has(name)) {
            console.error(`ConfigMgr getConfig error ${name}`);
            return null;
        }
        return this.configMap.get(name) as BaseConfig<T>;
    }
}

