import { _decorator, Component, Node, Label, Button, RichText } from 'cc';
import { rulesData } from '../../engine/RulesData';

const { ccclass, property } = _decorator;

const HAND_ORDER = [
    'Straight Flush',
    'Four of a Kind',
    'Full House',
    'Flush',
    'Straight',
    'Three of a Kind',
    'Two Pair',
    'Pair',
    'High Card',
] as const;

const HAND_NAME_ZH: Record<typeof HAND_ORDER[number], string> = {
    'Straight Flush': '同花順',
    'Four of a Kind': '四條',
    'Full House': '葫蘆',
    'Flush': '同花',
    'Straight': '順子',
    'Three of a Kind': '三條',
    'Two Pair': '兩對',
    'Pair': '一對',
    'High Card': '高牌',
};

@ccclass('HandsRulePanel')
export class HandsRulePanel extends Component {

    @property(Button)
    private closeButton: Button | null = null;

    @property(RichText)
    private handsListLabel: RichText | null = null;

    protected start(): void {
        this.closeButton?.node.on(Button.EventType.CLICK, this.hide, this);
        this._populateList();
    }

    show() {
        this.node.active = true;
    }

    hide() {
        this.node.active = false;
    }

    private _populateList() {
        if (!this.handsListLabel) return;

        const lines = HAND_ORDER.map(name => {
            const { chips, mult } = rulesData.hands[name];
            return `<b>${HAND_NAME_ZH[name]}</b>   <color=#5bc8fa>+${chips} 籌碼</color>   <color=#fe5f55>x${mult} 倍率</color>`;
        });

        this.handsListLabel.string = `<color=#ffffff>一回合至少出1張牌，最多出5張牌</color>\n${lines.join('\n')}`;
    }

    protected onDestroy(): void {
        this.closeButton?.node.targetOff(this);
    }
}
