import { Card } from '../types';
import { rulesData } from './RulesData';
import { CardEvaluationResult } from '../types/CardEvaluationResult';
import { Level } from '../types/Level';


export function getCardPoint(card: Card): number {
    const rankInfo = rulesData.ranks[card.rank as keyof typeof rulesData.ranks];
    return rankInfo ? rankInfo.points : 0;
}

export function getCardValue(card: Card): number {
    const rankInfo = rulesData.ranks[card.rank as keyof typeof rulesData.ranks];
    return rankInfo ? rankInfo.value : 0;
}

export function evaluateHand(cards: Card[]): CardEvaluationResult {
    const defaultResult = (name: keyof typeof rulesData.hands, scoringCards: Card[]): CardEvaluationResult => {
        const rule = rulesData.hands[name];
        return { name: name as string, chips: rule.chips, mult: rule.mult, scoringCards };
    };

    if (cards.length === 0) {
        return defaultResult('High Card', []);
    }

    // Sort descending by rank value
    const sorted = [...cards].sort((a, b) => getCardValue(b) - getCardValue(a));

    // Group by rank
    const rankCounts = new Map<string, Card[]>();
    for (const card of sorted) {
        if (!rankCounts.has(card.rank)) rankCounts.set(card.rank, []);
        rankCounts.get(card.rank)!.push(card);
    }

    // Group by suit
    const suitCounts = new Map<string, Card[]>();
    for (const card of sorted) {
        if (!suitCounts.has(card.suit)) suitCounts.set(card.suit, []);
        suitCounts.get(card.suit)!.push(card);
    }

    const suitGroups = Array.from(suitCounts.values());
    const isFlush = suitGroups.some(arr => arr.length >= 5);
    const flushCards = isFlush ? suitGroups.find(arr => arr.length >= 5)! : [];

    let isStraight = false;
    let straightCards: Card[] = [];

    // Unique ranks for straight
    const uniqueRanks: { rank: string; val: number; card: Card }[] = [];
    rankCounts.forEach((cardsOfRank, rank) => {
        uniqueRanks.push({ rank, val: getCardValue(cardsOfRank[0]), card: cardsOfRank[0] });
    });
    uniqueRanks.sort((a, b) => b.val - a.val);

    for (let i = 0; i <= uniqueRanks.length - 5; i++) {
        if (uniqueRanks[i].val - uniqueRanks[i + 4].val === 4) {
            isStraight = true;
            straightCards = uniqueRanks.slice(i, i + 5).map(u => u.card);
            break;
        }
    }

    if (!isStraight && uniqueRanks.length >= 5 && uniqueRanks[0].val === 14) {
        const has2345 = [2, 3, 4, 5].every(v => uniqueRanks.some(u => u.val === v));
        if (has2345) {
            isStraight = true;
            const aCard = uniqueRanks.find(u => u.val === 14)!.card;
            const twoToFive = [5, 4, 3, 2].map(v => uniqueRanks.find(u => u.val === v)!.card);
            straightCards = [aCard, ...twoToFive];
        }
    }

    // Since a played hand is max 5 cards, if it's flush + straight, it's Straight Flush.
    if (isStraight && isFlush) {
        return defaultResult('Straight Flush', sorted.slice(0, 5));
    }

    const pairs = [];
    let threeOfAKind = [];
    let fourOfAKind = [];

    // Important to keep rankCounts sorted by rank value implicitly or explicitly. Map preserves insertion order.
    // The entries are based on `sorted`, which is descending, so highest pairs appear first!
    rankCounts.forEach(group => {
        if (group.length === 4) fourOfAKind = group;
        else if (group.length === 3) threeOfAKind = group;
        else if (group.length === 2) pairs.push(group);
    });

    if (fourOfAKind.length === 4) {
        return defaultResult('Four of a Kind', fourOfAKind);
    }

    if (threeOfAKind.length === 3 && pairs.length >= 1) {
        return defaultResult('Full House', [...threeOfAKind, ...pairs[0]]);
    }

    if (isFlush) {
        return defaultResult('Flush', flushCards.slice(0, 5));
    }

    if (isStraight) {
        return defaultResult('Straight', straightCards);
    }

    if (threeOfAKind.length === 3) {
        return defaultResult('Three of a Kind', threeOfAKind);
    }

    if (pairs.length >= 2) {
        return defaultResult('Two Pair', [...pairs[0], ...pairs[1]]);
    }

    if (pairs.length === 1) {
        return defaultResult('Pair', pairs[0]);
    }

    return defaultResult('High Card', [sorted[0]]);
}

export function evaluateLevel(level: number): Level | null {
    const rule = rulesData.levels[level] as Level | undefined;
    if (!rule) return null;
    return {
        ante: rule.ante,
        hands: rule.hands,
        discards: rule.discards,
        handSize: rule.handSize,
        blind: rule.blind,
        reward: rule.reward,
        blindName: rule.blindName,
        levelName: rule.levelName
    };
}