import { Node, Vec3, tween, UIOpacity } from 'cc';

export function screenShake(node: Node, intensity: number = 8, duration: number = 0.3): Promise<void> {
    const origin = node.position.clone();
    const steps = Math.max(4, Math.round(duration / 0.05));
    const stepDur = duration / steps;

    return new Promise(resolve => {
        let t = tween(node);
        for (let i = 0; i < steps; i++) {
            const decay = 1 - i / steps;
            const ox = (Math.random() * 2 - 1) * intensity * decay;
            const oy = (Math.random() * 2 - 1) * intensity * decay;
            t = t.to(stepDur, { position: new Vec3(origin.x + ox, origin.y + oy, origin.z) });
        }
        t.to(stepDur, { position: origin })
            .call(() => resolve())
            .start();
    });
}

export function scalePunch(node: Node, peakScale: number = 1.3, duration: number = 0.25): Promise<void> {
    const original = node.scale.clone();
    const peak = new Vec3(
        original.x * peakScale,
        original.y * peakScale,
        original.z * peakScale,
    );

    return new Promise(resolve => {
        tween(node)
            .to(duration * 0.4, { scale: peak }, { easing: 'quadOut' })
            .to(duration * 0.6, { scale: original }, { easing: 'backOut' })
            .call(() => resolve())
            .start();
    });
}

export function flash(node: Node, duration: number = 0.3): Promise<void> {
    const uiOpacity = node.getComponent(UIOpacity) ?? node.addComponent(UIOpacity);
    const originalOpacity = uiOpacity.opacity;

    return new Promise(resolve => {
        node.active = true;
        uiOpacity.opacity = 255;
        tween(uiOpacity)
            .to(duration, { opacity: originalOpacity })
            .call(() => {
                node.active = false;
                resolve();
            })
            .start();
    });
}
