import { _decorator, Component, Node, instantiate, Prefab, Vec3 } from 'cc';
import { CardView } from './CardView';
import { CardInfoPopup } from './CardInfoPopup';
import { Card, CardEvents } from '../../types';

const { ccclass, property } = _decorator;

@ccclass('HandView')
export class HandView extends Component {
    @property(Prefab)
    cardViewPrefab: Prefab | null = null;

    @property(CardInfoPopup)
    cardInfoPopup: CardInfoPopup | null = null;

    @property(Node)
    deckSpawnNode: Node | null = null;

    private _cardViews: CardView[] = [];
    private readonly DEAL_STAGGER_MS = 60;
    private readonly CARD_SPACING = 150;
    // Fan curve: how many pixels the edge cards drop below centre (parabolic)
    private readonly CURVE_FACTOR = 1;
    // Fan tilt: degrees of rotation per card-slot away from centre
    private readonly TILT_FACTOR = 2;

    public renderHand(cards: Card[]) {
        this.node.removeAllChildren();
        this._cardViews = [];

        if (!this.cardViewPrefab) return;

        for (let i = 0; i < cards.length; i++) {
            const cardNode = instantiate(this.cardViewPrefab);
            cardNode.parent = this.node;
            
            const cardView = cardNode.getComponent(CardView);
            if (cardView) {
                cardView.setCardModel(cards[i]);
                this._cardViews.push(cardView);
                
                // Listen to pure intents emitted by CardInteraction
                cardNode.on(CardEvents.TAP, this.onCardTap, this);
                cardNode.on(CardEvents.LONG_PRESS_START, this.onCardLongPress, this);
                cardNode.on(CardEvents.DRAG_START, this.onCardDragStart, this);
                cardNode.on(CardEvents.DRAG_END, this.onCardDragEnd, this);
                cardNode.on(CardEvents.DRAG_MOVE, this.onCardDragMove, this);
            }
        }
        
        this.layoutCards(false);
    }

    public async dealCards(cards: Card[]): Promise<void> {
        if (!this.cardViewPrefab) return;

        // Snapshot existing views by card ID so we can reuse them
        const existingById = new Map<string, CardView>();
        for (const cv of this._cardViews) {
            if (cv.cardModel) existingById.set(cv.cardModel.id, cv);
        }

        // Destroy views that are no longer part of the new hand
        const newIds = new Set(cards.map(c => c.id));
        for (const cv of this._cardViews) {
            if (cv.cardModel && !newIds.has(cv.cardModel.id) && cv.node.isValid) {
                cv.node.removeFromParent();
                cv.node.destroy();
            }
        }

        const totalCards = cards.length;
        if (totalCards === 0) {
            this._cardViews = [];
            return;
        }

        const centerIndex = (totalCards - 1) / 2;

        // Spawn point in HandView local space — use deckSpawnNode if wired, else fallback
        let spawnPos: Vec3;
        if (this.deckSpawnNode) {
            spawnPos = new Vec3();
            this.node.inverseTransformPoint(spawnPos, this.deckSpawnNode.worldPosition);
        } else {
            spawnPos = new Vec3(280, -350, 0);
        }

        this._cardViews = [];
        const promises: Promise<void>[] = [];
        let newCardStagger = 0;

        for (let i = 0; i < totalCards; i++) {
            const card = cards[i];
            const offset = i - centerIndex;
            const targetPos = new Vec3(offset * this.CARD_SPACING, -this.CURVE_FACTOR * offset * offset, 0);
            const targetAngle = -this.TILT_FACTOR * offset;

            const existing = existingById.get(card.id);
            if (existing && existing.node.isValid) {
                // Card already in hand — will slide to its new layout position
                this._cardViews.push(existing);
            } else {
                // Newly drawn card — spawn from deck and fly in
                const cardNode = instantiate(this.cardViewPrefab);
                cardNode.parent = this.node;
                const cardView = cardNode.getComponent(CardView);
                if (cardView) {
                    cardView.setCardModel(card);
                    this._cardViews.push(cardView);

                    cardNode.on(CardEvents.TAP, this.onCardTap, this);
                    cardNode.on(CardEvents.LONG_PRESS_START, this.onCardLongPress, this);
                    cardNode.on(CardEvents.DRAG_START, this.onCardDragStart, this);
                    cardNode.on(CardEvents.DRAG_END, this.onCardDragEnd, this);
                    cardNode.on(CardEvents.DRAG_MOVE, this.onCardDragMove, this);

                    cardNode.setPosition(spawnPos);
                }
            }
        }

        // Fix sibling order in one pass now that all nodes are in the parent,
        // then trigger animations. Doing this after the loop avoids index
        // shifting caused by interleaved setSiblingIndex calls.
        for (let i = 0; i < this._cardViews.length; i++) {
            const cv = this._cardViews[i];
            cv.node.setSiblingIndex(i);

            const offset = i - centerIndex;
            const targetPos = new Vec3(offset * this.CARD_SPACING, -this.CURVE_FACTOR * offset * offset, 0);
            const targetAngle = -this.TILT_FACTOR * offset;

            if (existingById.has(cv.cardModel!.id)) {
                cv.setBaseTransform(targetPos, targetAngle, true);
            } else {
                promises.push(cv.flyTo(targetPos, targetAngle, newCardStagger * this.DEAL_STAGGER_MS));
                newCardStagger++;
            }
        }

        await Promise.all(promises);
    }

    private layoutCards(animate: boolean = false) {
        const totalCards = this._cardViews.length;
        if (totalCards === 0) return;

        const centerIndex = (totalCards - 1) / 2;

        for (let i = 0; i < totalCards; i++) {
            const cardView = this._cardViews[i];


            // skip the card which is 
            const offset = i - centerIndex;

            const targetX = offset * this.CARD_SPACING;
            // Parabolic curve: edges drop below the centre
            const targetY = -this.CURVE_FACTOR * offset * offset;
            // Tilt outward from centre
            const targetAngle = -this.TILT_FACTOR * offset;

            // Always sync sibling index so z-order matches array order (fix sort overlap)
            cardView.node.setSiblingIndex(i);

            // setBaseTransform skips visual update while card is being dragged,
            // so the card flies back correctly on drop.
            cardView.setBaseTransform(new Vec3(targetX, targetY, 0), targetAngle, animate);
        }
    }

    public animateSortHand(cards: Card[]): Promise<void> {
        const idToView = new Map(this._cardViews.map(cv => [cv.cardModel?.id, cv]));
        this._cardViews = cards
            .map(c => idToView.get(c.id))
            .filter((cv): cv is CardView => !!cv);

        this.layoutCards(true);
        return new Promise(resolve => setTimeout(resolve, 200));
    }

    public getSelectedCards(): Card[] {
        return this._cardViews.filter(c => c.isSelected).map(c => c.cardModel!);
    }

    public getCardViews(): CardView[] {
        return this._cardViews;
    }

    public syncSelectionState(selectedIds: string[]) {
        for (const cardView of this._cardViews) {
            if (cardView.cardModel) {
                const shouldBeSelected = selectedIds.includes(cardView.cardModel.id);
                if (cardView.isSelected !== shouldBeSelected) {
                    cardView.setSelected(shouldBeSelected);
                }
            }
        }
    }

    private onCardTap(cardView: CardView) {
        if (!cardView.cardModel) return;
        this.node.emit('INTENT_TOGGLE_CARD', cardView.cardModel.id);
    }

    private onCardLongPress(cardView: CardView) {
        if (this.cardInfoPopup) {
            this.cardInfoPopup.show(cardView);
        }
    }

    private onCardDragStart(cardView: CardView) {
        cardView.setDragging(true);
        cardView.node.setSiblingIndex(this._cardViews.length - 1); // Bring to front visually
        
        if (this.cardInfoPopup) {
            this.cardInfoPopup.show(cardView);
        }
    }

    private onCardDragMove(cardView: CardView, dx: number, dy: number) {
        cardView.updateDragPosition(new Vec3(dx, dy, 0));
        this.checkDragSorting(cardView);
    }

    private onCardDragEnd(cardView: CardView) {
        cardView.setDragging(false);
        if (this.cardInfoPopup) {
            this.cardInfoPopup.hide();
        }
        // Force Z-order update on drop
        this.layoutCards(false); 
    }

    private checkDragSorting(draggingCard: CardView) {
        const draggingIndex = this._cardViews.indexOf(draggingCard);
        if (draggingIndex === -1) return;

        let newIndex = draggingIndex;
        const dragX = draggingCard.node.position.x;

        // Determine new index based on x position
        for (let i = 0; i < this._cardViews.length; i++) {
            if (i === draggingIndex) continue;
            const targetX = this._cardViews[i].node.position.x;
            
            if (draggingIndex < i && dragX > targetX) {
                newIndex = i;
            } else if (draggingIndex > i && dragX < targetX) {
                newIndex = i;
                break; // Found the first one it's smaller than
            }
        }

        if (newIndex !== draggingIndex) {
            // Swap in array
            this._cardViews.splice(draggingIndex, 1);
            this._cardViews.splice(newIndex, 0, draggingCard);
            
            // Re-layout with animation. The dragging card won't visibly animate
            // but the other cards will make space smoothly.
            this.layoutCards(true);
        }
    }

}
