import * as cc from 'cc'
import { _decorator, Component, instantiate, assetManager } from 'cc';
const { ccclass, property, menu} = cc._decorator

import { BaseGameData } from './BaseGameData';
import * as PlatformModule from './PlatformModule';

@ccclass("BasePrefab")
export class BasePrefab {
    @property(cc.Prefab)
    prefab: cc.Prefab = null

    @property(cc.CCString)
    name: string = ""

    @property({type:cc.CCString, tooltip:"描述"})
    memo: string = ""

    @property({type:cc.CCString, tooltip:"填 prefab 或 prefabPath", visible: PlatformModule.HasPlatformModule}) // 如果物件種類太多，可以用 prefabPath 來減少開始載入時間， prefab 優先
    prefabPath: string = ""

}


@ccclass('BasePrefabMgr')
@menu('小遊戲/Base/BasePrefabMgr')
/**
 * 小遊戲用prefab管理器
 * 需要掛入node中使用 把要建立的prefab拉進去
 * 使用 instantiatePref()生成物件
 * 使用 recycleObject()回收物件
 * 若功能已經夠用的情形下 可以直接使用
 * 但若需要新增功能 請用繼承的方式來擴充
 */
export class BasePrefabMgr extends Component {

    @property( BasePrefab )
    objectPrefab: BasePrefab[] = [];

    private prefabMap = new Map<string, BasePrefab>();
    private cachedNode = new Map<string, cc.Node[]>();
    private static instance: BasePrefabMgr = null;

    private prefabMgrRoot: cc.Node = null;

    public static get Instance(){
        return this.instance;
    }

    protected onLoad(): void {
        BasePrefabMgr.instance = this;

        //建立一個node 名稱為 prefabMgr
        this.prefabMgrRoot = new cc.Node("prefabMgrRoot");
        this.prefabMgrRoot.setParent(this.node);
        this.prefabMgrRoot.setPosition(5000,5000,0);

        for( let info of this.objectPrefab ){
            this.prefabMap.set( info.name, info );
        }
    }

    protected onDestroy(): void {
        for( let [key, value] of this.cachedNode ){
            for( let node of value ){
                node.destroy();
            }
        }
        this.cachedNode.clear();
        this.prefabMgrRoot.destroy();
        BasePrefabMgr.instance = null;
    }

    public instantiatePref( name: string , active: boolean = true ){

        if( this.cachedNode.has( name ) ){
            let cache = this.cachedNode.get( name );
            if( cache.length > 0 ){
                let node = cache.pop();
                node.active = active;
                return node;
            }
        }
        
        let info = this.prefabMap.get( name );
        if( info ){
            try{
                if( info.prefab ){
                    let node = instantiate( info.prefab );
                    return node;
                }
    
                if( info.prefabPath ){
                    let b = assetManager.getBundle(PlatformModule.GameDefine.Infos.get(BaseGameData.Instance.GameID).bundleName);
                    let retNode : cc.Node;
                    b.load( info.prefabPath, cc.Prefab, ( err, pref )=>{
                        retNode = instantiate( pref );
                    })
                    return retNode;
                }
            }catch(e){
                console.error('[Pref]load prefab error, ' + name, ' : ', e );
            }
        }        
        console.error('[Pref]prefab not in GamePlay:' + name );
        return null;
    }

    public recycleObject( name: string, node: cc.Node, maxCache: number = 5 ){
        if( !this.cachedNode.has( name ) ){
            this.cachedNode.set( name, [] );
        }
        node.setParent(this.prefabMgrRoot); // 預設必先切換 parenting 回 parentMgrRoot
        let cache = this.cachedNode.get( name );
        if( cache.length < maxCache ){
            node.setRTS(cc.Quat.IDENTITY, cc.Vec3.ZERO, cc.Vec3.ONE);
            cache.push( node );
        }else{
            node.destroy();
        }
    }
    
}
