import { _decorator, Component, Node } from 'cc';
import { SingleGameCollectStageConfig, SingleGameCollectActivityStateConfig, SingleGameCollectActivityStatePlayer, SingleGameCollectActivityState } from './SingleGameCollectActivityDataDefine';
const { ccclass, property } = _decorator;

@ccclass('SingleGameCollectActivityManager')
export class SingleGameCollectActivityManager extends Component {

    private static _instance: SingleGameCollectActivityManager | null = null;

    public static get Instance() {
        if (!SingleGameCollectActivityManager._instance) {
            SingleGameCollectActivityManager._instance = new SingleGameCollectActivityManager();
        }
        return SingleGameCollectActivityManager._instance;
    }

    public static Dispose() {
        SingleGameCollectActivityManager._instance = null;
    }

    private config: SingleGameCollectActivityStateConfig | null = null;
    private player: SingleGameCollectActivityStatePlayer | null = null;
    private cacheCurrentStage: number = 0;
    private cacheOldCollectionCount: number = 0;
    
    get TargetObject(): number {
        return this.config?.collectObjectNo ?? 0;
    }
    get TargetReward(): number {
        if (this.player && this.config) {
            const stage = this.player.currentStage;
            const stageconf = this.findStageConfig(stage);
            if (stageconf) {
                return stageconf.rewardItemNo;
            }
        }
        return 0;
    }
    get StageTargetCollectCount(): number {
        if (this.player && this.config) {
            const stage = this.player.currentStage;
            const stageconf = this.findStageConfig(stage);
            if (stageconf) {
                return stageconf.collectCount;
            }
        }
        return 0;
    }
    get ActivityEndTime(): number {
        return 0; // TODO
    }
    get CurrentStage(): number {
        return this.player?.currentStage ?? this.cacheCurrentStage;
    }
    get TotalStages(): number {
        return this.config?.stageConfigsList?.length ?? 0;
    }
    get Over(): boolean {
        return this.player?.isOver ?? false;
    }
    get CollectedCount(): number {
        return this.player?.currentCount ?? 0;
    }
    get OldCollectionCount(): number {
        return this.cacheOldCollectionCount;
    }
    set OldCollectionCount(value: number) {
        this.cacheOldCollectionCount = value;
    }

    initialize(sourceState: SingleGameCollectActivityState) {
        if (!sourceState) {
            console.warn("[SingleGame] initialize GetCollectActivityState: sourceStates is null or empty");
            return;
        }
        const config = sourceState.config;
        const player = sourceState.player;
        if (config) {
            this.config = config;
        }
        if (player) {
            this.player = player;
            this.cacheCurrentStage = player.currentStage;
        }
    }

    hasReadyStageReward(): boolean {
        if (this.Over) {
            return false;
        }
        const sourceStages = this.config.stageConfigsList;
        for (let i = 0; i < sourceStages.length; i++) {
            if (sourceStages[i].stageNo === this.CurrentStage &&
                this.CollectedCount >= sourceStages[i].collectCount) {
                return true;
            }
        }
        return false;
    }

    private getServerTime() {
        // TODO: 目前採 client device time
        return Math.floor(Date.now() / 1000);
    }

    isOpenNow(): boolean {
        const now = this.getServerTime();
        return true; // TODO
    }

    isOpenAndValid(): boolean {
        // TODO: 可補充遊戲特別規則
        return this.isOpenNow();
    }

    isCollectionRewardClaimed(id: number): boolean {
        if (this.Over || this.player.currentStage > id) {
            return true;
        }
        return false;
    }

    syncCollectionProgress() {
        this.OldCollectionCount = this.CollectedCount;
    }

    refreshCollected(count: number) {
        if (this.player) {
            this.player.currentCount = count;
        }
    }

    findStageConfig(id: number): SingleGameCollectStageConfig | null {
        if (this.config) {
            const configs = this.config.stageConfigsList;
            for (let i = 0; i < configs.length; i++) {
                if (configs[i].stageNo === id) {
                    return configs[i];
                }
            }
        }
        return null;
    }
}
