export type BindingHandler<T> = (prev: T, next: T) => void;

export class ReactiveProperty<T> {
    private _value: T;
    private _bindings: BindingHandler<T>[] = [];
    private _suppressed = false;

    constructor(initialValue: T) {
        this._value = initialValue;
    }

    get value(): T {
        return this._value;
    }

    set value(newValue: T) {
        const prev = this._value;
        if (prev === newValue) return;
        this._value = newValue;
        if (!this._suppressed) {
            this._notify(prev, newValue);
        }
    }

    /** Update value without triggering any bindings */
    setSilent(newValue: T) {
        this._value = newValue;
    }

    bind(handler: BindingHandler<T>): () => void {
        this._bindings.push(handler);
        return () => {
            const idx = this._bindings.indexOf(handler);
            if (idx >= 0) this._bindings.splice(idx, 1);
        };
    }

    suppress() {
        this._suppressed = true;
    }

    resume() {
        this._suppressed = false;
    }

    /** Re-enable notifications and immediately trigger all bindings with current value */
    resumeAndNotify() {
        this._suppressed = false;
        this._notify(this._value, this._value);
    }

    /** Force-trigger all bindings with current value (no-op when suppressed) */
    notify() {
        if (!this._suppressed) {
            this._notify(this._value, this._value);
        }
    }

    unbindAll() {
        this._bindings = [];
    }

    get suppressed(): boolean {
        return this._suppressed;
    }

    private _notify(prev: T, next: T) {
        for (const handler of this._bindings) {
            handler(prev, next);
        }
    }
}
