import { _decorator, Component, Node, Label, Graphics, UITransform, Vec3, Color, view } from 'cc';
import { GameRendererEngine } from './GameRendererEngine';
import { GamePhase } from '../types/GamePhase';
import { TUTORIAL_STEPS, TutorialStep, SpotlightTarget, AdvanceTrigger } from '../engine/TutorialSteps';
import { Card } from '../types/Card';
import { RichText } from 'cc';

const { ccclass, property } = _decorator;

const DIM_COLOR = new Color(0, 0, 0, 180);
const HOLE_PAD  = 24;

interface HoleRect { minX: number; minY: number; maxX: number; maxY: number; }

/**
 * Drop onto an empty node in balatro_main.scene.
 * Wire: renderer, tutorialOverlay, dimGraphics, bubbleLabel,
 *       inputBlocker, tutorialButton.
 *
 * inputBlocker = full-screen Node + BlockInputEvents (blocks all game input).
 *   active=true  → tap-anywhere / animDone steps
 *   active=false → game-interaction steps; Button.interactable handles the rest
 */
@ccclass('TutorialController')
export class TutorialController extends Component {

    @property(GameRendererEngine)
    renderer: GameRendererEngine | null = null;

    @property(Node)
    tutorialOverlay: Node | null = null;

    /** Full-screen node with a Graphics component — visual dim + hole only. */
    @property(Graphics)
    dimGraphics: Graphics | null = null;

    @property(RichText)
    bubbleLabel: RichText | null = null;

    /**
     * Full-screen Node with BlockInputEvents.
     * active=true  → hard wall (tap steps / animDone).
     * active=false → game receives input; Button.interactable gates which buttons work.
     */
    @property(Node)
    inputBlocker: Node | null = null;

    @property(Node)
    tutorialButton: Node | null = null;

    // ── Private state ────────────────────────────────────────────────

    private _stepIndex: number = 0;
    private _active: boolean = false;

    /** Bound once in start(); unbind on destroy. */
    private _persistentUnbinds: Array<() => void> = [];
    /** Bound per step; cleared between steps. */
    private _stepUnbinds: Array<() => void> = [];

    // ── Lifecycle ────────────────────────────────────────────────────

    start() {
        if (!this.renderer) return;

        const unbind = this.renderer.engine.phase$.bind((_prev, next) => {
            if (this.tutorialButton) {
                this.tutorialButton.active = (next === GamePhase.START);
            }
        });
        this._persistentUnbinds.push(unbind);

        if (this.tutorialButton) {
            this.tutorialButton.active = (this.renderer.engine.phase === GamePhase.START);
            this.tutorialButton.on(Node.EventType.TOUCH_END, this.beginTutorial, this);
        }

        if (this.tutorialOverlay) this.tutorialOverlay.active = false;
        if (this.inputBlocker)    this.inputBlocker.active    = false;
    }

    onDestroy() {
        this._clearStepListeners();
        for (const unbind of this._persistentUnbinds) unbind();
        this._persistentUnbinds = [];
        this.tutorialButton?.off(Node.EventType.TOUCH_END, this.beginTutorial, this);
    }

    // ── Public API ───────────────────────────────────────────────────

    async beginTutorial() {
        if (!this.renderer || this._active) return;
        this._active    = true;
        this._stepIndex = 0;

        if (this.tutorialButton) this.tutorialButton.active = false;

        await this.renderer.handleBlindSelect(1);
        await this._applyPresetHand(TUTORIAL_STEPS[0]);

        if (this.tutorialOverlay) this.tutorialOverlay.active = true;
        this._showStep(0);
    }

    // ── Step control ─────────────────────────────────────────────────

    private async _showStep(index: number) {
        const step = TUTORIAL_STEPS[index];
        if (!step) return;

        if (step.presetHand && index > 0) await this._applyPresetHand(step);

        if (this.bubbleLabel) this.bubbleLabel.string = step.bubble;

        this._applySpotlight(step.spotlight);
        this._listenForAdvance(step);
    }

    advanceStep() {
        this._clearStepListeners();
        this._restoreAllButtons();
        this._stepIndex++;

        if (this._stepIndex >= TUTORIAL_STEPS.length) {
            this.exitTutorial();
        } else {
            this._showStep(this._stepIndex);
        }
    }

    exitTutorial() {
        this._clearStepListeners();
        this._restoreAllButtons();
        this._active = false;

        if (this.dimGraphics)     this.dimGraphics.clear();
        if (this.inputBlocker)    this.inputBlocker.active    = false;
        if (this.tutorialOverlay) this.tutorialOverlay.active = false;
    }

    // ── Visual spotlight (dim + hole) ────────────────────────────────

    private _applySpotlight(target: SpotlightTarget) {
        const spotNodes = this._resolveTarget(target);

        if (spotNodes.length > 0) {
            const hole = this._computeHole(spotNodes);
            this._redrawDim(hole);
        } else {
            this._redrawDim(null);
        }
    }

    private _redrawDim(hole: HoleRect | null) {
        const g = this.dimGraphics;
        if (!g) return;

        g.clear();
        g.fillColor = DIM_COLOR;

        const vs = view.getVisibleSize();
        const padding = 200;
        const W  = vs.width + padding,  H  = vs.height + padding;
        const hw = W / 2,     hh = H / 2;

        if (!hole) {
            g.rect(-hw, -hh, W, H);
            g.fill();
            return;
        }

        const { minX, minY, maxX, maxY } = hole;
        const hH = maxY - minY;

        g.rect(-hw,  maxY,    W,           hh  - maxY);  // top
        g.rect(-hw, -hh,      W,           minY + hh);   // bottom
        g.rect(-hw,  minY,    minX + hw,   hH);          // left
        g.rect(maxX, minY,    hw  - maxX,  hH);          // right
        g.fill();
    }

    private _computeHole(spotNodes: Node[]): HoleRect {
        const g  = this.dimGraphics!;
        const vs = view.getVisibleSize();
        const hw = vs.width / 2, hh = vs.height / 2;

        let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;

        for (const node of spotNodes) {
            const uiT = node.getComponent(UITransform);
            if (!uiT) continue;
            const wr = uiT.getBoundingBoxToWorld();
            for (const wc of [new Vec3(wr.xMin, wr.yMin, 0), new Vec3(wr.xMax, wr.yMax, 0)]) {
                const lc = new Vec3();
                g.node.inverseTransformPoint(lc, wc);
                if (lc.x < minX) minX = lc.x;
                if (lc.y < minY) minY = lc.y;
                if (lc.x > maxX) maxX = lc.x;
                if (lc.y > maxY) maxY = lc.y;
            }
        }

        return {
            minX: Math.max(minX - HOLE_PAD, -hw),
            minY: Math.max(minY - HOLE_PAD, -hh),
            maxX: Math.min(maxX + HOLE_PAD,  hw),
            maxY: Math.min(maxY + HOLE_PAD,  hh),
        };
    }

    private _resolveTarget(target: SpotlightTarget): Node[] {
        const r    = this.renderer!;
        const pick = (...nodes: Array<Node | null | undefined>): Node[] =>
            nodes.filter((n): n is Node => !!n);

        switch (target) {
            case 'hand':         return pick(r.handView?.node);
            case 'selectedCard': return pick(r.handView?.node, r.runningChipsLabel?.node);
            case 'playButton':   return pick(r.playButton?.node);
            case 'scoreArea':    return pick(r.scoreLabel?.node, r.climaxLabel?.node);
            case 'handType':     return pick(r.currentHandTypeLabel?.node, r.runningChipsLabel?.node, r.runningMultLabel?.node);
            case 'chipsLabel':   return pick(r.runningChipsLabel?.node);
            case 'targetScore':  return pick(r.targetScoreLabel?.node);
            case 'handsLeft':    return pick(r.handsLeftLabel?.node, r.discardsLeftLabel?.node);
            case 'none':         return [];
        }
    }

    // ── Button interactability ───────────────────────────────────────

    /**
     * Disable every game button EXCEPT those needed for this trigger.
     *
     * The renderer's selection$ binding calls updateButtonStates() which can
     * re-enable buttons, so for interaction steps we also subscribe to
     * selection$ and re-apply the restriction after each renderer update.
     */
    private _applyButtonRestriction(trigger: AdvanceTrigger) {
        const r = this.renderer;
        if (!r) return;

        const blockAll = () => {
            if (r.playButton)          r.playButton.interactable          = false;
            if (r.discardButton)       r.discardButton.interactable       = false;
            if (r.sortByCardRankButton) r.sortByCardRankButton.interactable = false;
            if (r.sortByCardSuitButton) r.sortByCardSuitButton.interactable = false;
            if (r.handsRuleButton) r.handsRuleButton.interactable = false;
        };

        const blockNonPlay = () => {
            if (r.discardButton)       r.discardButton.interactable       = false;
            if (r.sortByCardRankButton) r.sortByCardRankButton.interactable = false;
            if (r.sortByCardSuitButton) r.sortByCardSuitButton.interactable = false;
            if (r.handsRuleButton) r.handsRuleButton.interactable = false;
        };

        if (trigger === 'cardSelected' || trigger === 'twoSameRankSelected') {
            blockAll();
            // Re-apply after renderer's updateButtonStates fires on selection change
            this._stepUnbinds.push(r.engine.selection$.bind(() => blockAll()));
        }

        if (trigger === 'handPlayed') {
            blockNonPlay();
            this._stepUnbinds.push(r.engine.selection$.bind(() => blockNonPlay()));
        }
    }

    private _restoreAllButtons() {
        const r = this.renderer;
        if (!r) return;
        // Let the renderer's existing bindings re-evaluate the correct state
        r.engine.selection$.notify();
        r.engine.playsLeft$.notify();
        r.engine.discardsLeft$.notify();
        if (r.playButton)          r.playButton.interactable          = true;
        if (r.discardButton)       r.discardButton.interactable       = true;
        if (r.sortByCardRankButton) r.sortByCardRankButton.interactable = true;
        if (r.sortByCardSuitButton) r.sortByCardSuitButton.interactable = true;
        if (r.handsRuleButton) r.handsRuleButton.interactable = true;
    }

    // ── Advance triggers ─────────────────────────────────────────────

    private _listenForAdvance(step: TutorialStep) {
        const engine = this.renderer!.engine;

        switch (step.advanceOn) {
            case 'tutorialDone':
                this.exitTutorial();
                break;

            case 'tap':
                if (this.inputBlocker) this.inputBlocker.active = true;
                this.inputBlocker?.once(Node.EventType.TOUCH_END, this._onTapAdvance, this);
                break;

            case 'cardSelected':
                if (this.inputBlocker) this.inputBlocker.active = false;
                this._applyButtonRestriction('cardSelected');
                this._stepUnbinds.push(engine.selection$.bind((_p, next) => {
                    if (next.length > 0) this.advanceStep();
                }));
                break;

            case 'twoSameRankSelected':
                if (this.inputBlocker) this.inputBlocker.active = false;
                this._applyButtonRestriction('twoSameRankSelected');
                this._stepUnbinds.push(engine.selection$.bind((_p, next) => {
                    if (next.length >= 2) {
                        const ranks = engine.getSelectedCards().map(c => c.rank);
                        if (ranks.some((r, i) => ranks.indexOf(r) !== i)) this.advanceStep();
                    }
                }));
                break;

            case 'handPlayed':
                if (this.inputBlocker) this.inputBlocker.active = false;
                this._applyButtonRestriction('handPlayed');
                this._stepUnbinds.push(engine.playsLeft$.bind(() => this.advanceStep()));
                break;

            case 'animDone':
                if (this.inputBlocker) this.inputBlocker.active = true;
                this.scheduleOnce(() => this.advanceStep(), 3.5);
                break;
        }
    }

    private _onTapAdvance() {
        this.advanceStep();
    }

    private _clearStepListeners() {
        for (const unbind of this._stepUnbinds) unbind();
        this._stepUnbinds = [];
        this.inputBlocker?.off(Node.EventType.TOUCH_END, this._onTapAdvance, this);
        this.unscheduleAllCallbacks();
    }

    // ── Preset hand injection ────────────────────────────────────────

    private async _applyPresetHand(step: TutorialStep) {
        if (!step.presetHand || !this.renderer) return;
        const hand: Card[] = step.presetHand.map(c => ({ ...c }));
        this.renderer.engine.setHand(hand);
        this.renderer.handView?.renderHand(hand);
    }
}
