import { _decorator, Component, Node } from 'cc';
import * as PlatformModule from './PlatformModule';
import { IBaseGameService } from './IBaseGameService';
const { ccclass, property } = _decorator;

@ccclass('BaseGameData')
export class BaseGameData {

    private static instance: BaseGameData = null;
    public static get Instance() {
        if (!BaseGameData.instance) {
            BaseGameData.instance = new BaseGameData();
        }
        return BaseGameData.instance;
    }
    public static clearAll(){
        BaseGameData.instance = null;
    }

    /**
     * 不可引用真實實現 class
     */
    private gameService: IBaseGameService | null = null;
    private gameBundleName: string = "";
    private gameID : number = 0;
    private isLoginFromPlatform : boolean = false;  //由平台登入 or 由本地場景開啟
    private hasPlatformModule : boolean = false;  //是否有真的平台 , 若沒有, 則一定是由本地場景開啟

    public get Service() {
        return this.gameService;
    }
    public set Service(service: IBaseGameService) {
        this.gameService = service;
    }

    public get GameID() {
        return this.gameID;
    }
    public set GameID(id:number) {
        this.gameID = id;
    }

    public get IsLoginFromPlatform() {
        return this.isLoginFromPlatform;
    }

    public set IsLoginFromPlatform(isLogin:boolean) {
        this.isLoginFromPlatform = isLogin;
    }

    public set HasPlatformModule(hasPlatform:boolean) {
        this.hasPlatformModule = hasPlatform;
    }

    public get HideCommonUI() {
        // 如果用真的平台, 但非從平台登入, 則無法顯示天bar, 公版UI等
        return this.hasPlatformModule && (!this.isLoginFromPlatform);
    }

    public get GameBundleName(): string {
        return this.gameBundleName;
    }

    public set GameBundleName(name: string) {
        this.gameBundleName = name;
    }
}


