import { _decorator, EventTarget } from 'cc';
const { ccclass, property } = _decorator;

export class BaseGameEvent {

    private static eventTarget: EventTarget = null;

    public static get Instance() {
        if (!BaseGameEvent.eventTarget) {
            BaseGameEvent.eventTarget = new EventTarget();
        }
        return BaseGameEvent.eventTarget;
    }

    public static emit(event: string, ...args: any[]) {
        BaseGameEvent.Instance?.emit(event, ...args);
    }

    public static on(event: string, callback: (...args: any[]) => void, target?: any) {
        BaseGameEvent.Instance?.on(event, callback, target);
    }

    public static off(event: string, callback: (...args: any[]) => void, target?: any) {
        BaseGameEvent.Instance?.off(event, callback, target);
    }

    public static clearAll(){
        BaseGameEvent.eventTarget = null;
    }
}


